insert into categories (id, slug, name, emoji, description_md, api_count) values (1, 'weather', 'Weather', '🌦', 'Forecasts, climate history and severe-weather feeds — checked around the clock.', 36);
insert into categories (id, slug, name, emoji, description_md, api_count) values (2, 'finance', 'Finance', '📈', 'FX, crypto and market data with the free-tier fine print actually verified.', 68);
insert into categories (id, slug, name, emoji, description_md, api_count) values (3, 'geo', 'Geo & Maps', '🗺', 'Geocoding, IP location and country data. Rate limits documented, not guessed.', 69);
insert into categories (id, slug, name, emoji, description_md, api_count) values (4, 'science', 'Science & Space', '🔭', 'Space, physics and research data from agencies and observatories.', 49);
insert into categories (id, slug, name, emoji, description_md, api_count) values (5, 'animals', 'Animals', '🐕', 'The classics — every image endpoint verified to still return an actual dog.', 16);
insert into categories (id, slug, name, emoji, description_md, api_count) values (6, 'fun', 'Fun & Games', '🎮', 'Game data, jokes and trivia for demos, teaching and toy projects.', 46);
insert into categories (id, slug, name, emoji, description_md, api_count) values (7, 'data', 'Open Data', '📚', 'Books, countries, encyclopedic and public datasets with stable schemas.', 117);
insert into categories (id, slug, name, emoji, description_md, api_count) values (8, 'developer', 'Developer Tools', '🔧', 'Utilities you wire into everything else — IPs, avatars, placeholders, QR.', 183);
insert into categories (id, slug, name, emoji, description_md, api_count) values (9, 'crypto', 'Crypto & Web3', '🪙', 'Coins, chains and on-chain data — free endpoints with the rate limits verified.', 37);
insert into categories (id, slug, name, emoji, description_md, api_count) values (10, 'transport', 'Transport', '🚆', 'Transit, flights, vehicles and tracking feeds. Live where the agency publishes it.', 42);
insert into categories (id, slug, name, emoji, description_md, api_count) values (11, 'games', 'Games & Anime', '🎮', 'Game, comic and anime data for demos, bots and toy projects.', 75);
insert into categories (id, slug, name, emoji, description_md, api_count) values (12, 'books', 'Books & Words', '📖', 'Books, dictionaries and language data with stable, well-documented schemas.', 23);
insert into categories (id, slug, name, emoji, description_md, api_count) values (13, 'media', 'Media', '🎬', 'Video, music, images and art — keyless where possible, plus free-tier APIs that need your own key (TMDb, Fanart.tv, Last.fm).', 65);
insert into categories (id, slug, name, emoji, description_md, api_count) values (14, 'health', 'Health & Food', '🩺', 'Health, fitness, nutrition and food data from open registries.', 59);
insert into categories (id, slug, name, emoji, description_md, api_count) values (15, 'security', 'Security', '🔐', 'Threat intel, breach checks and validation utilities. Keyless tiers only.', 21);
insert into categories (id, slug, name, emoji, description_md, api_count) values (16, 'social', 'Social & Work', '💬', 'Social, jobs, calendars and messaging metadata — the connective tissue APIs.', 63);
insert into categories (id, slug, name, emoji, description_md, api_count) values (17, 'gov', 'Government', '🏛', 'Public-sector open data: agencies, law, elections and civic datasets.', 68);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (1, 'open-meteo', 'Open-Meteo', '🌤', 'Hourly forecasts for any coordinate — no key, no signup.', 'Open-Meteo serves fast global weather forecasts assembled from national weather services. The free endpoint needs no API key, answers over HTTPS with permissive CORS, and covers hourly and daily variables, historical reanalysis and air quality. Note the license: the free tier is for non-commercial use — a paid keyed tier exists for products.', 1, 'https://open-meteo.com/en/docs', 'https://api.open-meteo.com/v1', 'none', 'endpoint', 1, 1, '<10,000 calls/day, no signup', '600/min · 5,000/hour', 0, 'no', 'CC-BY 4.0', 'healthy', '2026-05-02', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (2, 'frankfurter', 'Frankfurter', '💱', 'Central-bank FX rates. MIT-licensed, self-hostable, commercial-safe.', 'Frankfurter tracks reference exchange rates from the European Central Bank and friends. It is the rare free API with zero strings attached: MIT-licensed code, self-hostable via Docker, explicit yes to commercial use, and no quotas beyond abuse-prevention rate limiting. The gold standard for what a free API should be.', 2, 'https://frankfurter.dev', 'https://api.frankfurter.dev/v1', 'none', 'endpoint', 1, 1, 'Unlimited — abuse-rate-limited only', 'Unpublished, generous', 0, 'yes', 'Public data (ECB reference rates)', 'healthy', '2026-05-02', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (3, 'coingecko', 'CoinGecko', '🦎', 'Crypto prices and market data with a real free demo tier.', 'CoinGecko exposes coin prices, market charts and exchange data. The free demo tier works without a card but enforces strict per-minute limits that tighten during market volatility — our checks catch the throttling windows other directories miss. Response shapes have shifted twice this year; see the change log below.', 2, 'https://docs.coingecko.com', 'https://api.coingecko.com/api/v3', 'apiKey', 'endpoint', 1, 1, '10k calls/mo demo key, no card', '~30/min, tightens under load', 0, 'unclear', 'Proprietary — attribution required', 'degraded', '2026-05-02', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (4, 'rest-countries', 'REST Countries', '🌍', 'Every country as clean JSON — flags, currencies, borders.', 'REST Countries answers with structured data for all 250 country codes: names, capitals, currencies, languages, borders and flag assets. Community-run and donation-funded, which our monitoring treats honestly: it is reliable but occasionally slow under load, and v3 broke v2 consumers — shape history below.', 7, 'https://restcountries.com', 'https://restcountries.com/v3.1', 'none', 'endpoint', 1, 1, 'Unlimited', 'None published', 0, 'yes', 'MPL-2.0', 'healthy', '2026-05-02', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (5, 'nominatim', 'Nominatim (OSM)', '📍', 'OpenStreetMap geocoding — powerful, with strict etiquette.', 'Nominatim turns addresses into coordinates and back using OpenStreetMap data. The public instance is free but governed by a strict usage policy: one request per second per application, a real User-Agent, and no heavy or commercial-primary use — self-host for that. We surface those terms up front because violating them gets apps banned.', 3, 'https://nominatim.org/release-docs/latest/api/Overview/', 'https://nominatim.openstreetmap.org', 'userAgent', 'endpoint', 1, 1, '1 req/sec, identified UA required', '1/sec hard — per application', 0, 'no', 'ODbL (OpenStreetMap)', 'healthy', '2026-05-02', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (6, 'pokeapi', 'PokéAPI', '⚡', 'The Pokémon dataset every tutorial is built on.', 'PokéAPI serves the full Pokémon universe — species, moves, types, sprites — as deeply linked JSON. It is the most-taught API on the internet and holds up under that traffic remarkably well. Fully static-cached, so latency is excellent worldwide.', 6, 'https://pokeapi.co/docs/v2', 'https://pokeapi.co/api/v2', 'none', 'endpoint', 1, 1, 'Unlimited (be reasonable)', 'None — locally cache please', 0, 'no', 'Fair-use fan data', 'healthy', '2026-05-02', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (7, 'nasa-apod', 'NASA APOD', '🪐', 'Astronomy Picture of the Day, straight from NASA.', 'NASA’s Astronomy Picture of the Day API returns the daily image with its explanation and metadata. A DEMO_KEY works instantly for prototyping; a free personal key raises the limits. Public-domain data, explicit yes to commercial use — one of the friendliest licenses in the catalog.', 4, 'https://api.nasa.gov', 'https://api.nasa.gov/planetary', 'apiKey', 'endpoint', 1, 1, '1,000 req/hour with free key', 'DEMO_KEY: 30/hour, 50/day', 0, 'yes', 'Public domain (US Gov)', 'healthy', '2026-05-02', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (8, 'open-library', 'Open Library', '📖', 'Books, authors and covers from the Internet Archive.', 'Open Library exposes bibliographic data for tens of millions of books — search, works, editions, covers — maintained by the Internet Archive. Great for reading apps and coursework. Bulk users should download the data dumps instead of crawling the API.', 7, 'https://openlibrary.org/developers/api', 'https://openlibrary.org', 'none', 'endpoint', 1, 1, 'Unlimited within courtesy limits', 'Soft — identified UA appreciated', 0, 'unclear', 'Mixed — mostly open', 'healthy', '2026-05-02', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (9, 'ipify', 'ipify', '🔌', 'Your public IP as JSON. One job, done perfectly.', 'ipify returns the caller’s public IP address. That is the entire API — which is exactly why it appears in half the networking tutorials ever written. Unlimited, CORS-open, commercial-friendly, and in five years of community memory it has effectively never been down.', 8, 'https://www.ipify.org', 'https://api.ipify.org', 'none', 'endpoint', 1, 1, 'Unlimited', 'None', 0, 'yes', 'n/a', 'healthy', '2026-05-02', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (10, 'agify', 'Agify', '🎂', 'Predicts age from a first name. Weirdly useful for demos.', 'Agify estimates a person’s age from their first name using aggregated census-style data. It is the canonical “my first fetch()” API: no key, instant JSON, CORS everywhere. Free tier covers 100 names a day; the paid tier is rarely needed outside batch jobs.', 6, 'https://agify.io', 'https://api.agify.io', 'none', 'endpoint', 1, 1, '100 names/day, no signup', '100/day per IP', 0, 'yes', 'Proprietary', 'healthy', '2026-05-02', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (11, 'dog-ceo', 'Dog CEO', '🐶', '20,000+ open-source dog photos by breed.', 'Dog CEO serves random dog images from the Stanford Dogs dataset, browsable by breed and sub-breed. Community-run and donation-backed. The single most wholesome endpoint in this directory, and our uptime data proves the dogs are dependable.', 5, 'https://dog.ceo/dog-api/', 'https://dog.ceo/api', 'none', 'endpoint', 1, 1, 'Unlimited', 'None published', 0, 'yes', 'Stanford Dogs dataset', 'healthy', '2026-05-02', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (12, 'wikipedia-rest', 'Wikipedia REST', '📰', 'Page summaries and extracts for anything on Wikipedia.', 'Wikimedia’s REST API returns clean page summaries — title, extract, thumbnail — perfect for hover cards and enrichment. Backed by Wikimedia’s serious infrastructure, so it is one of the most reliable free endpoints anywhere. Respect the etiquette: identified User-Agent, modest concurrency.', 7, 'https://en.wikipedia.org/api/rest_v1/', 'https://en.wikipedia.org/api/rest_v1', 'none', 'endpoint', 1, 1, 'Unlimited within etiquette', '200/sec global courtesy cap', 0, 'yes', 'CC BY-SA 4.0', 'healthy', '2026-05-09', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (13, 'open-notify', 'Open Notify', '🛰', 'Where is the ISS right now? A beloved API in decline.', 'Open Notify reports the live position of the International Space Station and who is in space. A classroom classic for a decade — but it is a single volunteer-run box, HTTP-only, and our checks show error rates climbing for weeks. Status: DYING. We list honest replacements below; consider wheretheiss.at.', 4, 'http://open-notify.org', 'http://api.open-notify.org', 'none', 'endpoint', 0, 0, 'Unlimited (volunteer-run)', 'Please be gentle', 0, 'unclear', 'n/a', 'dying', '2026-05-02', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (14, 'sunrise-sunset', 'Sunrise-Sunset', '🌅', 'Golden hour, civil twilight and day length for any point.', 'Returns sunrise, sunset and twilight times for any coordinates and date. No key required. Recently added to the directory — the NEW badge means it has under two weeks of monitoring history, so treat the early numbers gently.', 1, 'https://sunrise-sunset.org/api', 'https://api.sunrise-sunset.org', 'none', 'endpoint', 1, 1, 'Unlimited, attribution requested', 'No burst traffic', 0, 'unclear', 'n/a', 'new', '2026-06-22', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (15, 'coindesk-bpi', 'CoinDesk BPI', '🪦', 'The Bitcoin Price Index that powered a thousand tutorials.', 'CoinDesk’s free Bitcoin Price Index was the default “first crypto API” for a decade of blog posts. The v1 endpoint was retired and now refuses connections entirely. Archived here with its final known response shape so old tutorials can be understood — and updated.', 2, 'https://www.coindesk.com', 'https://api.coindesk.com/v1', 'none', 'endpoint', 1, 1, 'Was: unlimited', '—', 0, 'no', 'Proprietary', 'dead', '2026-05-02', NULL, '2026-05-14', 'Ten thousand tutorials called. Nobody answered.');
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (16, 'chartlyrics', 'ChartLyrics', '🪦', 'Song lyrics over SOAP/REST, from a gentler internet.', 'ChartLyrics offered lyric search back when SOAP was still a reasonable word to say out loud. The API now returns 404 on all documented routes and the domain serves a parking page. Archived with its last known shape. Rest easy.', 6, 'http://www.chartlyrics.com/api.aspx', 'http://api.chartlyrics.com', 'none', 'endpoint', 0, NULL, 'Was: unlimited', '—', 0, 'unclear', 'Unlicensed lyrics data', 'dead', '2026-05-02', NULL, '2026-06-02', '404: the music finally stopped.');
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (17, 'omdb', 'OMDb', '🎞', 'Movie and series metadata by title or IMDb ID.', 'The Open Movie Database returns plot, cast, ratings, runtime and poster art for films and shows. Query by title or tt-prefixed IMDb ID. Free tier with a personal key from omdbapi.com; the public patron key `trilogy` works for prototyping.', 13, 'https://www.omdbapi.com/', 'https://www.omdbapi.com', 'apiKey', 'endpoint', 1, NULL, '1,000 req/day free key', 'Patron key `trilogy` is shared — cache responses', 0, 'unclear', 'Community-contributed metadata', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (18, 'tmdb', 'TMDb', '🎬', 'Community movie and TV metadata at scale.', 'The Movie Database powers posters, cast, ratings, discover feeds and image CDN URLs for films and shows. Free API key after signup at themoviedb.org. Attribution required; commercial use needs separate approval from TMDb.', 13, 'https://developer.themoviedb.org/docs', 'https://api.themoviedb.org/3', 'apiKey', 'reachability', 1, NULL, 'Free personal API key', '~50 req/sec documented ceiling', 0, 'no', 'TMDb terms — attribution required', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (19, 'fanart-tv', 'Fanart.tv', '🖼', 'HD logos, posters and backgrounds for media libraries.', 'Fanart.tv serves artwork keyed by TMDB, TVDB or MusicBrainz IDs — ideal for Plex, Kodi and home-theater apps. Free API key after signup. Responses are JSON lists of image URLs with language and vote metadata.', 13, 'https://fanart.tv/api-docs/', 'https://webservice.fanart.tv/v3', 'apiKey', 'reachability', 1, NULL, 'Free personal API key', 'Unpublished', 0, 'unclear', 'Fanart.tv terms — user-contributed art', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (20, 'tvdb', 'TVDB', '📺', 'TV series, episode and artwork metadata.', 'TheTVDB v4 API covers series search, seasons, episodes, people and artwork references. Free personal API key at thetvdb.com. Bearer token auth; login endpoint exchanges key + pin for a short-lived JWT.', 13, 'https://thetvdb.com/api-information', 'https://api4.thetvdb.com/v4', 'apiKey', 'reachability', 1, NULL, 'Free personal API key', 'Unpublished', 0, 'unclear', 'TVDB terms — user-contributed data', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (21, 'lastfm', 'Last.fm', '🎵', 'Music metadata and scrobbling from listener data.', 'Last.fm API returns artist, album and track metadata plus similar-artist graphs built from scrobble data. Free API key after signup at last.fm/api. All calls require api_key in the query string; attribution to Last.fm required.', 13, 'https://www.last.fm/api', 'https://ws.audioscrobbler.com/2.0', 'apiKey', 'reachability', 1, NULL, 'Free personal API key', 'Unpublished', 0, 'unclear', 'Last.fm terms — attribution required', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (22, 'trakt', 'Trakt', '📺', 'Watch history, ratings and streaming availability for movies and TV.', 'Trakt.tv syncs what you watch across devices and exposes a JSON API for search, calendars, recommendations and streaming links. Free API key after OAuth app registration at trakt.tv/oauth/applications. Send Trakt-Api-Key and Trakt-Api-Version headers on every request.', 13, 'https://trakt.docs.apiary.io/', 'https://api.trakt.tv', 'apiKey', 'reachability', 1, NULL, 'Free OAuth application', '1,000 req every 5 min documented', 0, 'unclear', 'Trakt terms — user-contributed data', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (23, 'imdb-api', 'IMDb-API', '🎬', 'Unofficial IMDb metadata wrapper with a free tier.', 'imdb-api.com is a third-party JSON wrapper over IMDb titles, cast, ratings and images — not affiliated with Amazon/IMDb. Free RapidAPI-style key after signup; distinct from OMDb and from our keyless IMDbOT scraper. Check terms before commercial use.', 13, 'https://imdb-api.com/', 'https://imdb-api.com/en/API', 'apiKey', 'reachability', 1, NULL, 'Free tier with daily cap', 'Unpublished', 0, 'no', 'Third-party scrape — not official IMDb', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (24, 'simkl', 'Simkl', '📺', 'Trending movies, TV and anime with cross-IDs.', 'Simkl tracks watch history and publishes read-only JSON for trending titles, ratings and cross-refs to IMDb, TMDb and TVDB. Trending and lookup routes work without a key; search and user routes need a client_id from simkl.com/settings/developer.', 13, 'https://simkl.docs.apiary.io/', 'https://api.simkl.com', 'none', 'endpoint', 1, NULL, 'Free read routes; client_id for search', '1 req/s documented', 0, 'unclear', 'Simkl terms — user-contributed data', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (25, 'watchmode', 'Watchmode', '📡', 'Where to stream movies and shows by region.', 'Watchmode maps titles to Netflix, Prime, Disney+ and dozens of other services by country. Free tier after signup at watchmode.com — 1,000 requests/month. Complements TMDb watch/providers with a dedicated streaming-availability index.', 13, 'https://api.watchmode.com/docs/', 'https://api.watchmode.com/v1', 'apiKey', 'reachability', 1, NULL, 'Free — 1,000 req/month', '1,000 req/month (free tier)', 0, 'unclear', 'Watchmode terms', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (26, 'cat-facts', 'Cat Facts', '🐱', 'Random feline trivia served as tidy JSON', 'Hit one endpoint and get a random cat fact plus its character length, with no key or signup. It is handy filler for chatbots, loading screens, or an intro-to-REST demo. Responses are tiny, quick, and CORS-friendly.', 5, 'https://catfact.ninja/', 'https://catfact.ninja', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (27, 'http-dog', 'HTTP Dog', '🐶', 'Every HTTP status code described in JSON, with dog pics', 'Append a status code plus .json to get a small object with the code, its title, and links to matching dog images in several formats. It is a cousin of HTTP Cat, but this metadata endpoint actually returns JSON. Good for docs, error pages, or a laugh.', 5, 'https://http.dog/', 'https://http.dog', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (28, 'randomdog', 'RandomDog', '🐕', 'A random dog media URL wrapped in JSON', 'One GET returns the file size and a direct URL to a random dog photo or video. No key, no pagination, just woof. The media can be jpg, png, gif, or mp4, so check the extension before embedding.', 5, 'https://random.dog/woof.json', 'https://random.dog', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (29, 'jikan', 'Jikan', '🍥', 'Unofficial MyAnimeList data as a keyless REST API', 'Jikan mirrors MyAnimeList''s public pages into a clean, keyless JSON API covering anime, manga, characters, and more. Query by ID or search and get rich metadata like scores, episode counts, and airing status. Data is cached and read-only; MyAnimeList owns the underlying content.', 11, 'https://jikan.moe', 'https://api.jikan.moe', 'none', 'endpoint', 1, 1, 'Free, no API key', '3 requests/sec, 60 requests/min (per Jikan v4 docs)', 0, 'unclear', 'Unverified (source data from MyAnimeList)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (30, 'nekosbest', 'NekosBest', '🐈', 'Anime neko images and roleplay GIFs with artist credits', 'Fetch a random anime image or reaction GIF by category, each response carrying the source URL and artist attribution. No key is needed and results are SFW. Categories span neko portraits plus hug, pat, and other roleplay animations.', 11, 'https://docs.nekos.best', 'https://nekos.best', 'none', 'endpoint', 1, 1, 'Free, no key', 'Unpublished', 0, 'unclear', 'Unverified (images credited to their artists)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (31, 'trace-moe', 'Trace Moe', '🔎', 'Find the exact anime scene from a screenshot', 'Pass an image URL to /search and trace.moe returns the most likely anime, episode, and timestamp, plus preview clip links. It works keyless for casual use under a per-IP quota; an API key raises the limits. Every match includes a similarity score so you can judge confidence.', 11, 'https://soruly.github.io/trace.moe-api/#/', 'https://api.trace.moe', 'none', 'endpoint', 1, 1, 'Free, no key; per-IP search quota applies', 'Concurrency/quota limited per IP (check GET /me)', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (32, 'art-institute-of-chicago', 'Art Institute of Chicago', '🖼️', 'Museum collection metadata, mostly CC0, no key', 'Browse the Art Institute''s collection as JSON: artworks, artists, exhibitions, and IIIF image links. Metadata ships under CC0 (the description field is CC-BY), so it is friendly for apps and research. No key is required, though a contact User-Agent is appreciated.', 13, 'https://api.artic.edu/docs/', 'https://api.artic.edu', 'none', 'endpoint', 1, 1, 'Free, no key', '60 requests/min per IP (per docs)', 0, 'yes', 'CC0 1.0 for metadata; ''description'' field is CC-BY 4.0', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (33, 'emojihub', 'EmojiHub', '😀', 'Random or filtered emoji with unicode and HTML codes', 'Grab a random emoji or filter by category and group, getting back the name, unicode points, and HTML entity codes as JSON. No key, tiny payloads, and open CORS. It is built from an open-source project, so you can self-host if you prefer.', 13, 'https://github.com/cheatsnake/emojihub', 'https://emojihub.yurace.pro', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (34, 'bhagavad-gita-telugu', 'Bhagavad Gita telugu', '📖', 'Bhagavad Gita verses in Telugu, Odia, English, and Spanish', 'Request any chapter and verse to receive the original text, word-by-word synonyms, translation, and an audio link as JSON. Language codes cover Telugu (tel), Odia (odi), English (eng), and Spanish (esp). It is a small keyless FastAPI service that responds quickly.', 12, 'https://gita-api.vercel.app', 'https://gita-api.vercel.app', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (35, 'bible-api', 'Bible-api', '📖', 'Fetch Bible verses as clean JSON, no key required', 'Request any verse or passage by reference (like john+3:16) and get back structured JSON with the verse text and translation metadata. It ships with public-domain translations such as the World English Bible. No signup and no key.', 12, 'https://bible-api.com/', 'https://bible-api.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Public Domain (WEB translation; per translation_note in response)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (36, 'kdp-intelligence', 'KDP Intelligence', '📚', 'Kindle niche demand and competition scores via API', 'Query keyword-level demand scores, monthly search volume and availability for Kindle Direct Publishing niches. The preview and check endpoints are keyless and free, while deeper competition and revenue data unlocks through x402 USDC micropayments. It runs as a FastAPI service with an OpenAPI spec.', 12, 'https://kdp-intelligence-api.vercel.app/docs', 'https://kdp-intelligence-api.vercel.app', 'none', 'endpoint', 1, 0, 'Free preview/check endpoints; full niche data is paid via x402 USDC', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (37, 'poetrydb', 'PoetryDB', '🪶', 'A public-domain poetry database you can query as JSON', 'Pull poems by author, title, line count or keyword, or just grab a random one, from a large collection of public-domain verse. Every response is JSON carrying the title, author and full text lines. No key and no auth.', 12, 'https://github.com/thundercomb/poetrydb#readme', 'https://poetrydb.org', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified (public-domain poetry; project is MIT-licensed)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (38, 'quran', 'Quran', '☪️', 'The Quran.com API: chapters, verses and translations', 'The Quran.com API exposes chapter and verse metadata, multiple translations, recitations and more as JSON. This sample pulls chapter 1 (Al-Fatihah) with its Arabic and English names and verse count. The public content endpoints are keyless.', 12, 'https://quran.api-docs.io/', 'https://api.quran.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (39, 'quran-cloud', 'Quran Cloud', '🕌', 'Retrieve any Ayah, Surah or Juz of the Quran as JSON', 'AlQuran Cloud serves the full Holy Quran through a REST API: request a single ayah, a whole surah, a juz, or the complete text, in Arabic plus many editions and translations. This sample returns ayah 262 (Al-Baqara 255) with its surah, juz and page context. No key needed.', 12, 'https://alquran.cloud/api', 'https://api.alquran.cloud', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (40, 'quran-api', 'Quran-api', '📗', 'Quran text in 90+ languages, served free from a CDN', 'Fawaz Ahmed''s Quran API delivers the full text and 400+ translations across 90+ languages as static JSON files hosted on the jsDelivr CDN, so it is fast and has no rate limits. Fetch a whole edition, a single chapter, or one verse like this 1:1 sample. No key and no server call.', 12, 'https://github.com/fawazahmed0/quran-api#readme', 'https://cdn.jsdelivr.net/gh/fawazahmed0/quran-api@1', 'none', 'endpoint', 1, 1, 'Free, no key (static CDN JSON files)', 'None (served as static files from jsDelivr CDN)', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (41, 'urantia-papers', 'Urantia Papers', '🌌', 'Full-text and semantic search over the Urantia Papers', 'An agent-friendly API for the Urantia Papers, covering 197 papers and 17,000+ paragraphs with full-text and semantic search, structured content, entities and audio URLs. This sample pulls a random paragraph with its paper and section references. The public GET endpoints need no key.', 12, 'https://urantia.dev', 'https://api.urantia.dev', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (42, 'wizard-world', 'Wizard World', '🧙', 'Spells, elixirs and houses from the Harry Potter world', 'A community API for the wizarding world: query spells, elixirs, ingredients, houses and more, all as JSON. This sample lists spells with their incantations, effects and light colour. No key required.', 12, 'https://wizard-world-api.herokuapp.com/swagger/index.html', 'https://wizard-world-api.herokuapp.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (43, 'pick-an-agency', 'Pick an Agency', '🏢', 'Search 47k+ marketing agencies by service and location', 'Search a directory of tens of thousands of marketing and PR agencies, filtering by service, location and rating, and get structured agency profiles back as JSON. This sample searches for SEO agencies. The keyless REST endpoints live under /api/v1, alongside an OpenAPI spec and an MCP endpoint.', 2, 'https://www.pickanagency.com/developers', 'https://www.pickanagency.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (44, 'namedays-calendar', 'Namedays Calendar', '📅', 'Whose name day is it today, across many countries', 'Abalin''s Nameday API returns the name days celebrated on a given date across dozens of countries as JSON. Call /V2/today for the current date (UTC by default), or /V2/date with a day and month. The GET endpoints need no key.', 16, 'https://nameday.abalin.net', 'https://nameday.abalin.net/api', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (45, 'the-calendar', 'The Calendar', '🗓️', 'Static-JSON public holidays for US states and 30 countries', 'A CORS-open, no-auth API that serves public holidays for US states and 30 countries, plus sports and finance calendars, as plain static JSON files. This sample returns the 2026 US federal holidays, sourced from 5 U.S.C. § 6103. Browse /api/index.json for the full file list.', 16, 'https://the-calendar.net/api/', 'https://the-calendar.net', 'none', 'endpoint', 1, 1, 'Free, no auth (per site)', 'None stated (site advertises no rate limit)', 0, 'unclear', 'Unverified (US federal list per 5 U.S.C. § 6103)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (46, 'alpha-mossland', 'Alpha (Mossland)', '🪙', 'Korean crypto-channel stance and a canonical entity store', 'Mossland''s Alpha exposes a canonical store of crypto entities, topics and events as static JSON, plus RAG Q&A and a pulse feed. This sample hits the canonical topics file. The GET endpoints are keyless and CORS-open, though the canonical stores were empty at probe time.', 9, 'https://alpha.moss.land/developers', 'https://alpha.moss.land', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (47, 'block-lottos', 'Block Lottos', '🎰', 'On-chain lottery jackpots, draws and stats as JSON', 'A public API for the Block Lottos on-chain lottery: live jackpot amounts, draw history and site stats for its Polygon and Base ledgers, with no key required. This sample reads the current Polygon jackpot. A full OpenAPI spec is served at /openapi.json.', 9, 'https://blocklottos.com/openapi.json', 'https://blocklottos.com', 'none', 'endpoint', 1, 1, 'Free, no key (API docs state no key required)', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (48, 'coinpaprika', 'Coinpaprika', '🌶️', 'Crypto prices, volumes and market overview without a key', 'Coinpaprika''s REST API serves prices, volumes, market caps and coin metadata for thousands of cryptocurrencies. This sample is the global market overview: total market cap, 24h volume and BTC dominance. The free tier is keyless.', 9, 'https://api.coinpaprika.com', 'https://api.coinpaprika.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (49, 'national-bank-of-poland', 'National Bank of Poland', '🏦', 'Official NBP currency exchange rates in JSON or XML', 'The National Bank of Poland''s public API publishes official currency exchange rate tables, gold prices and historical archives, available as JSON or XML. This sample returns the current USD mid-rate from table A. No key required.', 2, 'http://api.nbp.pl/en.html', 'https://api.nbp.pl', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (50, 'paralelo-bo', 'paralelo.bo', '💱', 'Live Bolivia parallel USD/BOB rate, refreshed every minute', 'Returns the current parallel-market exchange rate between US dollars and Bolivianos, aggregated from peer-to-peer sources. Each response carries buy, sell, median, and spread figures alongside an ISO timestamp. A plain-text variant at /rate.txt suits shell pipelines.', 2, 'https://paralelo.bo/api', 'https://paralelo.bo/api/v1', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished (60s cache stated)', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (51, '24-pull-requests', '24 Pull Requests', '🎁', 'Suggested open-source projects for December contribution sprints', 'A community project that nudges developers to send pull requests throughout December. The JSON API exposes suggested projects, participating users, and organisations. Each project entry links a GitHub repo with its primary language.', 8, 'https://24pullrequests.com/api', 'https://24pullrequests.com', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (52, 'beeceptor', 'Beeceptor', '🐝', 'Free echo endpoint that mirrors your HTTP request back as JSON', 'Beeceptor''s open echo host reflects whatever request you send it, reporting the method, path, headers, and parsed query params as JSON. Handy for debugging clients or webhooks with no signup. The wider Beeceptor product for custom mock servers does require an account.', 8, 'https://beeceptor.com/', 'https://echo.free.beeceptor.com', 'none', 'endpoint', 1, 1, 'Free public echo host, no signup', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (53, 'genderize-io', 'Genderize.io', '🧑', 'Guess likely gender from a first name, with a confidence score', 'Send a first name and get back a predicted gender plus a probability and the sample size behind it. No key is needed for light use, and response headers report your remaining quota. Part of the same family as Nationalize.', 8, 'https://genderize.io', 'https://api.genderize.io', 'none', 'endpoint', 1, 1, 'Keyless usage limited (x-rate-limit-limit: 25 observed); 2,500 names/mo with a free key', 'Keyless cap 25 per x-rate-limit-limit header; remaining/reset exposed in response headers', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (54, 'httpbin', 'Httpbin', '🔁', 'Echo service for inspecting HTTP requests and responses', 'A long-running testing endpoint that reflects request details, headers, and origin back as JSON. Useful for checking exactly what your HTTP client sends. The /get route returns a tidy summary of the incoming call.', 8, 'https://httpbin.org/', 'https://httpbin.org', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (55, 'jsdelivr', 'jsDelivr', '📦', 'Package versions and CDN download stats as JSON', 'Query metadata for any npm or GitHub package served by the jsDelivr CDN, including version lists and resolved dist-tags. A companion stats API reports download counts. No key required.', 8, 'https://github.com/jsdelivr/data.jsdelivr.com', 'https://data.jsdelivr.com/v1', 'none', 'endpoint', 1, 1, 'Free, no key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (56, 'jsonplaceholder', 'JSONPlaceholder', '🧩', 'Instant fake REST data for prototyping and demos', 'A zero-setup REST endpoint serving invented posts, todos, users, and comments as JSON. Reads return canned data, while writes are accepted but never persisted. Ideal for wiring up a frontend before a real backend exists.', 8, 'https://jsonplaceholder.typicode.com', 'https://jsonplaceholder.typicode.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (57, 'nationalize-io', 'Nationalize.io', '🌍', 'Predict likely nationalities behind a first name', 'Give it a first name and it returns a ranked list of country codes with probabilities. Works keyless for small volumes, with quota reported via response headers. Shares infrastructure with Genderize.', 8, 'https://nationalize.io', 'https://api.nationalize.io', 'none', 'endpoint', 1, 1, 'Keyless usage limited (x-rate-limit-limit: 25 observed); 2,500 names/mo with a free key', 'Keyless cap 25 per x-rate-limit-limit header; remaining/reset exposed in response headers', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (58, 'networkcalc', 'NetworkCalc', '🧮', 'DNS lookups, subnet math, and network tools over JSON', 'A keyless API covering DNS record lookups, IP and subnet calculations, and related networking utilities. The DNS endpoint returns A, MX, NS, TXT and other records in a single JSON payload. Separate account-only endpoints exist, but the core tools need no auth.', 8, 'https://networkcalc.com/api/docs', 'https://networkcalc.com/api', 'none', 'endpoint', 1, 1, 'Free public API, no key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (59, 'wiktionary', 'Wiktionary', '📖', 'Query the crowd-built dictionary through MediaWiki''s action API', 'The English Wiktionary is served by the same MediaWiki action API that powers Wikipedia, so you can pull definitions, etymologies and translations as structured JSON. Ask for the extract, wikitext, or any prop you like via query parameters. No key, no signup — just the standard MediaWiki endpoint.', 12, 'https://en.wiktionary.org/w/api.php', 'https://en.wiktionary.org/w', 'none', 'endpoint', 1, 0, 'Free — public MediaWiki action API', 'No hard published cap; Wikimedia User-Agent policy and request-etiquette apply', 0, 'yes', 'Content under CC BY-SA 4.0 / GFDL', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (60, 'disify', 'Disify', '🗑️', 'Flag disposable and throwaway email addresses in one GET', 'Disify checks an email address or domain and tells you whether it is disposable, whether the domain has valid DNS/MX records, and a confidence score with the signals behind it. Handy for filtering burner addresses out of signup flows. Just append the address to the path and read the JSON.', 16, 'https://www.disify.com/', 'https://www.disify.com/api', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (61, 'kickbox', 'Kickbox', '✉️', 'Kickbox''s open, keyless disposable-domain lookup', 'Kickbox exposes a free open endpoint that answers a single yes/no question: is this address on a known disposable/temporary email domain? Pass any email and get back a tiny JSON boolean. It is a subset of Kickbox''s paid verification suite, but this check needs no account.', 16, 'https://open.kickbox.com/', 'https://open.kickbox.com/v1', 'none', 'endpoint', 1, 1, 'Free — open disposable-address check', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (62, 'mail-tm', 'mail.tm', '📨', 'Spin up throwaway inboxes over a JSON:LD REST API', 'mail.tm is a temporary-email service with a clean REST API for creating disposable mailboxes and reading messages. The /domains endpoint lists which mail domains are currently available to register against, and it needs no authentication. Responses come back as Hydra/JSON-LD collections.', 16, 'https://docs.mail.tm', 'https://api.mail.tm', 'none', 'endpoint', 1, 1, 'Free — temporary mailboxes', 'Rate limited (429 on exceed); exact policy per docs.mail.tm', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (63, 'jokeapi', 'JokeAPI', '😂', 'Filterable jokes with a safe-mode switch and NSFW flags', 'JokeAPI serves single-line or two-part jokes across categories, with query flags to blacklist nsfw/racist/sexist/etc. content or force a clean safe-mode. Every response carries the flags so you know exactly what you got. No key required.', 6, 'https://v2.jokeapi.dev/', 'https://v2.jokeapi.dev', 'none', 'endpoint', 1, 1, 'Free — no key', '120 requests/minute per IP (per jokeapi.dev docs)', 0, 'unclear', 'Unverified (open-source project)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (64, 'corporate-buzz-words', 'Corporate Buzz Words', '💼', 'Generate one fresh corporate buzz-phrase per request', 'A tiny open-source generator that returns a single randomly assembled slice of corporate jargon, like "Credibly Engage Transparent Technology". Great for placeholder copy, mission-statement gags, or seeding demos. One GET, one phrase.', 6, 'https://github.com/sameerkumar18/corporate-bs-generator-api', 'https://corporatebs-generator.sameerkumar.website', 'none', 'endpoint', 1, 1, 'Free — no key', 'Unpublished', 0, 'unclear', 'Unverified (open-source)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (65, 'potterdb', 'PotterDB', '⚡', 'Harry Potter characters, spells and potions as JSON:API', 'PotterDB is an open database of the Harry Potter universe — characters, spells, potions, books and movies — served over a paginated JSON:API. Each character record carries house, species, blood status, wands and more. No key needed; page through with page[size] and page[number].', 6, 'https://docs.potterdb.com/', 'https://api.potterdb.com/v1', 'none', 'endpoint', 1, 1, 'Free — no key', 'Unpublished', 0, 'unclear', 'Unverified (data derived from Harry Potter Fandom, CC BY-SA)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (66, 'open-brewery-db', 'Open Brewery DB', '🍺', 'Search breweries, brewpubs and bottle shops worldwide', 'Open Brewery DB is a free directory of breweries, cideries and craft-beer bottle shops with names, types, addresses and geo-coordinates. Filter by city, state, type or name, or page through the whole set. No authentication required.', 14, 'https://www.openbrewerydb.org', 'https://api.openbrewerydb.org/v1', 'none', 'endpoint', 1, 1, 'Free — no key', 'Unpublished', 0, 'unclear', 'Unverified (open dataset)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (67, 'cheapshark', 'CheapShark', '🦈', 'Live PC-game deals and prices across digital stores', 'CheapShark aggregates current sale prices for PC/Steam games across dozens of storefronts and exposes them as JSON. The /deals feed returns titles with sale vs. normal price, savings percentage, store and Steam IDs, and Metacritic/Steam ratings. Keyless and CORS-friendly.', 11, 'https://www.cheapshark.com/api', 'https://www.cheapshark.com/api/1.0', 'none', 'endpoint', 1, 1, 'Free — no key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (68, 'foodish', 'Foodish', '🍕', 'One random food photo URL per call', 'Foodish returns the URL of a random food photograph — pizza, dosa, biryani and more — as a one-key JSON object. It is an open-source project meant for placeholders, demos and food-themed toys. Hit the endpoint, get an image link.', 14, 'https://github.com/surhud004/Foodish#readme', 'https://foodish-api.com', 'none', 'endpoint', 1, 1, 'Free — no key', 'Unpublished', 0, 'unclear', 'Unverified (open-source)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (69, 'sec-edgar-data', 'SEC EDGAR Data', '📊', 'Public-company filings and facts straight from the SEC', 'The SEC''s EDGAR data API serves filing histories and company facts for every US public company as JSON, keyed by CIK. The submissions endpoint returns a company''s identity, tickers, exchanges and recent filings. It is US-government public data; the SEC requires a descriptive User-Agent and rate-limits fair use.', 2, 'https://www.sec.gov/edgar/sec-api-documentation', 'https://data.sec.gov', 'none', 'endpoint', 1, 1, 'Free — public government data', 'Max 10 requests/second; descriptive User-Agent required (SEC fair-access policy)', 0, 'yes', 'Public domain (U.S. government work)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (70, 'justmeme-wtf', 'justmeme.wtf', '🖼️', 'Meme templates: browse, search, trend and randomize', 'justmeme.wtf offers a keyless JSON API over a large library of meme templates, with endpoints for listing, searching, trending, categories and a random pick. Each template comes back with a name, slug and image URL. CORS is open and no signup is needed.', 6, 'https://justmeme.wtf/api-docs', 'https://justmeme.wtf/api/v1', 'none', 'endpoint', 1, 1, 'Free — no key', '60 requests/minute per IP (per docs)', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (71, 'ibanforge', 'IBANforge', '🏦', 'IBAN validation and BIC lookup with a free keyless demo', 'IBANforge validates IBANs and looks up BIC/SWIFT codes across dozens of countries, backed by 121K+ BIC entries. The keyless /v1/demo endpoint returns worked examples showing the full validation shape (country, check digits, BBAN, SEPA reachability, BIC). Live queries need a free API key or an x402/USDC micropayment.', 2, 'https://api.ibanforge.com', 'https://api.ibanforge.com', 'none', 'endpoint', 1, 0, '200 requests/month with a free API key; /v1/demo and /health are keyless', 'Unpublished (200/month free quota)', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (72, 'astroworld', 'Astroworld', '⛏️', 'Minecraft game data: mobs, items, biomes, versions and more', 'Astroworld is a keyless REST API of Minecraft reference data — mobs, items, biomes, enchantments, structures, commands, versions and achievements. Mob records include HP, per-difficulty damage, drops, spawn conditions and behaviour notes. Filter with search/type/category params and add ?pretty=true for formatted output.', 11, 'https://api.astroworldmc.com', 'https://api.astroworldmc.com/api/v1', 'none', 'endpoint', 1, 1, 'Free — no key', 'Unpublished', 0, 'unclear', 'Unverified (Minecraft game data; Mojang content)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (73, 'barter-vg', 'Barter.VG', '🎮', 'Game, DLC, bundle and giveaway data for trading', 'Barter.vg is a game-trading tracker whose pages expose JSON by appending /json to routes — user libraries and wishlists, item lookups, bundles and giveaways. The Steam-app lookup returns a game''s trade stats: how many users have it tradable, wishlisted or in-library, plus pricing and release info. No key required.', 11, 'https://github.com/bartervg/barter.vg/wiki', 'https://barter.vg', 'none', 'endpoint', 1, 1, 'Free — no key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (74, 'cross-universe', 'Cross Universe', '🃏', 'Card data for the fan-made Cross Universe TCG', 'Cross Universe is a free fan-made trading card game, and this API returns full card data as JSON by card ID and language. Each record includes name, level, card type, attack/defense, types and structured effect text. Keyless with open CORS; the base path also serves card images.', 11, 'https://crossuniverse.net/apiDocs', 'https://crossuniverse.net', 'none', 'endpoint', 1, 1, 'Free — no key', 'Unpublished', 0, 'unclear', 'Unverified (fan project)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (75, 'disney', 'Disney', '🏰', 'Characters, films and park attractions of the Disney universe', 'A community-run catalog of Disney characters covering the films, shorts, TV shows and video games they appear in. Query the paginated /character endpoint for names, images and cross-references. No key required and CORS is wide open.', 11, 'https://disneyapi.dev', 'https://api.disneyapi.dev', 'none', 'endpoint', 1, 1, 'Free, no API key required', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (76, 'open5e', 'Open5e', '🐉', 'Open D&D 5e SRD monsters, spells and rules as JSON', 'A REST API over the Dungeons & Dragons 5e System Reference Document, serving monsters, spells, classes and magic items. Records are searchable and paginated, so you can pull a single stat block or crawl the whole bestiary. Built on openly licensed SRD content, no key needed.', 11, 'https://open5e.com/', 'https://api.open5e.com', 'none', 'endpoint', 1, 1, 'Free, no API key required', 'Unpublished', 0, 'unclear', 'SRD content under OGL 1.0a; API/site MIT-licensed', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (77, 'ffxiv-collect', 'FFXIV Collect', '🏆', 'Every Final Fantasy XIV mount, minion and collectable', 'Tracks the collectables of Final Fantasy XIV: mounts, minions, orchestrion rolls, achievements, hairstyles and more. Endpoints return rich descriptions, rarity data and in-game tooltips. Free and keyless with permissive CORS.', 11, 'https://ffxivcollect.com/', 'https://ffxivcollect.com/api', 'none', 'endpoint', 1, 1, 'Free, no API key required', 'Unpublished', 0, 'unclear', 'Unverified; game content © Square Enix', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (78, 'xivapi', 'XIVAPI', '⚔️', 'Final Fantasy XIV game data, servers and lore', 'A datamined API exposing Final Fantasy XIV game content: items, quests, recipes and live world/server lists. The keyless /servers endpoint returns current world names as a plain JSON array. An optional free key raises rate limits for heavier use.', 11, 'https://xivapi.com/', 'https://xivapi.com', 'none', 'endpoint', 1, 1, 'Free; optional free key raises limits', 'Rate-limited; higher limits with a free key (see docs)', 0, 'unclear', 'Unverified; game content © Square Enix', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (79, 'freetogame', 'FreeToGame', '🎮', 'Searchable database of free-to-play PC and browser games', 'A catalog of free-to-play titles across PC and browser, complete with genres, platforms, publishers and release dates. The /games endpoint returns the full list, and filters let you narrow by category or platform. No signup or key required.', 11, 'https://www.freetogame.com/api-doc', 'https://www.freetogame.com/api', 'none', 'endpoint', 1, 1, 'Free, no API key required', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (80, 'gamerpower', 'GamerPower', '🎁', 'Live tracker of game giveaways, loot and beta keys', 'Aggregates current game giveaways, free DLC, loot drops and beta keys from stores and platforms across the web. Each entry lists worth, platform, instructions and expiry so you know what is still claimable. Keyless JSON with open CORS.', 11, 'https://www.gamerpower.com/api-read', 'https://www.gamerpower.com/api', 'none', 'endpoint', 1, 1, 'Free, no API key required', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (81, 'geek-jokes', 'Geek Jokes', '🤓', 'One random geeky or programming joke per request', 'A tiny endpoint that returns a single random nerdy or programming-flavored joke. Ask for plain text, or with ?format=json get a neat JSON object. No key, ideal for a CLI splash screen or a chat bot.', 11, 'https://github.com/sameerkumar18/geek-joke-api', 'https://geek-jokes.sameerkumar.website', 'none', 'endpoint', 1, 1, 'Free, no API key required', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (82, 'genshin-impact', 'Genshin Impact', '⭐', 'Community data on Genshin Impact characters and lore', 'A community project serving Genshin Impact game data: characters, weapons, artifacts, elements and more. The /characters endpoint returns a JSON array of slugs you can drill into for stats and art. Fan-maintained, free and keyless.', 11, 'https://genshin.dev', 'https://genshin.jmp.blue', 'none', 'endpoint', 1, 1, 'Free, no API key required', 'Unpublished', 0, 'unclear', 'Unverified; community project', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (83, 'monster-hunter-world', 'Monster Hunter World', '🦖', 'Monsters, weapons and items from Monster Hunter: World', 'A structured dataset for Monster Hunter: World covering monsters, their elemental weaknesses and rewards, plus weapons, armor and items. The /monsters endpoint returns full records including habitats and drop tables. No key required, CORS enabled.', 11, 'https://docs.mhw-db.com/', 'https://mhw-db.com', 'none', 'endpoint', 1, 1, 'Free, no API key required', 'Unpublished', 0, 'unclear', 'Unverified; game content © Capcom', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (84, 'rick-and-morty', 'Rick and Morty', '🛸', 'Characters, locations and episodes from Rick and Morty', 'The full Rick and Morty universe as JSON: characters with status and origin, locations, and episode listings, images included. Fetch a single character by id or page through the whole cast. Free, keyless and CORS-friendly.', 11, 'https://rickandmortyapi.com', 'https://rickandmortyapi.com/api', 'none', 'endpoint', 1, 1, 'Free, no API key required', 'Unpublished', 0, 'unclear', 'Unverified; open-source project', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (85, 'scryfall', 'Scryfall', '🃏', 'Comprehensive Magic: The Gathering card database', 'A deep Magic: The Gathering API with every card, set, ruling and high-resolution scan. The /cards/random endpoint hands back a full card object; fuzzy name search and Scryfall-syntax queries are also available. Keyless, though the maintainers ask for a small delay between requests.', 11, 'https://scryfall.com/docs/api', 'https://api.scryfall.com', 'none', 'endpoint', 1, 1, 'Free, no API key required', '~10 requests/second; docs ask for 50-100 ms between requests', 0, 'unclear', 'Card data free to use; MTG content © Wizards of the Coast (see docs)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (86, 'universalis', 'Universalis', '📈', 'Crowdsourced Final Fantasy XIV market board prices', 'A crowdsourced market board aggregator for Final Fantasy XIV, exposing live listings, sale history and per-world price data. The /data-centers endpoint lists every data center and its worlds so you can target the right market. Free and keyless.', 11, 'https://universalis.app/docs/index.html', 'https://universalis.app/api/v2', 'none', 'endpoint', 1, 1, 'Free, no API key required', 'Unpublished', 0, 'unclear', 'Unverified; crowdsourced data', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (87, 'administrative-divisions-db', 'Administrative Divisions DB', '🗺️', 'First-level administrative divisions for every country', 'A dataset of first-level administrative divisions (states, provinces, counties) keyed by ISO country code. Each request returns a plain JSON array of division names, served as static files over a CDN so there are no rate limits. Fetch by country code, no key needed.', 3, 'https://github.com/kamikazechaser/administrative-divisions-db', 'https://rawcdn.githack.com/kamikazechaser/administrative-divisions-db/master/api', 'none', 'endpoint', 1, 1, 'Free, no API key required (static JSON via CDN)', 'None (static files served over CDN)', 0, 'unclear', 'Unverified (see repo)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (88, 'country-is', 'Country.is', '🌍', 'Look up a visitor''s country from their IP, no key', 'A minimalist endpoint that resolves the caller''s IP address to a two-letter country code. Hit the root URL to geolocate yourself, or pass any IP to look it up. Free, keyless and CORS-enabled for browser use.', 3, 'https://country.is/', 'https://api.country.is', 'none', 'endpoint', 1, 1, 'Free, no API key required', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (89, 'geojs', 'GeoJS', '📍', 'IP geolocation as JSON, JSONP or plain text', 'IP geolocation returning city, region, country, ASN and coordinates for the caller or any address. Output is available as JSON, JSONP or plain text, handy from browsers and shells alike. Free with no key and generous CORS.', 3, 'https://www.geojs.io/', 'https://get.geojs.io', 'none', 'endpoint', 1, 1, 'Free, no API key required', 'Unpublished (no enforced limit stated)', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (90, 'hackmyip', 'HackMyIP', '🛡️', 'Keyless IP geolocation, VPN scoring and breach checks', 'A no-signup toolkit API bundling IP geolocation, ISP and ASN data, VPN/proxy scoring, email breach lookups, and DNS/WHOIS queries. The /ip endpoint profiles the caller''s address with location, network and privacy details in one JSON payload. Every endpoint is keyless and CORS-enabled.', 3, 'https://hackmyip.com/api', 'https://hackmyip.com/api', 'none', 'endpoint', 1, 1, 'Completely free — no API key, no signup', 'Unpublished', 0, 'yes', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (91, 'psychonauts', 'Psychonauts API', '🧠', 'Characters and PSI powers from Double Fine''s Psychonauts', 'A fan tribute API for the cult game Psychonauts, serving its characters and PSI powers as JSON. Filter powers or characters by name, gender or a result limit. Hosted on Vercel, keyless, though it does not send CORS headers.', 11, 'https://github.com/thamudi/psychonauts-api/wiki/Endpoints', 'https://psychonauts-api.vercel.app/api', 'none', 'endpoint', 1, 0, 'Free, no API key required', 'Unpublished', 0, 'unclear', 'Unverified; fan tribute, game © Double Fine', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (92, 'ipapi-co', 'ipapi.co', '🌍', 'IP address to city, region, country, and coordinates', 'Point it at any IP address (or none, for the caller''s own) and it hands back location, network, timezone, and currency details as clean JSON. No key needed for light use; it answers with a 429 once you cross its quota.', 3, 'https://ipapi.co/api/#introduction', 'https://ipapi.co', 'none', 'endpoint', 1, 1, 'Free — quota not published; returns 429 when exceeded', 'Unpublished (429 Quota exceeded)', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (93, 'pinball-map', 'Pinball Map', '🕹️', 'Crowdsourced map of public pinball machines worldwide', 'A community-maintained directory of where to find real, playable pinball machines, organized by region. The keyless REST API lists regions, locations, and machines as JSON; maintainers just ask for attribution and no bulk hammering.', 3, 'https://pinballmap.com/api/v1/docs', 'https://pinballmap.com/api/v1', 'none', 'endpoint', 1, 1, 'Free — no key required', 'No hard limit; heavy/bulk use may be blocked', 0, 'unclear', 'Attribution requested; license unspecified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (94, 'postali', 'Postali', '📮', 'Keyless postal-code lookup for Mexico, Colombia & Spain', 'Resolve a postal code to its state, municipality, and neighborhoods across MX, CO, and ES with a single GET. No key, no signup, and CDN-cached JSON; a bare code with no country prefix defaults to Mexico.', 3, 'https://postali.app/api', 'https://postali.app/api/v1', 'none', 'endpoint', 1, 1, 'Free — no key, no signup, no monthly limit (per site)', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (95, 'postcodes-io', 'Postcodes.io', '🇬🇧', 'Free UK postcode lookup and geolocation, no key', 'Hand it a UK postcode and get back coordinates, ward, district, constituency, and administrative geography as JSON. Open source and free, with reverse-geocoding and autocomplete endpoints alongside the basic lookup.', 3, 'https://postcodes.io', 'https://api.postcodes.io', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished (no key; fair use)', 0, 'unclear', 'Service MIT-licensed; postcode data license unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (96, 'slf', 'SLF', '🎲', 'German word-game data: cities, countries, rivers by letter', 'A static JSON dataset for the German ''Stadt, Land, Fluss'' game, grouping example cities, countries, rivers, names, jobs, animals, brands, and plants under each starting letter. One keyless GET returns the whole letter-keyed object.', 3, 'https://github.com/slftool/slftool.github.io/blob/master/API.md', 'https://slftool.github.io', 'none', 'endpoint', 1, 1, 'Free — static file, no key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (97, 'brazil', 'Brazil', '🇧🇷', 'Community API for Brazilian public data (CEP, CNPJ, banks…)', 'A single friendly gateway to scattered Brazilian public datasets — postal codes (CEP), companies (CNPJ), banks, DDD area codes, holidays and more. This sample resolves a CEP to its street, neighborhood, city, and state. Keyless, but the maintainers ask you not to loop through every code.', 17, 'https://brasilapi.com.br/', 'https://brasilapi.com.br/api', 'none', 'endpoint', 1, 1, 'Free — no key (beta)', 'Fair use — no loops or full-range scanning', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (98, 'city-toronto-open-data', 'City, Toronto Open Data', '🏙️', 'Toronto''s open data catalog via a standard CKAN API', 'The City of Toronto publishes its open data through a standard CKAN backend. This endpoint lists every dataset package by id; from there you can pull each package''s metadata and downloadable resources. Keyless JSON, though it didn''t advertise CORS headers.', 17, 'https://open.toronto.ca/', 'https://ckan0.cf.opendata.inter.prod-toronto.ca/api/3/action', 'none', 'endpoint', 1, 0, 'Free — no key required (CKAN)', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (99, 'localgov-jp', 'LocalGov.jp', '🏯', 'Structured Japanese municipal grants & subsidies data', 'Normalizes grant and subsidy listings from 1,600+ Japanese municipalities into one searchable JSON API, each record linking back to the original government page. This search returns matching grants with issuer, prefecture, and eligibility. Currently free; an x402/USDC rail exists for future paid features.', 17, 'https://localgov.jp/', 'https://localgov.jp', 'none', 'endpoint', 1, 1, 'Free — all endpoints currently free (per llms.txt)', 'Unpublished', 0, 'yes', 'CC BY 4.0 (attribution: "via LocalGov.jp")', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (100, 'open-government-poland', 'Open Government, Poland', '🇵🇱', 'Poland''s national open-data portal as a JSON:API', 'dane.gov.pl exposes Poland''s open-data catalog through a versioned JSON:API. This endpoint pages through 25,000+ datasets with their titles, licenses, and modification dates; drill in for resources and downloads. Keyless, and many datasets carry CC0 or CC BY licenses.', 17, 'https://dane.gov.pl/en', 'https://api.dane.gov.pl', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Per dataset (many CC0 1.0 / CC BY)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (101, 'openmercantil', 'OpenMercantil', '🏢', 'Search Spanish companies and BORME event timelines', 'Look up Spanish companies by name and get back their CIF, slug, status, and activity counts, with deeper BORME (official gazette) event timelines available per company. No auth, open CORS, JSON only.', 17, 'https://openmercantil.es/api/documentacion', 'https://openmercantil.es', 'none', 'endpoint', 1, 1, 'Free — anonymous, no key', '60 req/min, 200 req/day per IP (anonymous)', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (102, 'lapis', 'LAPIS', '🧬', 'Query aggregated SARS-CoV-2 genomic sequence data', 'LAPIS (from CoV-Spectrum/GenSpectrum) serves aggregated statistics over open SARS-CoV-2 sequences — filter by mutation, lineage, date, or location and get counts back. This open instance needs no key and returns JSON, handy for genomic-epidemiology dashboards.', 14, 'https://cov-spectrum.ethz.ch/public', 'https://lapis.cov-spectrum.org/open/v2', 'none', 'endpoint', 1, 1, 'Free — no key (open instance)', 'Unpublished', 0, 'unclear', 'Open sequence data (GenBank/Nextstrain-derived); Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (103, 'longevity-world-cup', 'Longevity World Cup', '🏆', 'Biological-age competition data with biomarkers & rankings', 'Public leaderboard data from a biological-age contest: each athlete entry carries a division, country, and a set of blood and metabolic biomarkers. One GET returns the full athlete array as JSON, no key required.', 14, 'https://longevityworldcup.com/api/data/athletes', 'https://longevityworldcup.com', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (104, 'open-disease', 'Open Disease', '🦠', 'Free COVID-19 and influenza statistics, no key', 'disease.sh aggregates COVID-19 and influenza numbers from JHU, Worldometers, and other sources into one keyless JSON API. This endpoint returns global totals — cases, deaths, recovered, tests, and per-million rates. Free to use for widgets, dashboards, or apps.', 14, 'https://disease.sh/', 'https://disease.sh', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Unverified (sources vary; see project repo)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (105, 'ai-dev-jobs', 'AI Dev Jobs', '🤖', 'AI/ML engineering job listings, built for agents', 'Aggregates AI/ML developer jobs and exposes them through open REST (plus RSS and MCP) endpoints designed for agentic access. This search returns listings with title, company, and description. Public reads are free; an optional free key gives a stable identity and higher throttle.', 16, 'https://aidevboard.com/openapi.yaml', 'https://aidevboard.com/api/v1', 'none', 'endpoint', 1, 1, 'Free — public read endpoints open', 'Hourly abuse throttle; optional free API key', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (106, 'arbeitnow', 'Arbeitnow', '💼', 'European & remote job board aggregator', 'A single JSON feed of jobs aggregated from a European/remote job board, each entry carrying company, title, description, tags, location, and a remote flag. Keyless GET and paginated — good for building job widgets or feeds.', 16, 'https://documenter.getpostman.com/view/18545278/UVJbJdKh', 'https://www.arbeitnow.com/api', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (107, 'not-human-search', 'Not Human Search', '🤖', 'A search engine that ranks sites by how agent-ready they are', 'Not Human Search indexes websites and scores them on ''agentic readiness'' for AI agents and MCP servers. The keyless endpoints let you pull index stats, browse category buckets, and query top-scored or matching sites as JSON. Paid API-key plans exist, but reads like search and stats stay open.', 4, 'https://nothumansearch.ai/openapi.yaml', 'https://nothumansearch.ai/api/v1', 'none', 'endpoint', 1, 1, 'Free — no key for read endpoints (paid API-key plans offered)', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (108, 'tensorfeed', 'TensorFeed', '📡', 'JSON feeds of AI news, model prices, and agent activity', 'TensorFeed publishes machine-readable feeds covering AI headlines, model and GPU pricing, service status, and agent activity. Endpoints are plain keyless JSON documents you can poll on a schedule. Handy as a single source for ''what''s happening in AI'' without scraping.', 4, 'https://tensorfeed.ai/developers', 'https://tensorfeed.ai/api', 'none', 'endpoint', 1, 1, 'Free — no key (static JSON feed endpoints)', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (109, 'radio-browser', 'Radio Browser', '📻', 'Community directory of 59k+ internet radio stations', 'Radio Browser is a free, community-maintained catalog of internet radio streams searchable by name, tag, country, and language. The keyless JSON API also exposes aggregate stats like total stations and hourly click counts. It runs across several mirror hosts and just asks clients to send a descriptive User-Agent.', 13, 'https://api.radio-browser.info/', 'https://de1.api.radio-browser.info', 'none', 'endpoint', 1, 1, 'Free and open source — no key', 'Unpublished (clients asked to send a descriptive User-Agent)', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (110, 'florida-man', 'Florida Man', '🐊', '10,000+ real ''Florida Man'' headlines as static JSON by date', 'A tongue-in-cheek but real dataset of Florida Man news headlines, served as static JSON files on GitHub Pages. Fetch every headline for a given calendar date, a whole month, or the full index — each entry carries title, source, date, and extracted keywords. No key, no server, just files.', 7, 'https://github.com/juliayxhuang/florida-man-api#readme', 'https://juliayxhuang.github.io/florida-man-api', 'none', 'endpoint', 1, 1, 'Free — static JSON on GitHub Pages, no key', 'Unpublished (served via GitHub Pages)', 0, 'yes', 'MIT (repository license)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (111, 'noozra', 'Noozra', '🗞️', 'Aggregated news headlines from 200+ curated RSS sources', 'Noozra pulls headlines from a couple hundred curated RSS feeds and serves them as clean JSON. You can list recent articles, filter by category, or search by keyword. Each item includes headline, source, timestamp, image, and a short description.', 7, 'https://noozra.com/api', 'https://noozra.com/api', 'none', 'endpoint', 1, 1, 'Free tier available (pricing tiers published at /api/pricing)', 'Unpublished', 0, 'unclear', 'Unverified (aggregated RSS headlines)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (112, 'spaceflight-news', 'Spaceflight News', '🚀', 'News, blogs, and reports about spaceflight in one JSON API', 'The Spaceflight News API (SNAPI v4) aggregates articles, blogs, and reports from across the space industry. Results are paginated JSON with titles, summaries, source sites, and links, and can be tied to specific launches or events. No key required.', 7, 'https://spaceflightnewsapi.net', 'https://api.spaceflightnewsapi.net/v4', 'none', 'endpoint', 1, 1, 'Free — no key', 'Unpublished', 0, 'unclear', 'Unverified (links/metadata for third-party news)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (113, 'microlink-io', 'Microlink.io', '🔗', 'Turn any URL into structured title, description, image, and more', 'Microlink fetches a web page and returns its metadata — title, description, author, publisher, language, and preview image — as JSON. Pass a target URL as a query parameter and get back a normalized object plus the upstream response headers. The free tier is keyless and rate-limited; paid plans unlock more.', 7, 'https://microlink.io', 'https://api.microlink.io', 'none', 'endpoint', 1, 1, 'Free tier — no key required (Pro plans need a key)', 'Free tier is rate-limited per day (see pricing)', 0, 'unclear', 'N/A — returns metadata extracted from the URL you pass', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (114, 'modelpartfinder-error-codes', 'ModelPartFinder Error Codes', '🔧', 'Look up appliance error codes and the parts that fix them', 'ModelPartFinder maps appliance and equipment error codes to plain-English explanations and suggested replacement parts. Query by brand and code to get the fault description, the affected appliance type, and recommended part SKUs with prices. Keyless JSON, one lookup per request.', 7, 'https://modelpartfinder.com/docs/api', 'https://modelpartfinder.com/api/v1', 'none', 'endpoint', 1, 1, 'Free — no key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (115, 'nobel-prize', 'Nobel Prize', '🏅', 'Official open data on Nobel Prizes and laureates since 1901', 'The Nobel Prize''s own API serves structured data about prizes, categories, and laureates going back to 1901. Each prize record includes the year, category, award amounts, and the people honored with their motivations. Multilingual labels (English, Norwegian, Swedish) come baked in, no key needed.', 7, 'https://www.nobelprize.org/about/developer-zone-2/', 'https://api.nobelprize.org/2.1', 'none', 'endpoint', 1, 1, 'Free — no key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (116, 'open-scholarships', 'Open Scholarships', '🎓', 'Openly-licensed directory of US scholarships and student aid', 'Open Scholarships is a machine-readable, CC BY 4.0 directory of US scholarships sourced from official pages. Filter by state, availability, or keyword to get structured records with sponsor, award amounts, deadlines, and eligibility. Responses ship with the required attribution string built in.', 7, 'https://scholarships.grudged.io', 'https://scholarships.grudged.io/api', 'none', 'endpoint', 1, 1, 'Free — no key (CC BY 4.0; attribution required)', 'Unpublished', 0, 'yes', 'CC BY 4.0', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (117, 'statistics-of-the-world', 'Statistics of the World', '📊', 'Economic indicators for 218 countries from World Bank & IMF', 'Statistics of the World bundles hundreds of economic and demographic indicators — GDP, population, inflation, and more — for countries worldwide, drawing on World Bank and IMF data. Ask for a country by ISO code and get a tidy JSON profile plus its indicator values and years. An API-key header is optional, not required.', 7, 'https://statisticsoftheworld.com/api-docs', 'https://statisticsoftheworld.com/api/v1', 'none', 'endpoint', 1, 1, 'Free — no key (optional X-API-Key header)', 'Unpublished', 0, 'unclear', 'Unverified (data sourced from World Bank & IMF)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (118, 'umea-open-data', 'Umeå Open Data', '🇸🇪', 'Open data portal for the Swedish city of Umeå', 'Umeå''s municipal open data portal (built on OpenDataSoft) publishes datasets about the northern Swedish city, from energy consumption to geography. The Explore v2.1 API lets you browse the catalog and query records as JSON, with bilingual Swedish/English field labels. No key required.', 7, 'https://opendata.umea.se/api/', 'https://opendata.umea.se/api/explore/v2.1', 'none', 'endpoint', 1, 1, 'Free — open data portal, no key', 'Unpublished', 0, 'unclear', 'Varies by dataset (municipal open data; see portal)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (119, 'github-contribution-chart-generator', 'GitHub Contribution Chart Generator', '🟩', 'Fetch anyone''s GitHub contribution totals as JSON by year', 'Behind the contribution-chart image generator sits a JSON endpoint that returns a GitHub user''s yearly contribution totals and date ranges. Pass a username and get an array of years with totals — handy for building your own visualizations. It scrapes live, so responses can be slow and don''t include CORS headers.', 7, 'https://github-contributions.vercel.app', 'https://github-contributions.vercel.app/api/v1', 'none', 'endpoint', 1, 0, 'Free — no key', 'Unpublished', 0, 'unclear', 'Unverified (derived from public GitHub profile data)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (120, 'kanye-rest', 'kanye.rest', '🎤', 'A REST API that returns random Kanye West quotes', 'kanye.rest does exactly one thing: return a random Kanye West quote as JSON. Hit the root endpoint and you get a single ''quote'' field back. Keyless, CORS-friendly, and gloriously single-purpose.', 6, 'https://kanye.rest', 'https://api.kanye.rest', 'none', 'endpoint', 1, 1, 'Free — no key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (121, 'personality-fyi', 'Personality.fyi', '🧠', 'Free MBTI type data and OEJTS test items with scoring', 'Personality.fyi is a no-auth JSON API for the 16 MBTI personality types plus the open-source OEJTS test. Look up a type by its four-letter code to get its name, cognitive style, strengths, and blind spots, or pull test items and scoring. Everything is keyless and CORS-enabled.', 6, 'https://personality.fyi/api', 'https://personality.fyi/api/v1', 'none', 'endpoint', 1, 1, 'Free — no auth', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (122, 'zen-quotes', 'Zen Quotes', '☯️', 'Inspirational quotes as JSON, including a daily pick', 'Zen Quotes serves a large collection of inspirational quotes through a simple keyless API. Grab a random quote, the quote of the day, or a batch, each with author and a ready-made HTML blockquote. The free tier is rate-limited and asks for an attribution link when used publicly.', 6, 'https://zenquotes.io/', 'https://zenquotes.io/api', 'none', 'endpoint', 1, 0, 'Free — no key', 'Rate-limited on the free tier (see zenquotes.io)', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (123, 'launch-library-2', 'Launch Library 2', '🛰️', 'Database of rocket launches, agencies, and space events', 'Launch Library 2, by The Space Devs, is a detailed database of past and upcoming rocket launches, providers, pads, and related events. Query upcoming launches to get status, timing windows, launch provider, and rocket details as JSON. It''s keyless, but anonymous requests are throttled to a low rate.', 4, 'https://thespacedevs.com/llapi', 'https://ll.thespacedevs.com/2.2.0', 'none', 'endpoint', 1, 1, 'Free — no key (The Space Devs LL2)', 'Anonymous requests are throttled to a low rate (see docs)', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (124, 'openalex', 'OpenAlex', '📚', 'Open index of 300M+ scholarly works, authors, and venues', 'OpenAlex is a free, CC0 catalog of the global research graph — works, authors, institutions, sources, and concepts. Query works and get rich JSON records with DOIs, titles, open-access locations, and identifiers. Basic requests work without a key; a free key raises the usage limits.', 4, 'https://docs.openalex.org/', 'https://api.openalex.org', 'none', 'endpoint', 1, 1, 'Free tier (~$1/day of usage); free API key available for more', 'Usage-metered free tier (~$1/day per docs)', 0, 'yes', 'CC0', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (125, 'dead-drop', 'dead-drop', '🔐', 'Ephemeral zero-knowledge encrypted drops over a keyless API', 'dead-drop hands out self-destructing, client-encrypted data drops that the server never sees in plaintext. Keyless GET routes mint random drop names and report health, while creating or reading a drop runs through its documented terms-gated flow. Handy for one-time secret handoffs between machines or people.', 15, 'https://api.dead-drop.xyz/api/v1/docs', 'https://api.dead-drop.xyz/api/v1', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (126, 'bluesky', 'Bluesky', '🦋', 'Read public AT Protocol social data with no key or login', 'Bluesky''s public AppView exposes profiles, posts, feeds and follows over plain XRPC calls. Read-only lookups such as fetching a profile work with no key, no login and open CORS. Write actions and private data still require an authenticated session.', 16, 'https://docs.bsky.app/', 'https://public.api.bsky.app', 'none', 'endpoint', 1, 1, 'Free — public AppView, no key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (127, 'lanyard', 'Lanyard', '🎮', 'Expose a Discord user''s live presence as JSON or WebSocket', 'Lanyard mirrors a Discord member''s real-time presence, status and activities into a simple REST and WebSocket feed. Any user tracked by the public Lanyard bot can be read by their Discord ID with no key. To track your own account you first join the Lanyard Discord server.', 16, 'https://github.com/Phineas/lanyard', 'https://api.lanyard.rest', 'none', 'endpoint', 1, 1, 'Free — no key; user must be tracked by the Lanyard Discord bot', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (128, 'discgolf', 'DiscGolf', '🥏', 'Structured disc golf course data with coordinates and layouts', 'DiscGolfAPI serves a curated catalog of disc golf courses with coordinates, layouts, operational status and confidence scoring. Public course endpoints return JSON with no API key, tagged with attribution and licensing metadata. Filter by country and page through the listings to feed maps or apps.', 14, 'https://discgolfapi.com/docs/', 'https://io.discgolfapi.com/v1', 'none', 'endpoint', 1, 1, 'Free — public endpoints, no key', 'Unpublished', 0, 'unclear', 'Free to use with attribution (per response metadata)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (129, 'openf1', 'OpenF1', '🏎️', 'Open Formula 1 telemetry, laps, sessions and positions as JSON', 'OpenF1 publishes Formula 1 data, from session schedules and lap times to car telemetry and driver positions. Historical queries are open and keyless, returning tidy JSON arrays you can filter by year, session or driver. Live real-time access may require a free account.', 14, 'https://openf1.org/', 'https://api.openf1.org/v1', 'none', 'endpoint', 1, 1, 'Free & open (historical); real-time may require a free account', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (130, 'openligadb', 'OpenLigaDB', '⚽', 'Crowd-sourced football league fixtures and results, no key', 'OpenLigaDB is a community-maintained store of football match data, centered on the German Bundesliga but covering other competitions too. Grab matchdays, fixtures, results and team info as JSON with no key. The data is contributed and moderated by volunteers.', 14, 'https://www.openligadb.de', 'https://api.openligadb.de', 'none', 'endpoint', 1, 1, 'Free — no key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (131, 'padel-snipe', 'Padel Snipe', '🎾', 'Thousands of mapped padel clubs across Europe, CC-BY licensed', 'Padel Snipe publishes a geolocated dataset of padel clubs across several European countries plus a few beyond. One keyless GET returns every club with coordinates, court counts and booking platform, cached daily at the edge. The data ships under CC-BY 4.0, so commercial reuse is fine with attribution.', 14, 'https://padelsnipe.com/fr/world/api', 'https://padelsnipe.com/api', 'none', 'endpoint', 1, 1, 'Free — no auth', 'Fair use — no hard limit stated', 0, 'yes', 'CC-BY 4.0', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (132, 'sportscore', 'SportScore', '🏟️', 'Live scores and fixtures for several sports, keyless widget API', 'SportScore''s widget API returns live scores, fixtures and results for football and other sports as JSON. The attribution tier needs no key and sends open CORS headers, in exchange for a visible ''Powered by SportScore'' credit. Good for embedding recent matches without a signup.', 14, 'https://sportscore.com/developers/', 'https://sportscore.com/api/widget', 'none', 'endpoint', 1, 1, 'Free — no key (attribution tier)', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (133, 'squiggle', 'Squiggle', '🏉', 'AFL fixtures, results and tipping-model predictions as JSON', 'Squiggle aggregates Australian Football League fixtures, results and crowd-sourced model predictions into one JSON API. It is keyless but expects a descriptive User-Agent and blocks in-browser cross-origin calls, so use it server-side. A single query parameter selects teams, games or tips.', 14, 'https://api.squiggle.com.au', 'https://api.squiggle.com.au', 'none', 'endpoint', 1, 0, 'Free — no key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (134, 'dummyjson', 'DummyJSON', '🧪', 'Realistic fake REST data: products, users, carts, posts, todos', 'DummyJSON is a mock REST API stocked with believable products, users, carts, posts, comments and todos. Every resource is keyless and returns richly structured JSON, ideal for prototyping and front-end demos. Write endpoints simulate changes without persisting anything.', 8, 'https://dummyjson.com/', 'https://dummyjson.com', 'none', 'endpoint', 1, 1, 'Free — no key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (135, 'fakerapi', 'FakerAPI', '🎭', 'Generate fake people, addresses, products and more as JSON', 'FakerAPI spins up synthetic datasets, people, addresses, companies, images, credit cards and more, on demand. Pick a resource and a quantity and it returns keyless JSON with localizable, seedable fake data. Useful for filling test databases and UI mockups.', 8, 'https://fakerapi.it/en', 'https://fakerapi.it/api/v2', 'none', 'endpoint', 1, 1, 'Free — no key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (136, 'totalshiftleft-sandbox', 'TotalShiftLeft Sandbox', '🧰', 'Open REST/GraphQL/SOAP sandbox with optional OAuth2 and JWT', 'TotalShiftLeft is a multi-protocol testing sandbox exposing the same data over REST, GraphQL and SOAP. CRUD works without credentials, though you can layer on JWT, API key or OAuth2 to rehearse auth flows. The store starts empty, so its collections return valid but data-free responses until you seed them.', 8, 'https://demo.totalshiftleft.ai/', 'https://demo.totalshiftleft.ai/api/v1', 'none', 'endpoint', 1, 0, 'Free — open sandbox, auth optional', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (137, 'apimetro', 'Apimetro', '🚇', 'Mexico City transit geodata: metro lines, stations and GeoJSON', 'Apimetro maps Mexico City''s public transport, Metro, Metrobús, Cablebús, RTP and more, into structured geospatial JSON. Keyless endpoints return lines, stations, ridership analytics and GeoJSON geometry, using Spanish field names. All routes hang off the /movilidad base path.', 10, 'https://apimetro.dev/swagger/index.html', 'https://apimetro.dev/movilidad', 'none', 'endpoint', 1, 1, 'Free — no key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (138, 'bc-ferries', 'BC Ferries', '⛴️', 'Unofficial live BC Ferries sailing times and vessel capacity', 'This community API scrapes BC Ferries'' current conditions into clean JSON keyed by terminal pairs. Each route lists upcoming sailings with departure and arrival times plus real-time deck fill percentages. It is unofficial and keyless, best treated as a convenience mirror rather than a guarantee.', 10, 'https://www.bcferriesapi.ca', 'https://www.bcferriesapi.ca', 'none', 'endpoint', 1, 1, 'Free — no key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (139, 'openvan', 'OpenVan', '🚐', 'Vanlife data: fuel prices, currency rates and travel geo info', 'OpenVan bundles road-trip data, per-country fuel prices, currency rates and geolocation, behind a cheerful keyless API. Endpoints return structured JSON with open CORS, plus a /honk test route for good measure. Aimed at RV and vanlife apps that need fuel and cost signals worldwide.', 10, 'https://openvan.camp/docs', 'https://openvan.camp/api', 'none', 'endpoint', 1, 1, 'Free — no auth', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (140, 'transport-for-belgium', 'Transport for Belgium', '🚆', 'Belgian rail stations, schedules and live departures as JSON', 'iRail is a long-running third-party API for Belgian train travel, covering stations, connections, timetables and live board data. Add ?format=json to get keyless JSON; the project asks callers to send a descriptive User-Agent and use it fairly. It is community-run and independent of the national operator.', 10, 'https://docs.irail.be/', 'https://api.irail.be', 'none', 'endpoint', 1, 1, 'Free — no key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (141, 'final-space', 'Final Space', '🚀', 'Characters, episodes and locations from the Final Space cartoon', 'A fan-built JSON API cataloguing the animated series Final Space: its characters, episodes, quotes and locations. Each character record carries stats, aliases, abilities and an avatar image URL. No key, open CORS, JSON out of the box.', 13, 'https://finalspaceapi.com/docs/', 'https://finalspaceapi.com/api/v0', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (142, 'swapi-dev', 'SWAPI', '🛸', 'Star Wars people, planets, ships and films as tidy JSON', 'The classic Star Wars API: query people, planets, starships, vehicles, species and films through simple numbered endpoints. Each resource links to related records so you can crawl the whole galaxy. Keyless, CORS-open, plain JSON.', 13, 'https://swapi.dev/', 'https://swapi.dev/api', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (143, 'swapi-tech', 'SWAPI', '🌌', 'A maintained Star Wars API with wrapped, ID-based records', 'An actively hosted Star Wars data API covering people, planets, films, starships and more. Responses wrap each entity in a result/properties envelope with a description and cross-links. No signup, open CORS, JSON only.', 13, 'https://www.swapi.tech', 'https://www.swapi.tech/api', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (144, 'us-weather', 'US Weather', '🌦️', 'Official US forecasts, alerts and observations from the NWS', 'The US National Weather Service''s public API: start from a latitude/longitude to resolve the forecast grid point, then pull forecasts, hourly data, active alerts and station observations. Data is US-government public domain. Keyless, though it wants a descriptive User-Agent.', 1, 'https://www.weather.gov/documentation/services-web-api', 'https://api.weather.gov', 'none', 'endpoint', 1, 1, 'Free (US Government public data)', 'Unpublished (asks for a User-Agent identifying your app)', 0, 'yes', 'U.S. Government work / public domain', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (145, 'wttr-in', 'wttr.in', '⛅', 'Weather as JSON (or ASCII art) for any place on Earth', 'The console-friendly weather service, best known for its ASCII terminal output, also speaks JSON via the format=j1 query. One GET returns current conditions plus a multi-day forecast for a named location. No key needed and CORS is wide open.', 1, 'https://wttr.in/:help', 'https://wttr.in', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished (informal per-IP throttling)', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (146, 'opensensemap', 'openSenseMap', '🌡️', 'Live readings from citizen-run senseBox weather stations', 'An open-data platform where hobbyist senseBox stations publish environmental measurements — temperature, humidity, particulate matter, UV and more. Fetch a single box to see its sensors and latest values, or query boxes by bounding box. Keyless and CORS-friendly.', 1, 'https://api.opensensemap.org/', 'https://api.opensensemap.org', 'none', 'endpoint', 1, 1, 'Free (open-source citizen-science platform)', 'Unpublished', 0, 'unclear', 'Open data (license set per senseBox; often public domain)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (147, 'cataas', 'Cataas', '🐱', 'Cat as a service: random cat pics, gifs and metadata', 'Cataas serves endless cat images and gifs, and with ?json=true it hands back a small JSON object describing the cat instead of the raw picture. Each record carries an id, tags, mimetype and a direct URL. No key, open CORS.', 5, 'https://cataas.com/', 'https://cataas.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (148, 'randomduck', 'RandomDuck', '🦆', 'A random duck picture URL on every request', 'random-d.uk returns a JSON pointer to a random duck photo or gif each time you hit it. The payload is tiny: a friendly message and the image URL. No API key, though this endpoint did not advertise CORS headers.', 5, 'https://random-d.uk/api', 'https://random-d.uk/api', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (149, 'randomfox', 'RandomFox', '🦊', 'One random fox photo URL per call', 'randomfox.ca answers each GET with a JSON object holding a random fox image URL and a matching web link. It''s about as minimal as an API gets — handy for a quick placeholder image. Keyless with open CORS.', 5, 'https://randomfox.ca/floof/', 'https://randomfox.ca', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (150, 'meowfacts', 'MeowFacts', '😺', 'Random cat facts as JSON, one or many at a time', 'MeowFacts dishes out random feline trivia, returning a JSON object with a data array of fact strings. A count query parameter controls how many facts you get back. No key required and CORS is open.', 5, 'https://github.com/wh-iterabb-it/meowfacts', 'https://meowfacts.herokuapp.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (151, 'mcu-countdown', 'MCU Countdown', '🦸', 'How many days until the next Marvel release drops', 'The engine behind whenisthenextmcufilm.com exposes a JSON endpoint counting down to the next Marvel Cinematic Universe title, with details on the upcoming and following productions. Alternate paths cover Star Wars, DC and the Batman universe. Data is drawn from TMDB; no key needed.', 13, 'https://github.com/DiljotSG/MCU-Countdown', 'https://www.whenisthenextmcufilm.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified (movie data from TMDB)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (152, 'problemsbyvin', 'ProblemsByVin', '🚗', 'Free NHTSA reliability datasets: failure mileage, recalls, more', 'A set of static JSON datasets derived from tens of thousands of NHTSA owner complaints and recalls, covering failure-mileage quartiles, recall gaps, transmission and engine complaint density and more. Files are refreshed weekly and each ships with embedded methodology and licensing. Served as plain keyless JSON under CC BY 4.0.', 10, 'https://problemsbyvin.com/data/', 'https://problemsbyvin.com', 'none', 'endpoint', 1, 1, 'Free (weekly-refreshed static JSON datasets)', 'Unpublished (static JSON files)', 0, 'yes', 'CC BY 4.0', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (153, 'imdbot', 'IMDbOT', '🎬', 'Unofficial keyless IMDb-style movie and series search', 'A free, no-key search API that returns IMDb-style records for movies and shows — titles, years, IMDb IDs, cast and poster art — from a simple q query. It is the backend that powers the IMDbOT Telegram bot. Open CORS and JSON responses.', 13, 'https://imdb.iamidiotareyoutoo.com/docs/index.html', 'https://imdb.iamidiotareyoutoo.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (154, 'animechan', 'AnimeChan', '🍥', 'Random anime quotes with character and series attribution', 'Pulls a random line from a large library of anime quotes, each tagged with the character who said it and the show it came from. Filter by anime or character, or just grab a random quote. No key needed on the current api.animechan.io host.', 11, 'https://github.com/RocktimSaikia/anime-chan', 'https://api.animechan.io/v1', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (155, 'metropolitan-museum-of-art', 'Metropolitan Museum of Art', '🖼️', 'Open Access catalog of The Met''s collection', 'Query object records from the Metropolitan Museum of Art, including titles, artists, dates, departments and public-domain image links. Look up any object by ID or pull the full object-ID index. Fully keyless with open CORS.', 13, 'https://metmuseum.github.io/', 'https://collectionapi.metmuseum.org/public/collection/v1', 'none', 'endpoint', 1, 1, 'Free, no API key required', '80 requests/second (requested in docs)', 0, 'yes', 'CC0 1.0 (Open Access data)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (156, 'crossref-metadata-search', 'Crossref Metadata Search', '📚', 'Scholarly metadata for tens of millions of DOIs', 'Look up bibliographic metadata for academic works by DOI or free-text query across journal articles, books, datasets and more. Returns publisher, authors, titles, reference counts and citation links. Free public pool with no key; add a mailto for the faster polite pool.', 12, 'https://github.com/CrossRef/rest-api-doc', 'https://api.crossref.org', 'none', 'endpoint', 1, 1, 'Free, no key (public pool)', '5 requests/second, 1 concurrent (public pool, per X-Rate-Limit headers)', 0, 'yes', 'Open Crossref metadata (much is CC0)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (157, 'gutendex', 'Gutendex', '📖', 'JSON search over the Project Gutenberg library', 'A read-only web API over Project Gutenberg''s public-domain book catalog. Search by author, title, language or topic and get back IDs, authors, download counts and file links. No key required.', 12, 'https://gutendex.com/', 'https://gutendex.com', 'none', 'endpoint', 1, 1, 'Free, no key', 'Unpublished', 0, 'unclear', 'Public domain (Project Gutenberg data)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (158, 'nager-date', 'Nager.Date', '📅', 'Public holidays for 100+ countries by year', 'Returns official public and bank holidays for a given country and year, including local names, dates and whether each holiday is nationwide or regional. Also serves long weekends and supported-country lists. Keyless v3 REST endpoints with open CORS.', 16, 'https://date.nager.at', 'https://date.nager.at/api/v3', 'none', 'endpoint', 1, 1, 'Free, no key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (159, 'uk-bank-holidays', 'UK Bank Holidays', '🇬🇧', 'Official UK bank holidays as JSON', 'The UK government''s machine-readable feed of bank holidays for England & Wales, Scotland and Northern Ireland. Each event carries a title, date, notes and a ''bunting'' flag. Served under the Open Government Licence with no key required.', 16, 'https://www.gov.uk/bank-holidays.json', 'https://www.gov.uk', 'none', 'endpoint', 1, 1, 'Free, no key', 'Unpublished', 0, 'yes', 'Open Government Licence v3.0', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (160, 'coinlore', 'Coinlore', '🪙', 'Keyless crypto prices, market cap and rankings', 'Returns live ticker data for thousands of cryptocurrencies, including USD price, market cap, supply figures and percent changes over 1h/24h/7d. Query the full ranked list or specific coins by ID. No key and open CORS.', 9, 'https://www.coinlore.com/cryptocurrency-data-api', 'https://api.coinlore.net/api', 'none', 'endpoint', 1, 1, 'Free, no key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (161, 'cryptapi', 'CryptAPI', '💸', 'Keyless crypto payment-gateway helper API', 'A non-custodial crypto payment processor whose read endpoints are keyless. The /{coin}/info/ call returns a coin''s minimum amounts, forwarding fee and live fiat conversion rates. Designed for generating payment addresses and callbacks in commercial checkout flows.', 9, 'https://docs.cryptapi.io/', 'https://api.cryptapi.io', 'none', 'endpoint', 1, 1, 'Free API; provider takes ~1% fee per forwarded payment', 'Unpublished', 0, 'yes', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
