insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (196, 'abstract-email-validation', 'Abstract Email Validation', '✉️', 'Validate and enrich email addresses', 'Abstract API email validation checks deliverability, MX records, and disposable-domain flags. Free tier with API key from abstractapi.com.', 8, 'https://docs.abstractapi.com/email-validation', 'https://emailvalidation.abstractapi.com', 'apiKey', 'reachability', 1, 1, 'Free — 100 requests/month', '100 requests/month on free plan', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (197, 'ipgeolocation', 'IPGeolocation', '📍', 'IP → location, timezone, currency, and security', 'IPGeolocation.io resolves IPs to city, country, timezone, and threat signals. Free API key with daily lookup limits for developers.', 8, 'https://ipgeolocation.io/documentation.html', 'https://api.ipgeolocation.io', 'apiKey', 'reachability', 1, 1, 'Free — 1000 requests/day', '1000 requests/day on free plan', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (198, 'gemini', 'Gemini', '🪙', 'Live crypto ticker prices from the Gemini exchange, no key needed', 'Gemini''s public REST endpoints expose real-time market data for its cryptocurrency pairs without any authentication. The pubticker route returns the current bid, ask, last trade, and rolling 24h volume for a symbol like BTC/USD. Handy for quick price widgets and lightweight trading tools.', 9, 'https://docs.gemini.com/rest-api/', 'https://api.gemini.com/v1', 'none', 'endpoint', 1, 1, 'Public market data endpoints are keyless and free', 'Public API throttled per IP (specific numeric limit not confirmed at probe time)', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (199, 'mempool', 'Mempool', '₿', 'Recommended Bitcoin fee rates straight from a mempool explorer', 'Mempool.space runs an open Bitcoin explorer and exposes a keyless REST API over its live mempool. The recommended-fees endpoint returns suggested sat/vB rates for fastest, half-hour, hour, economy, and minimum confirmation targets. Useful for wallets estimating what to pay before broadcasting a transaction.', 9, 'https://mempool.space/docs/api/rest', 'https://mempool.space/api', 'none', 'endpoint', 1, 1, 'Free public API; no key for basic usage', 'Enforced — HTTP 429 on excess, repeated abuse may be banned; numeric limits unpublished', 0, 'unclear', 'Unverified (open-source project)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (200, 'economia-awesome', 'Economia.Awesome', '💵', 'Brazilian currency quotes and FX pairs, key optional', 'AwesomeAPI''s Economia service serves Brazilian-market currency and FX data via plain GET requests. The last-quote endpoint returns bid, ask, daily high/low, and percent change for a pair such as USD/BRL. Requests work without a key, though responses are briefly cached unless you register.', 2, 'https://docs.awesomeapi.com.br/api-de-moedas', 'https://economia.awesomeapi.com.br', 'none', 'endpoint', 1, 1, '100,000 requests/month free after registration; keyless access allowed (cached ~1 min)', 'Unauthenticated sequential queries capped at 100 results; responses cached ~1 min', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (201, 'postman-echo', 'Postman Echo', '🔁', 'Reflects your HTTP request back as JSON for client testing', 'Postman Echo is a hosted sandbox that mirrors whatever you send it. A GET to /get returns the query args, request headers, and full URL as JSON, making it an easy target for verifying HTTP clients, headers, and query handling. No key or signup required.', 8, 'https://www.postman-echo.com', 'https://postman-echo.com', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (202, 'apis-guru', 'APIs.guru', '📚', 'A machine-readable directory of public OpenAPI specifications', 'APIs.guru maintains a large, community-curated catalog of OpenAPI/Swagger definitions for public web APIs. The metrics endpoint gives a compact snapshot of the directory: how many specs, APIs, and endpoints are indexed plus counts of unreachable or invalid entries. The full listing is also keyless but large, so metrics is a friendlier sample.', 8, 'https://apis.guru/api-doc/', 'https://api.apis.guru/v2', 'none', 'endpoint', 1, 1, 'Free and open, no key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (203, 'cdnjs', 'CDNJS', '📦', 'Version, file and SRI metadata for CDNJS-hosted libraries', 'The CDNJS API returns metadata about the front-end libraries mirrored on the CDN. Querying a library like jquery yields its latest URL, SRI hash, current version, main filename, license, and homepage. Keyless and quick, it''s handy for build tools resolving asset URLs.', 8, 'https://api.cdnjs.com/libraries/jquery', 'https://api.cdnjs.com', 'none', 'endpoint', 1, 1, 'Free and open, no key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (204, 'digitalocean-status', 'DigitalOcean Status', '🌊', 'Live operational status of DigitalOcean''s services', 'DigitalOcean publishes its incident and uptime data through an Atlassian Statuspage public API. The status.json endpoint returns a top-level indicator and human-readable description of overall service health. No key required, ideal for status dashboards and uptime bots.', 8, 'https://status.digitalocean.com/api', 'https://status.digitalocean.com/api/v2', 'none', 'endpoint', 1, 1, 'Free (Atlassian Statuspage public API)', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (205, 'hipsum', 'Hipsum', '🧔', 'Hipster-flavored lorem ipsum placeholder text on demand', 'Hipsum generates filler text in an over-the-top hipster vocabulary instead of classic Latin lorem ipsum. A GET returns a JSON array of paragraphs sized by the paras parameter, ready to drop into mockups. No key or signup needed.', 8, 'https://hipsum.co', 'https://hipsum.co', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (206, 'ipinfo', 'IPinfo', '🌐', 'Geolocation and network details for any IP address', 'IPinfo returns location and network data for an IP. Hitting /json without a token resolves the caller''s own address to city, region, country, coordinates, ASN/org, and timezone. Keyless requests work but are rate-limited; a free token unlocks higher volume.', 8, 'https://ipinfo.io/developers', 'https://ipinfo.io', 'none', 'endpoint', 1, 1, 'Keyless /json works with limits; free token recommended (IPinfo Lite offers higher/unlimited access with a token)', 'Keyless/unauthenticated access is rate-limited; numeric caps not stated on the developers page', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (207, 'my-ip', 'MY IP', '📍', 'Your public IP plus country, in three JSON fields.', 'A no-frills lookup that echoes back the caller''s public IP address along with the country name and two-letter code. One GET, no key, no query params required. Handy for quick geo-gating or debugging what address the world actually sees.', 8, 'https://www.myip.com/api-docs/', 'https://api.myip.com', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (208, 'npm-registry', 'npm Registry', '📦', 'Read the metadata behind any published npm package.', 'The public npm registry answers plain GET requests for any package name and returns its full document: versions, dist-tags, maintainers, dependencies and more. No token is needed for reads and responses are CORS-open. Great for build tools, dashboards, or just checking the latest release of a library.', 8, 'https://github.com/npm/registry/blob/master/docs/REGISTRY-API.md', 'https://registry.npmjs.org', 'none', 'endpoint', 1, 1, 'Free (public registry)', 'Unpublished (bulk scraping discouraged)', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (209, 'free-dictionary', 'Free Dictionary', '📖', 'English word definitions, phonetics and audio as JSON.', 'Pass a word on the URL and get back an array of entries with definitions, parts of speech, example sentences, synonyms and pronunciation audio links. Keyless and CORS-friendly, drawn from open dictionary data. Individual entries carry their own source licenses (CC BY-SA 4.0 shows up on some).', 12, 'https://dictionaryapi.dev/', 'https://api.dictionaryapi.dev/api/v2', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Content under source licenses (CC BY-SA 4.0 seen on entries)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (210, 'chucknorris-io', 'chucknorris.io', '🥋', 'Hand-curated Chuck Norris facts, one JSON joke at a time.', 'Hit the random endpoint for a single curated Chuck Norris joke returned as tidy JSON with an id, the text, and a shareable URL. Category filtering and free-text search are also on offer. No key, CORS enabled, absurdity guaranteed.', 6, 'https://api.chucknorris.io', 'https://api.chucknorris.io', 'none', 'endpoint', 1, 1, 'Free, no key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (211, 'imgflip', 'Imgflip', '😂', 'The most popular meme templates as JSON.', 'The get_memes endpoint returns Imgflip''s current top ~100 meme templates with names, image URLs, dimensions and caption counts. It''s fully keyless and CORS-open; actually rendering a captioned meme requires a free Imgflip account. Useful for meme pickers and template galleries.', 6, 'https://imgflip.com/api', 'https://api.imgflip.com', 'none', 'endpoint', 1, 1, 'Free (get_memes is public; captioning needs a free account)', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (212, 'random-useless-facts', 'Random Useless Facts', '🤓', 'A true-but-pointless fact whenever you ask.', 'Returns a single random trivia fact as JSON, complete with source attribution and a permalink. English and German are supported via a language parameter. Keyless, CORS-open, and cheerfully unnecessary.', 6, 'https://uselessfacts.jsph.pl/', 'https://uselessfacts.jsph.pl/api/v2', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (213, 'mailcheck-ai', 'MailCheck.ai', '🛡️', 'Flag disposable and throwaway email domains.', 'Give it a domain and it reports whether that domain is disposable, whether it resolves MX records, and related signals like SPF and DMARC posture. Aimed at stopping temporary-inbox signups before they happen. Keyless for basic use and CORS-open.', 16, 'https://www.mailcheck.ai/#documentation', 'https://api.mailcheck.ai', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (214, 'guerrilla-mail', 'Guerrilla Mail', '📨', 'Spin up a throwaway inbox over a plain GET.', 'The AJAX API hands you a fresh disposable email address and a session token, then lets you poll that inbox for incoming messages. No account or key is needed to grab an address. Useful for exercising signup and verification flows in tests.', 16, 'https://www.guerrillamail.com/GuerrillaMailAPI.html', 'https://api.guerrillamail.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (215, 'serialif-color', 'Serialif Color', '🎨', 'Break a hex color into names, rgb and helpers.', 'Send a hex value on the path and receive a structured breakdown of that color: keyword name plus hex and rgb compositions. The service also documents complementary, grayscale and contrasting-text variants. Pure JSON, no key required.', 8, 'https://color.serialif.com/', 'https://color.serialif.com', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (216, 'chinese-text-project', 'Chinese Text Project', '📜', 'Full text of classical Chinese works, as JSON.', 'An open-access API into a large digital library of pre-modern Chinese texts. Request a work by its URN and receive the passage text plus its title as JSON. Basic access is keyless, and a free API key raises the limits; great for scholarship and language projects.', 12, 'https://ctext.org/tools/api', 'https://api.ctext.org', 'none', 'endpoint', 1, 1, 'Free (higher limits with a free API key)', 'Fair-use; raised with an API key', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (217, 'vector-express-v2-0', 'Vector Express v2.0', '📐', 'Discover free vector-format conversion paths.', 'A free API for converting between vector formats such as SVG, DXF, DWG, EPS and PDF. The public convert endpoint lists every available converter with its input and output formats, so you can plan a route before uploading a file. Keyless to browse.', 8, 'https://vector.express', 'https://vector.express/api/v2', 'none', 'endpoint', 1, 0, 'Free', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (218, 'wakatime', 'WakaTime', '⏱️', 'Public coding stats and the languages WakaTime tracks.', 'WakaTime powers automated time-tracking for programmers. A handful of endpoints are public and keyless, including the global leaderboard and this catalog of every programming language it recognizes, with colors and file extensions. Personal dashboards and detailed stats require an API key or OAuth.', 8, 'https://wakatime.com/developers', 'https://wakatime.com/api/v1', 'none', 'endpoint', 1, 0, 'Free public endpoints; personal data needs API key/OAuth', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (219, 'keyvalue', 'Keyvalue', '🗝️', 'A throwaway key-value store for quick prototypes.', 'Provision a storage bucket with a single GET, then store and fetch string values by key over simple REST calls. There are no accounts and no keys to manage, which makes it handy for hackday demos and glue code. Not meant for anything you need to keep.', 8, 'https://keyvalue.immanuel.co/', 'https://keyvalue.immanuel.co/api/KeyVal', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (220, 'memesio', 'Memesio', '😹', 'Meme-generation API with captions and share links.', 'A meme-creation service offering templates, AI caption helpers and hosted share links, pitched at apps and agents. Most generation endpoints require an API key, but some metadata reads respond without one. This entry probes the keyless caption tone-preset catalog.', 6, 'https://memesio.com/developers/api', 'https://memesio.com/api', 'none', 'endpoint', 1, 0, 'Public metadata endpoints keyless; generation needs an API key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (221, 'danish-data-service-energi', 'Danish data service Energi', '⚡', 'Live Danish grid prices and emissions, straight from Energinet', 'Energinet publishes Denmark''s electricity market and grid data as named open datasets you can query directly. Pull day-ahead spot prices, CO2 emissions, consumption and more by dataset name with a simple row limit. No key required, JSON out, CORS enabled.', 1, 'https://www.energidataservice.dk/', 'https://api.energidataservice.dk', 'none', 'endpoint', 1, 1, 'Free — no API key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (222, 'luchtmeetnet', 'Luchtmeetnet', '🌬️', 'Dutch air-quality readings and forecasts from RIVM stations', 'The Netherlands'' national air-quality network exposes its measuring stations and pollutant readings over an open API. Page through stations, then fetch measured and forecast values for components like NO2, PM10 and ozone. Keyless JSON with wide-open CORS.', 1, 'https://api-docs.luchtmeetnet.nl/', 'https://api.luchtmeetnet.nl/open_api', 'none', 'endpoint', 1, 1, 'Free — no API key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (223, 'pm2-5-open-data-portal', 'PM2.5 Open Data Portal', '😷', 'Crowd-sourced low-cost PM2.5 sensor readings, refreshed live', 'LASS aggregates thousands of community AirBox sensors (heavily in Taiwan) into one open feed. A single GET returns the latest snapshot from every device with timestamps, coordinates and particulate readings. No key needed—use the plain .json feed, since the default download is gzipped.', 1, 'https://pm25.lass-net.org/#apis', 'https://pm25.lass-net.org', 'none', 'endpoint', 1, 0, 'Free — no API key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (224, 'solematica', 'Solematica', '☀️', 'Compare Italian rooftop-solar installer offers in one call', 'Solematica benchmarks photovoltaic packages from major Italian energy operators—price per kW, panels, inverters, batteries and warranties. The public /providers endpoint returns the full comparison as JSON with no key, provided you credit Solematica. Deeper data like energy prices and satellite roof analysis needs paid credits.', 1, 'https://www.solematica.it/sviluppatori', 'https://api.solematica.it/api/v1', 'none', 'endpoint', 1, 0, 'Free public /providers endpoint; other endpoints need paid credits', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (225, 'uk-carbon-intensity', 'UK Carbon Intensity', '🌍', 'How clean is Britain''s grid right now? Ask National Grid', 'The official Carbon Intensity API for Great Britain reports current and forecast grams of CO2 per kWh, plus a low/moderate/high index. National Grid ESO runs it, it needs no key, and it returns clean JSON with CORS enabled. Documented under a CC BY 4.0 licence.', 1, 'https://carbon-intensity.github.io/api-definitions/#carbon-intensity-api-v1-0-0', 'https://api.carbonintensity.org.uk', 'none', 'endpoint', 1, 1, 'Free — no API key', 'Unpublished', 0, 'yes', 'CC BY 4.0 (per API docs)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (226, 'website-carbon', 'Website Carbon', '🌱', 'Estimate a web page''s CO2 footprint from its byte weight', 'Website Carbon models the greenhouse-gas emissions of loading a web page. The keyless /data endpoint takes a transfer size and a green-hosting flag and returns grams of CO2, an A–F rating and a ''cleaner than'' percentile. The URL-scanning /site endpoint now requires an API token.', 1, 'https://api.websitecarbon.com/', 'https://api.websitecarbon.com', 'none', 'endpoint', 1, 0, 'Free keyless byte-based /data endpoint', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (227, 'binlist', 'Binlist', '💳', 'Look up card scheme, type and issuer from a BIN/IIN', 'Binlist maps the leading digits of a payment card to its network, type, issuing bank and country. Append the BIN as a path segment with an ''Accept-Version: 3'' header and you get tidy JSON back. Free and unauthenticated, though it''s rate-limited and fronted by a firewall that rejects requests carrying a browser Origin header.', 2, 'https://binlist.net/', 'https://lookup.binlist.net', 'none', 'endpoint', 1, NULL, 'Free — no key (requires ''Accept-Version: 3'' header)', 'Rate limited for unauthenticated use; exact limit unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (228, 'fed-treasury', 'Fed Treasury', '🏛️', 'Official U.S. Treasury fiscal data, from debt to FX rates', 'The Treasury''s Fiscal Data service publishes federal finances—exchange rates, the national debt, interest rates and more—as a filterable JSON API. Select fields, page and sort with query parameters; no key required. It''s open U.S. Government data.', 2, 'https://fiscaldata.treasury.gov/api-documentation/', 'https://api.fiscaldata.treasury.gov/services/api/fiscal_service', 'none', 'endpoint', 1, 1, 'Free — no API key', 'Unpublished', 0, 'yes', 'Open U.S. Government data (public domain)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (229, 'goldprice-dev', 'Goldprice.dev', '🥇', 'Cross-validated gold, silver & copper spot prices in 13 currencies', 'Goldprice.dev serves precious-metal spot and futures quotes reconciled across sources, in more than a dozen currencies. The keyless /v1/prices endpoint returns core spot rows; a free account unlocks history, statistics and higher limits. Anonymous calls carry a usage-notice header.', 2, 'https://goldprice.dev/docs', 'https://api.goldprice.dev/v1', 'none', 'endpoint', 1, 0, 'Free keyless tier (limited fields); free account lifts caps', 'Anonymous usage caps apply; exact limit unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (230, 'razorpay-ifsc', 'Razorpay IFSC', '🏦', 'Resolve any Indian bank IFSC code to branch details', 'Razorpay''s open IFSC service turns an Indian bank branch code into its bank, branch, address, city and supported rails like NEFT, RTGS, IMPS and UPI. Just append the code to the base URL for keyless JSON. CORS is wide open.', 2, 'https://razorpay.com/docs/', 'https://ifsc.razorpay.com', 'none', 'endpoint', 1, 1, 'Free — no API key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (231, 'coffee', 'Coffee', '☕', 'A random photo of coffee, every single request', 'Part of alexflipnote''s playful image APIs, this one does exactly one thing: hand you a random coffee picture. A GET to /random.json returns a JSON object with the image URL. No key, no fuss.', 14, 'https://coffee.alexflipnote.dev/', 'https://coffee.alexflipnote.dev', 'none', 'endpoint', 1, 0, 'Free — no API key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (232, 'fruityvice', 'Fruityvice', '🍌', 'Nutrition and taxonomy facts for common fruits', 'Fruityvice answers questions about fruit—family, genus, order and per-serving nutrition like calories, sugar and protein. Query a single fruit by name or pull the whole list. Keyless JSON, no signup.', 14, 'https://www.fruityvice.com', 'https://www.fruityvice.com/api', 'none', 'endpoint', 1, 0, 'Free — no API key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (233, 'the-report-of-the-week', 'The Report of the Week', '🍔', 'Every food & drink review from TheReportOfTheWeek, as JSON', 'A community-built API cataloguing YouTuber TheReportOfTheWeek''s food, drink and ''Running On Empty'' reviews. Filter /api/v1/reports by category, rating or date to get products, manufacturers, video codes and scores. Keyless JSON.', 14, 'https://github.com/andyklimczak/TheReportOfTheWeek-API', 'https://www.thereportoftheweekapi.com', 'none', 'endpoint', 1, 0, 'Free — no API key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (234, 'whiskyhunter', 'WhiskyHunter', '🥃', 'Historical stats from online whisky auctions', 'WhiskyHunter aggregates results from the world''s online whisky auction houses. The auctions_data feed returns daily per-house statistics—mean winning bid, trading volume and lot counts—as a JSON array. No key required.', 14, 'https://whiskyhunter.net/api/', 'https://whiskyhunter.net/api', 'none', 'endpoint', 1, 0, 'Free — no API key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (235, 'call-of-duty-mobile', 'Call of Duty Mobile', '🎮', 'Unofficial CODM player profile lookups by name or UID', 'A reverse-engineered API for Call of Duty: Mobile that fetches public player profiles—level, rank, rating and country—by nickname or UID. A GET to /user/{name} returns JSON with no key. Unofficial and community-maintained, so expect occasional gaps.', 11, 'https://callofdutymobile.vercel.app/', 'https://callofdutymobile.vercel.app', 'none', 'endpoint', 1, 0, 'Free — no API key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (236, 'chess-com', 'Chess.com', '♟️', 'Read-only access to Chess.com players, games and clubs', 'Chess.com''s Published-Data API exposes public profiles, game archives, clubs, tournaments and leaderboards. Fetch a player by username to get their profile as JSON—no key, CORS enabled. The API prefers serial rather than parallel requests.', 11, 'https://www.chess.com/news/view/published-data-api', 'https://api.chess.com/pub', 'none', 'endpoint', 1, 1, 'Free — no API key', 'Serial requests expected; no fixed cap published', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (237, 'digimon-information', 'Digimon Information', '🦖', 'Look up Digimon creatures by name or level', 'A tiny fan API listing Digimon with their name, evolution level and artwork. Query by name for a single creature or browse the full roster. Keyless JSON with CORS on.', 11, 'https://digimon-api.vercel.app/', 'https://digimon-api.vercel.app/api', 'none', 'endpoint', 1, 1, 'Free — no API key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (238, 'digimon-tcg', 'Digimon TCG', '🃏', 'Search Digimon Card Game cards from digimoncard.io', 'A public search API for the Digimon trading card game. Query by card name to get types, colours, DP, effects, rarity and the sets a card appears in, all as JSON. No key required.', 11, 'https://documenter.getpostman.com/view/14059948/TzecB4fH', 'https://digimoncard.io/api-public', 'none', 'endpoint', 1, 1, 'Free — no API key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (239, 'gdbrowser', 'GDBrowser', '🟩', 'Query Geometry Dash levels and players without the game', 'GDBrowser wraps the Geometry Dash servers in a friendly REST API. Ask for a level by ID to get its name, author, difficulty, downloads, song and more as clean JSON—no key, CORS enabled. It''s a community proxy, so it depends on the game''s servers staying up.', 11, 'https://gdbrowser.com/api', 'https://gdbrowser.com/api', 'none', 'endpoint', 1, 1, 'Free — no API key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (240, 'hyrule-compendium', 'Hyrule Compendium', '🗡️', 'Data on every item, monster and creature in Zelda: BOTW', 'The Hyrule Compendium API serves entries from The Legend of Zelda: Breath of the Wild—monsters, materials, equipment and more—with descriptions, locations, drops and images. Fetch an entry by name for JSON. Fan-made and keyless; it has moved off Heroku to api.hyrule-compendium.com.', 11, 'https://github.com/gadhagod/Hyrule-Compendium-API', 'https://api.hyrule-compendium.com', 'none', 'endpoint', 1, 1, 'Free — no API key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (241, 'minecraft-server-status', 'Minecraft Server Status', '⛏️', 'Ping any Minecraft server for its MOTD, players, and version', 'Point it at a server host and it pings live for online status, player counts, MOTD, version, and icon. Supports both Java and Bedrock servers, with per-host caching so repeat lookups stay quick. No key, JSON out, and CORS wide open.', 11, 'https://api.mcsrvstat.us', 'https://api.mcsrvstat.us', 'none', 'endpoint', 1, 1, 'Free, no API key', 'Responses cached per host (~1 min); no published request cap', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (242, 'mmo-games', 'MMO Games', '🕹️', 'Browse free-to-play MMO games, news, and giveaways as JSON', 'A catalog of free-to-play titles from MMOBomb, filterable by genre and platform, alongside news and active giveaways. Each game entry carries a thumbnail, short blurb, publisher, and store link. Keyless GET, no signup required.', 11, 'https://www.mmobomb.com/api', 'https://www.mmobomb.com/api1', 'none', 'endpoint', 1, 1, 'Free, no API key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (243, 'open-trivia', 'Open Trivia', '❓', 'Pull random trivia questions across categories and difficulties', 'Fetch multiple-choice or true/false trivia questions filtered by category, difficulty, and type. Each result ships with the correct answer plus shuffled distractors, ready to drop straight into a quiz. Content is licensed CC BY-SA 4.0.', 11, 'https://opentdb.com/api_config.php', 'https://opentdb.com', 'none', 'endpoint', 1, 1, 'Free, no API key', 'One request per IP every 5 seconds (documented)', 0, 'yes', 'CC BY-SA 4.0', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (244, 'playerdb', 'PlayerDB', '👤', 'Resolve Minecraft, Steam, and Xbox player profiles by name or ID', 'Look up a player across Minecraft, Steam, or Xbox and get back canonical IDs, avatars, and profile metadata. Handy for turning a username into a stable UUID or grabbing a skin texture. No key needed, JSON response, open CORS.', 11, 'https://playerdb.co/', 'https://playerdb.co/api', 'none', 'endpoint', 1, 1, 'Free, no API key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (245, 'pokemon-tcg', 'Pokémon TCG', '🃏', 'Query Pokémon trading-card data — sets, cards, prices, and images', 'Search the Pokémon Trading Card Game catalog by card, set, type, and more, with images and market prices attached. It works without a key at a lower rate limit; a free key raises the ceiling. All Pokémon intellectual property belongs to its owners.', 11, 'https://pokemontcg.io', 'https://api.pokemontcg.io/v2', 'none', 'endpoint', 1, 1, 'Free; no key ~1,000 req/day & 30/min, free key ~20,000 req/day (documented)', 'Without key: ~30 req/min, 1,000 req/day (documented)', 0, 'unclear', 'Unverified (Pokémon IP)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (246, 'raider', 'Raider', '⚔️', 'World of Warcraft Mythic+ and raid rankings for characters & guilds', 'Pull WoW character and guild profiles, Mythic+ scores, raid progress, and the current season''s affix rotation. Public data is available without a key over plain JSON. The underlying game data is Blizzard''s.', 11, 'https://raider.io/api', 'https://raider.io/api/v1', 'none', 'endpoint', 1, 1, 'Free, no API key for public data', 'Unpublished', 0, 'unclear', 'Unverified (Blizzard game data)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (247, 'runescape', 'RuneScape', '🐉', 'Official RuneScape Grand Exchange item prices and trends', 'Jagex''s Grand Exchange catalogue endpoint returns an item''s current price, 30/90/180-day trends, image, and category. It answers JSON (despite a text/html content type) with no key required. RuneScape data is © Jagex.', 11, 'https://runescape.wiki/w/Application_programming_interface', 'https://services.runescape.com/m=itemdb_rs/api', 'none', 'endpoint', 1, 0, 'Free, no API key', 'Unpublished', 0, 'unclear', 'Unverified (© Jagex)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (248, 'tetr-io', 'TETR.IO', '🧩', 'Stats and player data from the TETR.IO Tetra Channel API', 'The Tetra Channel API exposes TETR.IO''s public numbers — global user counts, games played, and per-player records. Responses ship with cache windows the docs ask you to honor. Note the CORS header only allows tetr.io itself, so browser calls from other origins are blocked.', 11, 'https://tetr.io/about/api/', 'https://ch.tetr.io/api', 'none', 'endpoint', 1, 0, 'Free, no API key', 'Honor server-provided cache expiry (~60s); docs require caching', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (249, 'valorant-non-official', 'Valorant (non-official)', '🎯', 'Community API for Valorant agents, weapons, maps, and assets', 'A fan-maintained catalog of Valorant in-game content — agents, weapons, skins, maps, sprays — each with artwork and multi-language text. Keyless JSON with wide-open CORS. Not affiliated with Riot; all assets remain Riot''s.', 11, 'https://valorant-api.com', 'https://valorant-api.com/v1', 'none', 'endpoint', 1, 1, 'Free, no API key', 'Unpublished', 0, 'unclear', 'Unverified (Riot assets)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (250, 'xkcd', 'xkcd', '📈', 'Fetch xkcd comics as JSON — latest or by number', 'Grab any xkcd comic''s metadata — title, image URL, alt text, and publish date — as a tidy JSON object. Hit info.0.json for the newest strip or /{num}/info.0.json for a specific one. Comics are licensed CC BY-NC, so commercial reuse is not permitted.', 11, 'https://xkcd.com/json.html', 'https://xkcd.com', 'none', 'endpoint', 1, 0, 'Free, no API key', 'Unpublished', 0, 'no', 'CC BY-NC 2.5', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (251, 'yu-gi-oh', 'Yu-Gi-Oh!', '🎴', 'Search Yu-Gi-Oh! cards with stats, sets, prices, and art', 'Query the YGOPRODeck database by card name or filters and get full card details — type, ATK/DEF, archetype, set printings, and market prices. Keyless JSON with permissive CORS. Yu-Gi-Oh! is Konami''s property.', 11, 'https://db.ygoprodeck.com/api-guide/', 'https://db.ygoprodeck.com/api/v7', 'none', 'endpoint', 1, 1, 'Free, no API key', '20 requests per second per IP (documented)', 0, 'unclear', 'Unverified (Konami IP)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (252, 'adresse-data-gouv-fr', 'adresse.data.gouv.fr', '📮', 'Geocode and reverse-geocode French addresses (Base Adresse Nationale)', 'France''s national address geocoder turns a query string into ranked GeoJSON matches with coordinates, postcode, and city — reverse lookups too. It''s fast, keyless, and CORS-enabled, documented at 50 requests per second per IP. Data ships under open French licences.', 3, 'https://adresse.data.gouv.fr', 'https://api-adresse.data.gouv.fr', 'none', 'endpoint', 1, 1, 'Free, no API key', '50 requests/second per IP (documented)', 0, 'yes', 'Licence Ouverte / ODbL (Base Adresse Nationale)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (253, 'bdapis', 'BdAPIs', '🇧🇩', 'Divisions, districts, and upazilas of Bangladesh as JSON', 'A tidy reference API for Bangladesh''s administrative geography — divisions down to districts and upazilas — each with Bangla names and coordinates. Keyless GET with open CORS. Handy for dropdowns and location pickers.', 3, 'https://bdapis.com/', 'https://bdapis.com/api/v1.2', 'none', 'endpoint', 1, 1, 'Free, no API key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (254, 'cartes-io', 'Cartes.io', '🗺️', 'Create and read open collaborative maps and markers', 'An open-source mapping service where anyone can spin up public maps and drop markers, all reachable over a REST API. Listing maps is a keyless GET — just send Accept: application/json, or you get the web app''s HTML instead. CORS is enabled.', 3, 'https://github.com/M-Media-Group/Cartes.io/wiki/API', 'https://cartes.io/api', 'none', 'endpoint', 1, 1, 'Free, no API key for public read', 'Unpublished', 0, 'unclear', 'Unverified (open-source project; user-generated maps)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (255, 'geoapi', 'GeoApi', '🇫🇷', 'French administrative geography — communes, departments, regions', 'The French government''s Découpage Administratif API resolves communes, departments, and regions by name, code, or postcode, with population and INSEE codes attached. Keyless JSON, CORS-friendly, backed by official open data. Ideal for French address and territory lookups.', 3, 'https://api.gouv.fr/api/geoapi.html', 'https://geo.api.gouv.fr', 'none', 'endpoint', 1, 1, 'Free, no API key', 'Unpublished', 0, 'yes', 'Licence Ouverte (Etalab; INSEE/IGN data)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (256, 'steam', 'Steam', '🎮', 'Undocumented Steam storefront lookups — app details by ID', 'Steam''s internal storefront endpoint returns rich details for any app by ID: name, type, pricing, free-to-play flag, descriptions, and media. It''s undocumented and keyless but IP-rate-limited, so cache and go easy. No CORS header is sent, so use it server-side.', 11, 'https://github.com/Revadike/InternalSteamWebAPI/wiki', 'https://store.steampowered.com/api', 'none', 'endpoint', 1, 0, 'Free, no API key', 'Unpublished (undocumented endpoint; IP rate-limited)', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (257, 'hellosalut', 'HelloSalut', '👋', 'Say hello in any language, returned as JSON', 'Give it a language code and it hands back the local word for "hello." A tiny, single-purpose endpoint from fourtonfish that is handy for greeting users in their own tongue.', 3, 'https://fourtonfish.com/project/hellosalut-api/', 'https://fourtonfish.com/hellosalut', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (258, 'ibge', 'IBGE', '🇧🇷', 'Brazil''s official geography and statistics service', 'The Brazilian Institute of Geography and Statistics exposes its localities, regions and datasets over a clean REST API. This sample lists all Brazilian states with their region grouping; other paths cover municipalities, census and economic data.', 3, 'https://servicodados.ibge.gov.br/api/docs/', 'https://servicodados.ibge.gov.br', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (259, 'ipgeo', 'IPGEO', '🌐', 'IP geolocation with ISP, timezone and currency', 'TechnikNews returns geolocation for an IP address including region, ISP, timezone and even the local currency and proxy/hosting flags. No key or signup is needed for the JSON lookup.', 3, 'https://api.techniknews.net/ipgeo/', 'https://api.techniknews.net', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (260, 'open-topo-data', 'Open Topo Data', '⛰️', 'Elevation and ocean depth for a lat/lon', 'Query the elevation (or ocean depth) at one or more coordinates against a choice of open elevation datasets. The public instance is keyless; the test-dataset shown here returns a demo value while named datasets serve real terrain data.', 3, 'https://www.opentopodata.org', 'https://api.opentopodata.org', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (261, 'postalcodes', 'PostalCodes', '📮', 'Search postal codes and places worldwide', 'A keyless search endpoint that returns matching towns, regions and postal-code sets across many countries as JSON. Useful for autocomplete over global postal data; the site also offers per-country bulk exports.', 3, 'https://postalcodes.info/api', 'https://postalcodes.info', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (262, 'viacep', 'ViaCep', '📦', 'Brazilian CEP (zip code) lookups, instantly', 'Resolve a Brazilian CEP into street, neighbourhood, city, state and region plus IBGE and DDD codes. A long-standing, widely used free endpoint for Brazilian address data.', 3, 'https://viacep.com.br', 'https://viacep.com.br', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (263, 'ziptastic', 'Ziptastic', '🇺🇸', 'US ZIP code to city and state in one GET', 'Hand it a US ZIP code and it returns the country, state and city as JSON. A minimal, no-frills lookup with a single path segment.', 3, 'https://ziptasticapi.com/', 'https://ziptasticapi.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (264, 'bank-negara-malaysia-open-data', 'Bank Negara Malaysia Open Data', '🏦', 'Malaysia''s central bank open data feeds', 'The Bank Negara Malaysia open API publishes exchange rates, interest rates, Kijang Emas gold prices and other monetary data. The sample returns the latest gold buying/selling prices per ounce.', 17, 'https://apikijangportal.bnm.gov.my/', 'https://api.bnm.gov.my', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (265, 'brazil-central-bank-open-data', 'Brazil Central Bank Open Data', '💹', 'Brazil''s economic time-series (SGS system)', 'The Banco Central do Brasil serves thousands of economic time series through its SGS API. This sample pulls the latest USD/BRL PTAX reference rate; any series is addressable by its numeric code.', 17, 'https://dadosabertos.bcb.gov.br/', 'https://api.bcb.gov.br', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (266, 'brazil-receita-ws', 'Brazil Receita WS', '🏢', 'Look up Brazilian companies by CNPJ', 'ReceitaWS resolves a Brazilian company CNPJ into its registration status, legal name, trade name and business activities. The free keyless tier is heavily rate-limited but returns rich company records.', 17, 'https://www.receitaws.com.br/', 'https://www.receitaws.com.br', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (267, 'brazilian-chamber-of-deputies-open-data', 'Brazilian Chamber of Deputies Open Data', '🏛️', 'Brazil''s lower-house legislative open data', 'The Câmara dos Deputados publishes deputies, parties, bills, votes and expenses through a versioned REST API in JSON or XML. The sample lists political parties; server responses can be slow.', 17, 'https://dadosabertos.camara.leg.br/swagger/api.html', 'https://dadosabertos.camara.leg.br', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (268, 'city-gdansk', 'City, Gdańsk', '🏙️', 'Gdańsk city open data over CKAN', 'The city of Gdańsk runs a CKAN open-data portal whose action API lists and serves datasets as JSON. The sample returns the full catalogue of dataset slugs covering transport, budget, safety and more.', 17, 'https://ckan.multimediagdansk.pl/en', 'https://ckan.multimediagdansk.pl', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (269, 'city-helsinki', 'City, Helsinki', '🏙️', 'Helsinki region open data over CKAN', 'Helsinki Region Infoshare (HRI) exposes its open datasets through a CKAN action API. The sample lists every dataset slug in the catalogue, from a 3D model of the city to statistical tables.', 17, 'https://hri.fi/en_gb/', 'https://hri.fi/data/en', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (270, 'city-new-york-open-data', 'City, New York Open Data', '🗽', 'NYC''s open datasets over the Socrata API', 'New York City''s open-data portal is a Socrata instance where every dataset has a keyless JSON endpoint. The sample pulls two rows from the 311 service-request dataset; SoQL query parameters let you filter and page.', 17, 'https://opendata.cityofnewyork.us/', 'https://data.cityofnewyork.us', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (271, 'colorado-information-marketplace', 'Colorado Information Marketplace', '🏔️', 'Colorado state open-data catalog and datasets', 'Colorado''s state open-data portal runs on Socrata, so both its dataset catalog and individual datasets are queryable as JSON without a key. The sample hits the catalog discovery endpoint and returns dataset metadata.', 17, 'https://data.colorado.gov/', 'https://data.colorado.gov', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (272, 'data-usa', 'Data USA', '📊', 'US public data as tidy JSON records', 'Data USA visualizes public US datasets and exposes them through its Tesseract data API. Pick a cube, drilldowns and measures and it returns aggregated records; the sample pulls US population by year from an ACS cube.', 17, 'https://datausa.io/about/api/', 'https://api.datausa.io', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (273, 'epa', 'EPA', '♻️', 'US environmental facilities and datasets', 'The US Environmental Protection Agency''s Envirofacts service serves environmental records by building a REST path of table, column filter and row range. The sample returns a Toxics Release Inventory facility in California as JSON.', 17, 'https://www.epa.gov/developers/data-data-products#apis', 'https://data.epa.gov', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (274, 'federal-register', 'Federal Register', '📜', 'Every US federal rule, notice, and proclamation as JSON', 'The US government''s official daily journal, exposed as a clean REST API. Query proposed rules, final rules, notices, and presidential documents by date, agency, or keyword with no key. Responses are paginated JSON served straight from FederalRegister.gov.', 17, 'https://www.federalregister.gov/reader-aids/developer-resources/rest-api', 'https://www.federalregister.gov/api/v1', 'none', 'endpoint', 1, 1, 'Free — no key or signup required', 'Unpublished', 0, 'yes', 'US Government work — public domain', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (275, 'open-government-australia', 'Open Government, Australia', '🇦🇺', 'Australia''s national open-data catalogue over CKAN', 'The Australian Government''s central open-data portal, served through a standard CKAN API. Search 130k+ datasets and their resources with keyword, facet, and paging parameters. Metadata returns as JSON, with licensing set per dataset.', 17, 'https://www.data.gov.au/', 'https://data.gov.au/data/api/3', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Per-dataset (many CC BY 4.0)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (276, 'open-government-act', 'Open Government, ACT', '🏛️', 'Canberra''s open data via a Socrata catalog API', 'The Australian Capital Territory''s open-data platform, running on Socrata. Its discovery API lists datasets with their IDs, owners, and update times as JSON, and each dataset also carries its own SODA query endpoint. No key is needed to browse the catalog.', 17, 'https://www.data.act.gov.au/', 'https://data.act.gov.au', 'none', 'endpoint', 1, 1, 'Free — app token optional (raises limits)', 'Throttled; higher limits with a free Socrata app token', 0, 'unclear', 'Per-dataset', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (277, 'open-government-finland', 'Open Government, Finland', '🇫🇮', 'Finland''s open-data portal on CKAN', 'Finland''s national open-data service (Avoindata.fi), backed by CKAN. Search datasets from municipalities and agencies and read their metadata as JSON. Licensing is per dataset, with CC BY 4.0 common.', 17, 'https://www.avoindata.fi/en', 'https://www.avoindata.fi/data/en/api/3', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Per-dataset (many CC BY 4.0)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (278, 'open-government-germany', 'Open Government, Germany', '🇩🇪', 'Germany''s federal open-data catalogue over CKAN', 'GovData, the German federation''s cross-jurisdiction open-data portal, exposed as a CKAN API. Query 130k+ datasets from federal, state, and municipal publishers and get JSON metadata back. Data licenses vary per record.', 17, 'https://www.govdata.de/daten/-/details/govdata-metadatenkatalog', 'https://www.govdata.de/ckan/api/3', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Per-dataset', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (279, 'open-government-italy', 'Open Government, Italy', '🇮🇹', 'Italy''s national open-data catalogue over CKAN', 'Italy''s central open-data portal (dati.gov.it) served through CKAN. Search 60k+ datasets and pull their metadata as JSON with the standard package_search action. Many datasets are published under CC BY 4.0.', 17, 'https://www.dati.gov.it/', 'https://www.dati.gov.it/opendata/api/3', 'none', 'endpoint', 1, 0, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Per-dataset (many CC BY 4.0)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (280, 'open-government-netherlands', 'Open Government, Netherlands', '🇳🇱', 'Dutch government open data via CKAN', 'The Netherlands'' national open-data register, backed by CKAN. Search 20k+ datasets from Dutch public bodies and read DCAT-style metadata as JSON. Status and authority fields use official government URI vocabularies.', 17, 'https://data.overheid.nl/en/ondersteuning/data-publiceren/api', 'https://data.overheid.nl/data/api/3', 'none', 'endpoint', 1, 0, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Per-dataset', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (281, 'open-government-queensland-government', 'Open Government, Queensland Government', '🌏', 'Queensland Government open data over CKAN', 'The Queensland Government''s open-data portal, running CKAN. Search 180k+ datasets and resources spanning state and council publishers, returned as JSON. Many datasets carry Creative Commons Attribution licensing.', 17, 'https://www.data.qld.gov.au/', 'https://www.data.qld.gov.au/api/3', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Per-dataset (many CC BY 4.0)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (282, 'open-government-south-australian-government', 'Open Government, South Australian Government', '🗺️', 'South Australia''s open-data portal over CKAN', 'The Government of South Australia''s open-data catalog, served through CKAN. Query datasets and their resources with keyword and facet parameters and get JSON back. Records include jurisdiction and Creative Commons license fields.', 17, 'https://data.sa.gov.au/', 'https://data.sa.gov.au/data/api/3', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Per-dataset (Creative Commons Attribution common)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (283, 'open-government-switzerland', 'Open Government, Switzerland', '🇨🇭', 'Switzerland''s open-data catalogue over CKAN', 'opendata.swiss, the Swiss Confederation''s central open-data portal, exposed as a CKAN API. Search 17k+ multilingual datasets (DE/FR/IT/EN) and read their metadata as JSON. Contact points and periodicity use EU publication-office vocabularies.', 17, 'https://handbook.opendata.swiss/de/content/nutzen/api-nutzen.html', 'https://opendata.swiss/api/3', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Per-dataset', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (284, 'open-government-slovenia', 'Open Government, Slovenia', '🇸🇮', 'Slovenia''s national open-data portal over CKAN', 'Slovenia''s central open-data catalog (OPSI), backed by CKAN. Search ~9k datasets from Slovenian public bodies and pull their metadata as JSON. Fields are largely in Slovenian, with per-dataset CC licensing.', 17, 'https://podatki.gov.si/', 'https://podatki.gov.si/api/3', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Per-dataset (CC BY 4.0 common)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (285, 'open-government-spain', 'Open Government, Spain', '🇪🇸', 'Spain''s open-data catalogue as a linked-data API', 'datos.gob.es, Spain''s national open-data initiative, exposes its catalog through a linked-data-api (apidata) that returns JSON. Page through datasets and read DCAT metadata with URI-typed fields. No key required.', 17, 'https://datos.gob.es/en', 'https://datos.gob.es/apidata', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Per-dataset', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (286, 'open-government-sweden', 'Open Government, Sweden', '📊', 'Statistics Sweden''s statistical database as JSON', 'The PxWeb API behind Statistics Sweden (SCB), the data service documented by Sweden''s national data portal. A keyless GET walks the statistical tree, returning subject areas, tables, and — via follow-up queries — the figures themselves as JSON. Ideal for official Swedish statistics.', 17, 'https://www.dataportal.se/en/dataservice/91_29789/api-for-the-statistical-database', 'https://api.scb.se/OV0104/v1/doris/en', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Rate-limited per SCB PxWeb API terms (call-rate and response-size caps)', 0, 'yes', 'Free reuse with source attribution (SCB terms)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (287, 'open-government-uk', 'Open Government, UK', '🇬🇧', 'Query the UK''s open-data catalogue over CKAN, no key needed', 'data.gov.uk runs on CKAN, so you can hit its /api/3/action/ endpoints to search or list tens of thousands of published UK public-sector datasets. Responses are JSON and CORS is wide open. Individual dataset licences vary, though most sit under the Open Government Licence.', 17, 'https://data.gov.uk/', 'https://data.gov.uk/api/3', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'yes', 'Open Government Licence v3.0 (varies per dataset)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (288, 'open-government-victoria', 'Open Government, Victoria State Government', '🇦🇺', 'Victoria''s public datasets, searchable via a CKAN JSON API', 'The Victorian Government''s open-data portal exposes a standard CKAN action API at discover.data.vic.gov.au. Ask it to list or search the state''s datasets and you get clean JSON with permissive CORS. Most data defaults to CC BY 4.0 under the DataVic access policy.', 17, 'https://www.data.vic.gov.au/', 'https://discover.data.vic.gov.au/api/3', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'yes', 'CC BY 4.0 (default; varies per dataset)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (289, 'open-government-west-australia', 'Open Government, West Australia', '🗺️', 'Browse Western Australia''s open data through CKAN endpoints', 'Western Australia''s data catalogue answers CKAN /api/3/action/ calls at catalogue.data.wa.gov.au, returning JSON lists and metadata for state datasets (heavy on geology and mapping). No key, no signup, CORS enabled. Licensing is per-dataset, so check before you reuse.', 17, 'https://data.wa.gov.au/', 'https://catalogue.data.wa.gov.au/api/3', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Varies per dataset', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (290, 'represent-by-open-north', 'Represent by Open North', '🍁', 'Map any Canadian postcode to its elected reps and districts', 'Open North''s Represent API turns a Canadian postal code or point into the electoral districts and representatives that cover it, across federal, provincial, and municipal levels. Add ?format=json for a tidy JSON response; CORS is open. It''s free and keyless.', 17, 'https://represent.opennorth.ca/', 'https://represent.opennorth.ca', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Unverified (open; varies by source dataset)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (291, 'usaspending-gov', 'USAspending.gov', '💸', 'The firehose of US federal spending, straight as JSON', 'USAspending is the official source for how the US government spends money, and its v2 REST API serves agencies, awards, and budget figures without a key. This toptier-agencies call is a simple GET, though many deeper queries expect POST bodies. The data is US federal public-domain.', 17, 'https://api.usaspending.gov/', 'https://api.usaspending.gov/api/v2', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'yes', 'U.S. Government Work (public domain)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (292, 'covid-tracking-project', 'Covid Tracking Project', '🦠', 'The Covid Tracking Project''s frozen US pandemic archive', 'This is the archived v2 API from The Covid Tracking Project, serving daily US testing, hospitalization, and outcome figures as JSON. Data collection stopped on 7 March 2021, so treat it as a historical dataset rather than a live feed. It''s licensed CC BY 4.0 with open CORS.', 14, 'https://covidtracking.com/data/api/version-2', 'https://api.covidtracking.com', 'none', 'endpoint', 1, 1, 'Free — no key required (archived dataset)', 'Unpublished', 0, 'yes', 'CC BY 4.0', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (293, 'covid-19-india', 'Covid-19 India', '🇮🇳', 'Static JSON snapshots of India''s Covid-19 numbers by state', 'data.covid19india.org publishes flat JSON files with state- and district-level case, recovery, and vaccination counts for India. There are no query parameters — you just fetch the file you want. The volunteer project wound down, so the data is frozen in late 2021.', 14, 'https://data.covid19india.org/', 'https://data.covid19india.org', 'none', 'endpoint', 1, 0, 'Free — static JSON files (no key)', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (294, 'healthcare-gov', 'Healthcare.gov', '🏥', 'Healthcare.gov''s marketplace content, dumped as JSON', 'Healthcare.gov exposes its editorial content — glossary terms, articles, and guidance about the US health-insurance marketplace — as static JSON via /api. It''s built for reuse and translation, with each entry carrying both English and Spanish text. No key, US-government content.', 14, 'https://www.healthcare.gov/developers/', 'https://www.healthcare.gov', 'none', 'endpoint', 1, 0, 'Free — no key required', 'Unpublished', 0, 'yes', 'U.S. Government content (CMS)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (295, 'medlineplus-genetics', 'MedlinePlus Genetics', '🧬', 'Plain-language genetics reference from the NLM, in JSON', 'The US National Library of Medicine serves its MedlinePlus Genetics articles — conditions, genes, chromosomes, and mtDNA — as downloadable JSON files, one per topic. Fetch a condition by name and you get its summary, synonyms, and linked resources. Heads up: the CORS header only allows *.nlm.nih.gov origins.', 14, 'https://medlineplus.gov/about/developers/geneticsdatafilesapi/', 'https://medlineplus.gov/download/genetics', 'none', 'endpoint', 1, NULL, 'Free — no key required', 'Unpublished', 0, 'unclear', 'U.S. National Library of Medicine (see NLM terms)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (296, 'nppes', 'NPPES', '🩺', 'Look up any US healthcare provider by their NPI number', 'The CMS NPPES registry API returns public records for US healthcare providers — names, addresses, and taxonomies — keyed by National Provider Identifier. Pass version=2.1 plus at least one search field (like state and city) and you get JSON back. No key, public data.', 14, 'https://npiregistry.cms.hhs.gov/registry/help-api', 'https://npiregistry.cms.hhs.gov', 'none', 'endpoint', 1, 0, 'Free — no key required', 'Unpublished', 0, 'yes', 'U.S. Government (public NPI data)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (297, 'open-data-nhs-scotland', 'Open Data NHS Scotland', '🏴󠁧󠁢󠁳󠁣󠁴󠁿', 'Public Health Scotland''s open health data over CKAN', 'Scotland''s health open-data portal runs CKAN, so its /api/3/action/ endpoints list and search datasets on hospital activity, prescribing, demographics, and more. Responses are JSON, though this host returned no CORS header on our probe. Most datasets carry the Open Government Licence.', 14, 'https://www.opendata.nhs.scot', 'https://www.opendata.nhs.scot/api/3', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'yes', 'Open Government Licence (per dataset)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (298, 'genrenator', 'Genrenator', '🎲', 'Invents a nonsense music genre on every request', 'Genrenator is a delightfully useless toy: hit its endpoint and it hands back one freshly generated, faintly plausible music-genre name as a JSON string (think ''bubblegum hands up new age''). No key needed, and CORS echoes your origin. Perfect filler for demos and jokes.', 13, 'https://binaryjazz.us/genrenator-api/', 'https://binaryjazz.us', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (299, 'lyrics-ovh', 'Lyrics.ovh', '🎤', 'Fetch a song''s lyrics from just artist and title', 'Lyrics.ovh takes an artist and song title in the URL path and returns the lyrics as a single JSON field. It''s keyless with open CORS, which makes it a common first stop for lyric-fetching side projects. The lyrics themselves are third-party copyrighted text, so mind reuse.', 13, 'https://lyricsovh.docs.apiary.io', 'https://api.lyrics.ovh', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Unverified (lyrics are third-party copyrighted)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (300, 'musicbrainz', 'MusicBrainz', '🎵', 'The open music encyclopedia''s read API, JSON on request', 'MusicBrainz is a community-maintained database of artists, releases, and recordings, and its web service lets you look entities up by MBID (append ?fmt=json for JSON). Play nice: it asks for roughly one request per second and a descriptive User-Agent. Core data is CC0.', 13, 'https://musicbrainz.org/doc/Development/XML_Web_Service/Version_2', 'https://musicbrainz.org/ws/2', 'none', 'endpoint', 1, 1, 'Free — no key required', '~1 request/second per IP; descriptive User-Agent required', 0, 'yes', 'Core data CC0; some supplementary data CC BY-NC-SA 3.0', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (301, 'openwhyd', 'Openwhyd', '🎧', 'Curated streaming-track playlists as JSON feeds', 'Openwhyd is an open-source music-curation platform; append ?format=json to its pages and you get JSON lists of user-posted tracks that link out to YouTube, SoundCloud, and friends. This /hot endpoint returns what''s currently trending. Keyless, though no CORS header came back on our probe.', 13, 'https://openwhyd.github.io/openwhyd/API', 'https://openwhyd.org', 'none', 'endpoint', 1, 0, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (302, 'verome', 'Verome', '🎵', 'Search music, charts, lyrics and radio via YouTube Music', 'Verome is a keyless Deno-hosted API that bundles music search, charts, trending tracks, synced lyrics and radio mixes sourced from YouTube Music, YouTube and Last.fm. Hit /api/search with a query and it returns structured artist, song and album results as JSON. Because it proxies third-party services, treat uptime and data rights as those platforms'' own.', 13, 'https://github.com/Kirazul/Verome-API', 'https://verome-api.deno.dev', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (303, 'archive-org', 'Archive.org', '📚', 'Metadata and file listings for Internet Archive items', 'The Internet Archive''s metadata endpoint returns everything it knows about an item: its files, formats, checksums, servers and descriptive fields, all as JSON. Just append an item identifier to /metadata/ — no key, no signup. Handy for building on top of the Archive''s books, audio, video and web collections.', 7, 'https://archive.readme.io/docs', 'https://archive.org', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified (rights vary per item)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (304, 'botsarchive', 'BotsArchive', '🤖', 'Look up Telegram bots by username in a curated catalog', 'BotsArchive maintains a hand-curated database of Telegram bots and exposes their details through a small PHP API. Query /getBotID.php with a bot''s username and it returns the bot''s ID, category, tags, star rating and description as JSON. No key is required for the public lookups.', 7, 'https://botsarchive.com/docs.html', 'https://api.botsarchive.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (305, 'callook-info', 'Callook.info', '📻', 'Look up US ham radio callsigns and licensee details', 'Callook turns any United States amateur-radio callsign into structured JSON: license class, trustee, mailing address, grid square and lat/long. Append /json to a callsign and you''re done — no key needed. The data traces back to the FCC''s public ULS licensing records.', 7, 'https://callook.info', 'https://callook.info', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified (data from public FCC ULS records)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (306, 'lowy-asia-power-index', 'Lowy Asia Power Index', '🌏', 'Rankings of state power across Asia, as JSON', 'The Lowy Institute''s Asia Power Index scores and ranks countries on their comprehensive power across the region, and these endpoints surface the underlying data as JSON. Fetch /data/{year}.json (2018 onward) for per-country scores, ranks and year-on-year trends. The data is the Lowy Institute''s own research, exposed here through a community-written API guide.', 7, 'https://github.com/0x0is1/lowy-index-api-docs', 'https://power.lowyinstitute.org', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified (Lowy Institute research)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (307, 'onyx-bazaar', 'Onyx Bazaar', '🏷️', 'Leaderboard of paid x402 HTTP services on-chain', 'Onyx Bazaar is a public leaderboard of x402 pay-per-call HTTP services, indexed from Coinbase''s CDP discovery API and refreshed roughly every 15 minutes. The /bazaar.json endpoint returns ranked rows carrying each service''s URL, price, network and 30-day call and payer counts. Keyless, CORS-friendly JSON.', 7, 'https://onyx-actions.onrender.com/bazaar', 'https://onyx-actions.onrender.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (308, 'universities-list', 'Universities List', '🎓', 'Search universities by name, country and domain', 'This community dataset (Hipolabs) lets you search universities worldwide and get back their names, countries, web pages and email domains as JSON. Filter with ?name= and/or ?country= — no key, no signup. Note the public host is HTTP-only; there is no working HTTPS endpoint.', 7, 'https://github.com/Hipo/university-domains-list', 'http://universities.hipolabs.com', 'none', 'endpoint', 0, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (309, 'university-of-oslo', 'University of Oslo', '🏫', 'Open course and study-programme data from UiO', 'The University of Oslo publishes its study information as open JSON APIs — courses, semesters, schedules, exams and programmes. Ask /studies/v1/course/{code} for a course''s fundamentals, all keyless. Descriptive fields often come back in Norwegian.', 7, 'https://data.uio.no/', 'https://data.uio.no', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (310, 'voidly', 'Voidly', '🚫', 'Live internet-censorship measurements across 215 countries', 'Voidly aggregates network measurements into a live picture of internet censorship: which domains are blocked, where, and how deeply. The keyless /v1/measurement/summary gives a one-call global snapshot, while /data/censorship-index.json ships the full ranked dataset with Schema.org markup. The index is published under CC BY 4.0, so credit Voidly if you use it.', 7, 'https://voidly.ai/api-docs', 'https://api.voidly.ai', 'none', 'endpoint', 1, 1, 'Free (keyless data endpoints; Hydra ML endpoints need a key)', 'Unpublished', 0, 'yes', 'CC BY 4.0', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (311, 'datamuse', 'Datamuse', '🔤', 'A word-finding engine for rhymes, synonyms and more', 'Datamuse answers word queries: give it constraints like ''rhymes with blue'' or ''means almost the same as X'' and it returns ranked word suggestions as JSON. The /words endpoint takes parameters such as rel_rhy, ml and sp, all keyless. Great for writing tools, word games and autocomplete.', 7, 'https://www.datamuse.com/api/', 'https://api.datamuse.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (312, 'drupal-org', 'Drupal.org', '💧', 'Read Drupal.org projects, issues and users as JSON', 'Drupal.org exposes its own content through a read-only Services API, returning nodes — issues, projects, users and more — as paginated JSON. Hit /api-d7/node.json to page through the data; no key is needed for reads. Useful for dashboards over the Drupal ecosystem.', 7, 'https://www.drupal.org/drupalorg/docs/api', 'https://www.drupal.org/api-d7', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (313, 'shields', 'Shields', '🛡️', 'Badge data (and SVG), now available as JSON too', 'Shields.io is the badge factory behind millions of READMEs. Beyond the usual SVG, appending .json to a /badge/ path returns the badge''s label, message and color as structured JSON. It''s free and keyless; very heavy users are asked to self-host.', 7, 'https://shields.io/', 'https://img.shields.io', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (314, 'advice-slip', 'Advice Slip', '💡', 'Random one-line life advice, served as JSON', 'The Advice Slip API dishes out random pieces of advice, one slip at a time. Call /advice and you get a JSON object with an id and a single line of (often tongue-in-cheek) wisdom. No key, no signup, just advice.', 6, 'https://api.adviceslip.com/', 'https://api.adviceslip.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (315, 'icanhazdadjoke', 'icanhazdadjoke', '😄', 'The internet''s biggest pile of dad jokes, as JSON', 'icanhazdadjoke serves random dad jokes from a large collection. Send an Accept: application/json header to the root URL and it returns a joke plus its id as JSON (otherwise you get plain text or HTML). Keyless and delightfully groan-worthy.', 6, 'https://icanhazdadjoke.com/api', 'https://icanhazdadjoke.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (316, 'quotes-on-design', 'Quotes on Design', '🎨', 'Design-world wisdom served from a WordPress API', 'Pulls inspirational quotes about design and creativity from the Quotes on Design site''s WordPress REST endpoint. Each call returns a post with the author''s name and the quote as rendered HTML. No key needed, just refresh for another dose of studio wisdom.', 6, 'https://quotesondesign.com/api/', 'https://quotesondesign.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (317, 'stoicism-quote', 'Stoicism Quote', '🏛️', 'One Stoic maxim per request from a public Lambda API', 'Returns a single random Stoic quote with its author, drawn from thinkers like Marcus Aurelius. It is backed by an open-source AWS Lambda project and answers plain GET requests with tidy JSON. Handy for calm-inducing widgets and daily-quote bots.', 6, 'https://github.com/tlcheah2/stoic-quote-lambda-public-api', 'https://stoic-quotes.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (318, 'iseven-humor', 'isEven (humor)', '🔢', 'The API that reveals whether a number is even', 'A tongue-in-cheek service that takes a number in the URL path and tells you, in JSON, whether it is even. The free tier even bundles a random text advertisement in every response. Gloriously unnecessary and thoroughly keyless.', 4, 'https://isevenapi.xyz/', 'https://api.isevenapi.xyz', 'none', 'endpoint', 1, 1, 'Free tier limited to numbers 0–999,999 with ads (per site''s joke pricing)', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (319, 'isro', 'ISRO', '🛰️', 'India''s spacecraft roster as clean JSON', 'Lists spacecraft launched by the Indian Space Research Organisation, each with an id and name. This community-built endpoint wraps ISRO''s public data behind a simple, CORS-friendly REST call. No key required to browse the fleet.', 4, 'https://isro.vercel.app', 'https://isro.vercel.app', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (320, 'tle', 'TLE', '📡', 'Two-line element sets for orbiting satellites', 'Serves NORAD two-line element (TLE) orbital data for satellites by catalog number, including the familiar line1/line2 pair and a timestamp. Query 25544 and you get the ISS''s current elements. Ideal for orbit-propagation and satellite-tracking projects.', 4, 'https://tle.ivanstanojevic.me/#/docs', 'https://tle.ivanstanojevic.me', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (321, 'lorem-picsum', 'Lorem Picsum', '🖼️', 'Placeholder photos, plus a JSON catalog of them', 'Best known for serving random placeholder images, Lorem Picsum also exposes a JSON list endpoint describing available photos with author, dimensions, and download URLs. The images themselves come from Unsplash. Great for mocking up galleries without hardcoding assets.', 13, 'https://picsum.photos/', 'https://picsum.photos', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Images sourced from Unsplash', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (322, 'inspirehep-net', 'inspirehep.net', '⚛️', 'Search the high-energy-physics literature by API', 'INSPIRE is the reference database for high-energy physics, and its REST API lets you query papers, authors, and citations. A literature search returns hit metadata like titles and author affiliations as JSON. Open access to millions of HEP records with no login.', 4, 'https://github.com/inspirehep/rest-api-doc', 'https://inspirehep.net', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (323, 'idigbio', 'iDigBio', '🦴', 'Search millions of digitized biological specimens', 'iDigBio aggregates natural-history specimen records from museums and collections worldwide. Its search API accepts a JSON record-query and returns matching specimens with full Darwin Core fields. A single query can surface hundreds of thousands of catalogued organisms.', 4, 'https://github.com/idigbio/idigbio-search-api/wiki', 'https://search.idigbio.org', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (324, 'arcsecond-io', 'arcsecond.io', '🔭', 'Astronomical object data from a single endpoint', 'Arcsecond.io consolidates astronomy data sources behind one API, resolving object names to coordinates, aliases, and catalog cross-references. Ask for m1 and it returns the Crab Nebula''s equatorial position and a stack of alternate designations. Keyless for basic object lookups.', 4, 'https://api.arcsecond.io/', 'https://api.arcsecond.io', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (325, 'itis', 'ITIS', '🌿', 'Federal taxonomy: names, authors, and TSNs', 'The Integrated Taxonomic Information System is a U.S. government database of scientific names for plants, animals, fungi, and microbes. Its JSON web service matches a search term to taxa, returning each name''s author, validity, and taxonomic serial number. Authoritative and free to query.', 4, 'https://www.itis.gov/ws_description.html', 'https://www.itis.gov/ITISWebService/jsonservice', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (326, 'newton', 'Newton', '➗', 'Symbolic and arithmetic math over HTTP', 'Newton solves math expressions passed in the URL path, handling operations like simplify, factor, derive, and integrate. Send it 2^2+2(2) to simplify and it replies with the result 8 in JSON. An open-source calculator you can call from anywhere.', 4, 'https://newton.vercel.app', 'https://newton.vercel.app', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (327, 'noctua', 'Noctua', '🌌', 'Resolve star and sky-object names to catalog data', 'NoctuaSky''s REST API powers a stargazing app and resolves celestial object names to detailed records. Look up Polaris and you get magnitudes, coordinates, spectral type, and a long list of catalog aliases. Useful for planetarium and observing tools.', 4, 'https://api.noctuasky.com/api/v1/swaggerdoc/', 'https://api.noctuasky.com/api/v1', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (328, 'open-science-framework', 'Open Science Framework', '🔬', 'Programmatic access to the Open Science Framework', 'The OSF API exposes public research projects, files, and metadata from the Center for Open Science''s platform. Listing nodes returns project titles, descriptions, categories, and timestamps as JSON:API documents. A gateway to open study designs, data, and preprints.', 4, 'https://developer.osf.io', 'https://api.osf.io/v2', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (329, 'share', 'SHARE', '📚', 'An open dataset of scholarly research activity', 'SHARE compiles metadata about research outputs and scholarly events from a broad network of sources. Its v2 API lists those harvest sources and exposes the aggregated records as JSON:API. A window into who is publishing and sharing what across academia.', 4, 'https://share.osf.io/api/v2/', 'https://share.osf.io/api/v2', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (330, 'usgs-earthquake-hazards-program', 'USGS Earthquake Hazards Program', '🌎', 'Real-time global earthquake feeds as GeoJSON', 'The USGS FDSN event service streams earthquake catalogs going back decades, filterable by time, place, and magnitude. Ask for GeoJSON and you get tidy Features carrying location, depth, and shake metadata for every quake. No key, wide-open CORS, and it''s U.S. government public-domain data.', 4, 'https://earthquake.usgs.gov/fdsnws/event/1/', 'https://earthquake.usgs.gov/fdsnws/event/1', 'none', 'endpoint', 1, 1, 'Free — no API key required', 'Unpublished', 0, 'yes', 'Public domain (U.S. Government work)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (331, 'usgs-water-services', 'USGS Water Services', '💧', 'Live streamflow and gauge readings for US waters', 'USGS Water Services exposes instantaneous and historical measurements from thousands of stream, lake, and groundwater sites across the United States. Query by site number and parameter code (like 00060 for discharge) and receive WaterML-flavored JSON. Public-domain data with no signup required.', 4, 'https://waterservices.usgs.gov/', 'https://waterservices.usgs.gov/nwis', 'none', 'endpoint', 1, 1, 'Free — no API key required', 'Unpublished', 0, 'yes', 'Public domain (U.S. Government work)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (332, 'world-bank', 'World Bank', '🏦', 'Development indicators for every country on Earth', 'The World Bank''s open data API serves thousands of development indicators — GDP, population, health, education — across countries and decades. Endpoints return paginated JSON with a metadata header followed by the data array. Free, keyless, and released under CC BY 4.0.', 4, 'https://datahelpdesk.worldbank.org/knowledgebase/topics/125589', 'https://api.worldbank.org/v2', 'none', 'endpoint', 1, 1, 'Free — no API key required', 'Unpublished', 0, 'yes', 'CC BY 4.0', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (333, 'filterlists', 'FilterLists', '🛡️', 'The directory of adblock and firewall filter lists', 'FilterLists catalogs hundreds of filter lists used by ad blockers, firewalls, and hosts files, along with their maintainers, licenses, syntaxes, and languages. The REST endpoint returns the full catalog as JSON so you can build tooling around block-list metadata. Keyless, though it sends no CORS headers.', 15, 'https://filterlists.com', 'https://api.filterlists.com', 'none', 'endpoint', 1, 0, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (334, 'microsoft-security-response-center-msrc', 'Microsoft Security Response Center (MSRC)', '🔒', 'Microsoft''s security update documents, as CVRF JSON', 'The Microsoft Security Response Center API publishes machine-readable security update summaries in the CVRF format. The updates endpoint lists every monthly release with titles, dates, and links to the full vulnerability documents. No key needed — but it quietly returns an empty body unless your client sends a browser-like User-Agent.', 15, 'https://msrc.microsoft.com/report/developer', 'https://api.msrc.microsoft.com', 'none', 'endpoint', 1, 0, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (335, 'national-vulnerability-database', 'National Vulnerability Database', '🐞', 'The US government''s CVE vulnerability database', 'NIST''s National Vulnerability Database offers the canonical REST feed for CVE records, complete with descriptions, CVSS scores, and references. Look up a single CVE by ID or page through the whole corpus. Keyless access is capped at five requests per 30 seconds; a free key lifts that ceiling.', 15, 'https://nvd.nist.gov/developers/vulnerabilities', 'https://services.nvd.nist.gov/rest/json', 'none', 'endpoint', 1, 1, 'Free — no key required (free key raises limits)', '5 requests per rolling 30 seconds without an API key (50 with a free key)', 0, 'yes', 'Public domain (U.S. Government work)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (336, 'uk-police', 'UK Police', '🚓', 'Street-level crime and policing data for England & Wales', 'The data.police.uk API opens up street-level crimes, outcomes, stop-and-search records, and neighbourhood boundaries from UK police forces. This endpoint lists which months of data each force has published. Free, keyless, and released under the Open Government Licence.', 15, 'https://data.police.uk/docs/', 'https://data.police.uk/api', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'yes', 'Open Government Licence v3.0', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (337, 'hackernews', 'HackerNews', '🟧', 'Read every Hacker News story and comment via Firebase', 'Y Combinator''s Hacker News exposes its entire item graph — stories, comments, jobs, polls, and users — through a simple Firebase REST API. Fetch any item by ID to get its author, score, timestamp, and child comment IDs. No key, and it even echoes your Origin for CORS.', 16, 'https://github.com/HackerNews/API', 'https://hacker-news.firebaseio.com/v0', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (338, 'city-bikes', 'City Bikes', '🚲', 'Live bike-share stations from 500+ networks worldwide', 'CityBikes aggregates real-time bike-sharing data from hundreds of systems across the globe into one consistent API. List every network with its location and operator, then drill into any network for live station availability. Free and keyless with permissive CORS.', 14, 'https://api.citybik.es/v2/', 'https://api.citybik.es/v2', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (339, 'nhl-records-and-stats', 'NHL Records and Stats', '🏒', 'Unofficial NHL franchise, records, and standings data', 'The NHL''s public web endpoints (records.nhl.com and api-web.nhle.com) return rich JSON on franchises, standings, schedules, and historical records. This franchise list maps every team past and present to its abbreviations and seasons. Undocumented and unofficial, but keyless and live.', 14, 'https://gitlab.com/dword4/nhlapi', 'https://records.nhl.com/site/api', 'none', 'endpoint', 1, 0, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (340, 'racinghub', 'RacingHub', '🏎️', 'Formula 1 history from 1950 to today, as clean JSON', 'RacingHub is an open-source REST API wrapping the F1DB dataset of Formula 1 seasons, drivers, constructors, race results, and standings. Endpoints are paginated JSON — the seasons list summarizes champions and race counts year by year. Free and keyless; an independent project not affiliated with Formula 1.', 14, 'https://racinghub.net/api/v1/docs#/', 'https://racinghub.net/api/v1', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'unclear', 'CC BY 4.0 (source data from the F1DB project)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (341, 'tourneyradar', 'TourneyRadar', '♟️', 'Upcoming chess tournaments from 140+ federations', 'TourneyRadar collects upcoming over-the-board chess tournaments from national federations around the world into one JSON feed. Browse events with dates, categories, locations, and geo-coordinates, or search across them. Free, keyless, and CORS-friendly, though it''s a community project with no published terms.', 14, 'https://tourneyradar-api.vercel.app', 'https://tourneyradar-api.vercel.app', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (342, 'bacon-ipsum', 'Bacon Ipsum', '🥓', 'Meat-flavored lorem ipsum placeholder text', 'Bacon Ipsum generates filler text seasoned with cuts of meat instead of Latin. Ask its JSON API for a number of paragraphs — all-meat or meat-and-filler — and it returns an array of savory placeholder strings. Free and keyless with open CORS.', 8, 'https://baconipsum.com/json-api/', 'https://baconipsum.com/api', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (343, 'fakestoreapi', 'FakeStoreAPI', '🛒', 'Fake products, carts, and users for e-commerce demos', 'FakeStoreAPI serves realistic-looking but fictional store data — products, categories, carts, and users — for prototyping shopping UIs. Grab a single product to get its title, price, category, image, and rating. Free and keyless with open CORS.', 8, 'https://fakestoreapi.com/', 'https://fakestoreapi.com', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (344, 'itsthisforthat', 'ItsThisForThat', '💡', 'Instant mad-lib startup pitches, one JSON call at a time', 'Returns a randomly mashed-up ''X for Y'' startup concept as a tiny JSON object with `this` and `that` fields. Perfect filler for demos, placeholder copy, or a laugh in standup. No key, no signup, just hit the endpoint.', 8, 'https://itsthisforthat.com/api.php', 'https://itsthisforthat.com', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished (docs ask you not to hammer it)', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (345, 'randomuser', 'RandomUser', '🧑', 'Fake but realistic user profiles for your test fixtures', 'Generates lifelike random people with names, addresses, emails, logins, and photo URLs. Handy for seeding databases, mocking UIs, or load-testing forms without touching real PII. Returns clean JSON and supports nationality and field filters.', 8, 'https://randomuser.me', 'https://randomuser.me', 'none', 'endpoint', 1, 1, 'Free — no key or signup', 'Unpublished', 0, 'unclear', 'Unverified (generated data; sample photos governed by UI Faces terms)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (346, 'uuid-generator', 'UUID Generator', '🆔', 'Bulk RFC-compliant UUIDs served straight as JSON', 'Generates v1/v3/v4/v5 UUIDs on demand and hands them back as a plain JSON array. Point it at /api/generate/v1 for a fresh identifier or request batches for seeding. No account, no key, CORS-friendly.', 8, 'https://www.uuidtools.com/docs', 'https://www.uuidtools.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (347, 'yes-no', 'Yes No', '🎱', 'A coin-flip oracle that answers yes, no, or maybe', 'Returns a random yes/no/maybe verdict plus a matching animated GIF, all as JSON. Great for magic-8-ball bots, decision-paralysis jokes, or teaching students to parse an API. Keyless and open to cross-origin requests.', 8, 'https://yesno.wtf/api', 'https://yesno.wtf', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (348, 'libretranslate', 'LibreTranslate', '🌐', 'Self-hostable machine translation with an open API', 'An open-source translation engine whose hosted instance exposes /languages as a keyless JSON GET listing supported language pairs. The actual /translate call on the public host may require an API key or donation. The software is AGPL-3.0 and can be self-hosted for unrestricted use.', 8, 'https://libretranslate.com/docs', 'https://libretranslate.com', 'none', 'endpoint', 1, 1, 'Free — /languages is keyless; hosted /translate may require a key or donation', 'Unpublished (per hosted instance)', 0, 'unclear', 'Unverified (software is AGPL-3.0)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (349, 'postalpincode', 'PostalPinCode', '📮', 'Look up any Indian PIN code''s post offices in JSON', 'Resolves a six-digit Indian PIN code into every post office it covers, with district, division, circle, and delivery status. Also supports lookup by post-office name. Returns JSON with no key required.', 10, 'http://www.postalpincode.in/Api-Details', 'https://api.postalpincode.in', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (350, 'refuge-restrooms', 'REFUGE Restrooms', '🚻', 'Crowd-sourced safe, accessible, gender-neutral restrooms', 'A community-maintained directory of restrooms that are safe for transgender, intersex, and gender-nonconforming people. Query by page or location to get names, addresses, coordinates, and accessibility flags as JSON. Open source and keyless.', 10, 'https://www.refugerestrooms.org/api/docs/', 'https://www.refugerestrooms.org/api/v1', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Unverified (project is open source on GitHub)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (351, 'transport-for-norway', 'Transport for Norway', '🚆', 'Norway-wide stops and journeys from Entur''s open data', 'Entur''s national mobility platform exposes open geocoding and journey planning over Norway''s public transport. The geocoder autocomplete resolves place and stop names into coordinates as JSON, no key needed. Entur asks callers to send an ET-Client-Name header to avoid rate limiting.', 10, 'https://developer.entur.org/', 'https://api.entur.io', 'none', 'endpoint', 1, 1, 'Free — open data, no key; ET-Client-Name header requested', 'Rate-limited for unidentified consumers (no numeric threshold published)', 0, 'yes', 'Norwegian Licence for Open Government Data (NLOD)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (352, 'transport-for-spain', 'Transport for Spain', '🚉', 'Renfe rail station data via Spain''s open CKAN portal', 'Renfe''s open-data portal serves railway reference data through a standard CKAN datastore API. The datastore_search endpoint returns station records with codes, names, coordinates, and addresses as JSON, no key required. Data and field names are in Spanish.', 10, 'https://data.renfe.com/api/1/util/snippet/api_info.html?resource_id=a2368cff-1562-4dde-8466-9635ea3a572a', 'https://data.renfe.com/api/3/action', 'none', 'endpoint', 1, 0, 'Free — no key required', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (353, 'transport-for-switzerland', 'Transport for Switzerland', '🚃', 'Swiss train connections and schedules, no key needed', 'A friendly wrapper over Swiss public-transport timetables that returns connections, departures, and station lookups as JSON. Ask for a route between two towns and get platforms, times, and live delay data back. Keyless and CORS-enabled; throughput is bounded by the underlying timetable.search.ch limits.', 10, 'https://transport.opendata.ch/', 'https://transport.opendata.ch/v1', 'none', 'endpoint', 1, 1, 'Free — no key required', 'Bounded by timetable.search.ch limits (no fixed number published)', 0, 'unclear', 'Unverified (powered by Opendata.ch)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (354, 'transport-for-the-netherlands', 'Transport for The Netherlands', '🚌', 'Live Dutch bus, tram, and train departures, nationwide', 'OVAPI exposes real-time public-transport data for the whole of the Netherlands, keyed by line and stop. Query lines, stops, and live departure times as plain JSON with no key required. Heads up: the domain''s TLS certificate is misconfigured, so it answers cleanly only over plain HTTP.', 10, 'https://github.com/skywave/KV78Turbo-OVAPI/wiki', 'http://v0.ovapi.nl', 'none', 'endpoint', 0, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (355, 'transport-for-toronto-canada', 'Transport for Toronto, Canada', '🚇', 'Toronto TTC stops and next-departure times as JSON', 'myTTC turns any Toronto Transit Commission station or stop into a tidy JSON feed of routes and upcoming departure times. Append .json to a stop''s slug and you get schedules without signing up. Handy for building transit widgets around the TTC network.', 10, 'https://myttc.ca/developers', 'https://myttc.ca', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (356, 'auto-body-shop-directory', 'Auto Body Shop Directory', '🔧', 'Search 43k+ US auto body and repair shops by city', 'AutoBodyShopNear.com publishes a directory of tens of thousands of US collision, repair, and recycler shops. Public GET endpoints page through listings by city, state, or ZIP and return each shop''s address and phone. Reuse asks that you credit the source and link back to the shop profile.', 10, 'https://autobodyshopnear.com/developers/body-shop-api', 'https://autobodyshopnear.com/api/v1/public', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Proprietary — attribution + link-back required', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (357, 'brazilian-vehicles-and-prices', 'Brazilian Vehicles and Prices', '🚗', 'Brazil''s official FIPE car, bike, and truck price tables', 'This community API wraps Brazil''s FIPE reference price tables for cars, motorcycles, and trucks. Walk from brands to models to model-years and read the average market price, all as keyless JSON. Great for Brazilian automotive pricing and valuation tools.', 10, 'https://deividfortuna.github.io/fipe/', 'https://parallelum.com.br/fipe/api/v1', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified (data sourced from Fundação Instituto de Pesquisas Econômicas / FIPE)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (358, 'nhtsa', 'NHTSA', '🚙', 'Decode US VINs and look up every registered make', 'NHTSA''s vPIC service is the US government''s catalog of vehicle makes, models, and VIN decoding. Fetch all manufacturers or decode a VIN into make, model, and body class straight from federal data. No key, and as a US Government work the data sits in the public domain.', 10, 'https://vpic.nhtsa.dot.gov/api/', 'https://vpic.nhtsa.dot.gov/api', 'none', 'endpoint', 1, 1, 'Free, no key', 'Unpublished', 0, 'yes', 'Public domain (U.S. Government work)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (359, 'an-api-of-ice-and-fire', 'An API of Ice And Fire', '🐉', 'Books, characters, and houses from Game of Thrones lore', 'An API of Ice and Fire serves structured data on the books, characters, and houses of George R. R. Martin''s A Song of Ice and Fire. Every resource is a hyperlinked JSON document you can crawl without a key. A friendly playground for REST and pagination demos.', 13, 'https://anapioficeandfire.com/', 'https://anapioficeandfire.com/api', 'none', 'endpoint', 1, 1, 'Free, no key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (360, 'ron-swanson-quotes', 'Ron Swanson Quotes', '🥓', 'Random Ron Swanson wisdom, one gruff quote at a time', 'This tiny service returns random quotes from Parks and Recreation''s Ron Swanson as a JSON array. Ask for one or several at once, no key needed. It runs on a free Heroku dyno, so expect the occasional cold-start pause.', 13, 'https://github.com/jamesseanwright/ron-swanson-quotes#ron-swanson-quotes-api', 'https://ron-swanson-quotes.herokuapp.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (361, 'lucifer-quotes', 'Lucifer Quotes', '😈', 'Random quotes from the devil himself, as JSON', 'A minimal open-source endpoint that hands back random lines from the TV series Lucifer, wrapped as a small JSON array of quote and author. No signup, no key, permissive CORS. Drop-in filler for demos, bots, or quote-of-the-day widgets.', 13, 'https://github.com/shadowoff09/lucifer-quotes', 'https://lucifer-quotes.vercel.app', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (362, 'stranger-things-quotes', 'Stranger Things Quotes', '🔦', 'Random Stranger Things quotes with speaker attribution', 'This open-source API returns random quotes from Stranger Things, each tagged with the character who said it, as plain JSON. It needs no key and sets open CORS headers, so it works straight from the browser. Nice for lightweight fan projects and coding tutorials.', 13, 'https://github.com/shadowoff09/strangerthings-quotes', 'https://strangerthings-quotes.vercel.app', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (363, 'stromberg-quotes', 'Stromberg Quotes', '💼', 'Quotes, characters, and episodes from sitcom Stromberg', 'The Stromberg API serves quotes, characters, and episode data from the German mockumentary sitcom Stromberg. Endpoints under /api return random or searchable JSON with open CORS and no key. Responses are in German, fitting for the source material.', 13, 'https://www.stromberg-api.de/', 'https://www.stromberg-api.de', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (364, 'swapi-graphql', 'SWAPI GraphQL', '🌌', 'Star Wars films, people, and planets over GraphQL', 'A GraphQL wrapper around SWAPI covering Star Wars films, characters, planets, and starships. Send the query as a URL parameter on a GET request and it answers with exactly the fields you asked for, no key required. Useful for learning GraphQL against familiar data.', 13, 'https://graphql.org/swapi-graphql', 'https://swapi-graphql.netlify.app/.netlify/functions', 'none', 'endpoint', 1, 1, 'Free, no key', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (365, 'thronesapi', 'ThronesApi', '⚔️', 'Game of Thrones characters with portraits, as JSON', 'ThronesApi lists Game of Thrones characters along with their house, title, and a hosted portrait image URL. A single keyless GET returns the full roster as JSON. Convenient when you want character art plus metadata in one call.', 13, 'https://thronesapi.com/', 'https://thronesapi.com/api/v2', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (366, 'aviationweather', 'AviationWeather', '🛩️', 'NOAA METARs, TAFs, and PIREPs in machine-readable JSON', 'AviationWeather.gov is NOAA/NWS''s official feed of aviation weather: METAR observations, TAF forecasts, and pilot reports. Request a station''s latest METAR as JSON with a plain GET and no key. Being US Government data, it is public domain. Note: no CORS header is sent.', 1, 'https://www.aviationweather.gov/dataserver', 'https://aviationweather.gov/api/data', 'none', 'endpoint', 1, 0, 'Free, no key', 'Unpublished (NWS requests reasonable use)', 0, 'yes', 'Public domain (U.S. Government / NOAA)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (367, 'hong-kong-observatory', 'Hong Kong Observatory', '🌦️', 'Hong Kong weather, warnings, and climate open data', 'The Hong Kong Observatory''s open-data API returns current weather, rainfall by district, forecasts, and warnings as JSON. A single keyless GET with a dataType parameter pulls the current-conditions report. Data is bilingual (English and Chinese) via a lang switch.', 1, 'https://www.hko.gov.hk/en/abouthko/opendata_intro.htm', 'https://data.weather.gov.hk/weatherAPI/opendata', 'none', 'endpoint', 1, 1, 'Free, no key', 'Unpublished', 0, 'unclear', 'HKO open data (see terms of use)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (368, 'ipma', 'IPMA', '☀️', 'Portugal''s official city weather forecasts as JSON', 'IPMA, Portugal''s meteorological institute, publishes open weather and climate data including multi-day city forecasts. Fetch a city''s daily forecast by its numeric ID as static JSON with no key. Attribution to IPMA is expected when you reuse the data.', 1, 'https://api.ipma.pt/open-data/', 'https://api.ipma.pt/open-data', 'none', 'endpoint', 1, 1, 'Free, no key', 'Unpublished', 0, 'unclear', 'IPMA open data (attribution ''Fonte: IPMA'' expected)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (369, 'rainviewer', 'RainViewer', '🌧️', 'Global weather-radar tile timestamps and map metadata', 'RainViewer''s public API returns the latest global radar and satellite map frames as a JSON index of timestamps and tile paths. One keyless GET gives you everything needed to animate a precipitation radar layer. Attribution to RainViewer is requested.', 1, 'https://www.rainviewer.com/api.html', 'https://api.rainviewer.com/public', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified (attribution requested)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (370, 'meteorologisk-institutt', 'Meteorologisk Institutt', '🌤️', 'Norwegian Met Institute global forecasts, free with attribution', 'The Norwegian Meteorological Institute''s api.met.no provides global point forecasts, including the compact locationforecast used here. Pass latitude and longitude and it returns hourly temperature, wind, and precipitation as JSON. It requires an identifying User-Agent and is licensed under CC BY 4.0 / NLOD.', 1, 'https://api.met.no/weatherapi/documentation', 'https://api.met.no/weatherapi', 'none', 'endpoint', 1, 1, 'Free, no key; requires identifying User-Agent', 'Throttled; identify via User-Agent and respect caching headers (per docs)', 0, 'yes', 'CC BY 4.0 / NLOD (Norwegian Licence for Open Government Data)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
