insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (390, 'kroki', 'Kroki', '📐', 'Diagrams from text — health and metadata JSON', 'Renders Mermaid, PlantUML and more to images. The /health route returns service status as JSON; diagram POST routes return binary media.', 8, 'https://kroki.io', 'https://kroki.io', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
