insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (393, 'indian-mutual-fund', 'Indian Mutual Fund', '💰', 'Indian Mutual Fund — Get complete history of India Mutual Funds Data', 'Indian Mutual Fund exposes get complete history of India Mutual Funds Data We verified a keyless GET endpoint returning JSON (Finance). Check the provider docs for rate limits and terms before production use.', 2, 'https://www.mfapi.in/', 'https://api.mfapi.in', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (394, 'thecocktaildb', 'TheCocktailDB', '🍸', 'Cocktail recipes, ingredients and glassware', 'TheCocktailDB is a crowd-sourced drinks database with the free test key `1` embedded in the URL path. Pull a random cocktail, search by name, or filter by ingredient — every response is JSON with measures, instructions and thumbnail images. Sister project to TheMealDB.', 14, 'https://www.thecocktaildb.com/api/json/v1/1', 'https://www.thecocktaildb.com/api/json/v1/1', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (395, 'd-d-5e-api', 'D&D 5e API', '🐉', 'Dungeons & Dragons 5e spells, monsters and classes', 'The D&D 5e API serves the System Reference Document as linked JSON: spells, monsters, classes, equipment and rules. No key, permissive CORS, and stable resource URLs — the go-to backend for character builders and homebrew tools.', 11, 'https://www.dnd5eapi.co/api', 'https://www.dnd5eapi.co/api', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (396, 'magic-the-gathering', 'Magic: The Gathering', '🪄', 'Magic: The Gathering cards, sets and types', 'The magicthegathering.io API exposes every MTG card with mana cost, rulings, set and multiverse IDs. Paginated JSON, no authentication, and generous rate limits for hobby projects. Useful for deck builders and card-price companions.', 11, 'https://api.magicthegathering.io/v1', 'https://api.magicthegathering.io/v1', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (397, 'itunes-search', 'iTunes Search', '🎵', 'Search Apple Music, iTunes, App Store and podcasts', 'Apple''s public iTunes Search API returns music, apps, movies, books and podcasts as JSON with artwork URLs and preview links. No key required; keep requests modest per Apple''s guidance. Widely used for music metadata and podcast directories.', 6, 'https://itunes.apple.com', 'https://itunes.apple.com', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (398, 'deezer', 'Deezer', '🎧', 'Music catalog — tracks, albums, artists and previews', 'Deezer''s public API returns track, album and artist metadata with 30-second preview URLs. Search and object-lookup routes need no key; OAuth is only for user playlists. CORS is closed, so call it server-side. Great for music-discovery UIs.', 6, 'https://api.deezer.com', 'https://api.deezer.com', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (399, 'urban-dictionary', 'Urban Dictionary', '📖', 'Crowd-sourced slang definitions and examples', 'The unofficial-but-stable Urban Dictionary API returns definitions, usage examples and up/down votes for any term. Keyless JSON; note that content is user-submitted and may be NSFW, so filter before showing to general audiences.', 6, 'https://api.urbandictionary.com/v0', 'https://api.urbandictionary.com/v0', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (400, 'timeapi-io', 'TimeAPI.io', '🕐', 'Current time, time-zone and conversion by zone', 'TimeAPI.io returns the current date-time for any IANA time zone plus conversion, day-of-week and DST helpers. Free and keyless JSON — a modern option for scheduling apps that need reliable time-zone math without bundling tzdata.', 16, 'https://timeapi.io/api', 'https://timeapi.io/api', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (401, 'binance', 'Binance', '📈', 'Live crypto spot prices and market data', 'Binance''s public market-data endpoints return spot prices, order books and klines without an API key (keys are only for trading). The /ticker/price route is the lightest quote check. Respect the weight-based rate limits in production.', 9, 'https://api.binance.com/api/v3', 'https://api.binance.com/api/v3', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (402, 'coinbase', 'Coinbase', '🪙', 'Crypto and fiat exchange rates from Coinbase', 'Coinbase''s public v2 endpoints return exchange rates, spot/buy/sell prices and currency lists with no authentication. Pass any base currency to /exchange-rates for a full cross-rate map. Ideal for lightweight crypto tickers and converters.', 9, 'https://api.coinbase.com/v2', 'https://api.coinbase.com/v2', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (403, 'kraken', 'Kraken', '🐙', 'Public crypto ticker, order book and OHLC data', 'Kraken''s public REST endpoints expose ticker, depth, spread and OHLC data keyless (auth is trading-only). Responses wrap payloads in an {error, result} envelope. A solid, well-documented source for crypto price feeds.', 9, 'https://api.kraken.com/0/public', 'https://api.kraken.com/0/public', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (404, 'blockchain-info', 'Blockchain.info', '🔗', 'Bitcoin price across dozens of fiat currencies', 'Blockchain.info''s /ticker returns the current BTC price — 15-minute delayed plus buy/sell — across 30+ fiat currencies as JSON. Keyless and long-lived; the wider Blockchain Data API also exposes blocks and transactions for on-chain explorers.', 9, 'https://blockchain.info', 'https://blockchain.info', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (405, 'bigdatacloud-geocode', 'BigDataCloud Geocode', '📌', 'Client-side reverse geocoding — no key', 'BigDataCloud''s reverse-geocode-client endpoint turns latitude/longitude into locality, city and country without an API key (it is free for client-side use). Returns localized place names and the admin hierarchy — handy for "where am I" features and location labels.', 3, 'https://api.bigdatacloud.net/data', 'https://api.bigdatacloud.net/data', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (406, 'elden-ring-api', 'Elden Ring API', '⚔️', 'Elden Ring items, bosses, weapons and NPCs', 'A community Elden Ring database exposing bosses, weapons, armor, spells, classes and NPCs as paginated JSON. No key; responses carry a count/total envelope for easy paging. Popular for build planners and wiki mirrors.', 11, 'https://eldenring.fanapis.com/api', 'https://eldenring.fanapis.com/api', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (407, 'sampleapis', 'SampleAPIs', '🧪', 'Ready-made mock datasets for prototyping', 'SampleAPIs serves themed fake datasets — coffee, cocktails, movies, cars, football and more — as static JSON arrays. No key, CORS-open, and perfect for wiring up a frontend before the real backend exists.', 8, 'https://api.sampleapis.com', 'https://api.sampleapis.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (408, 'affirmations-dev', 'Affirmations.dev', '💪', 'Random positive affirmation as tiny JSON', 'affirmations.dev returns a single uplifting affirmation per request in a one-field JSON body. No key, CORS-open, and about as simple as an API gets — a friendly hello-world fetch or a daily-motivation widget.', 6, 'https://www.affirmations.dev', 'https://www.affirmations.dev', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (409, 'fbi-wanted', 'FBI Wanted', '🕵️', 'FBI Most Wanted list as structured JSON', 'The FBI''s public Wanted API returns current cases — fugitives, missing persons and seeking-information notices — with photos, descriptions, subjects and field offices. No key; paginate with page/pageSize. Official US government open data.', 17, 'https://api.fbi.gov', 'https://api.fbi.gov', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (410, 'theaudiodb', 'TheAudioDB', '🎶', 'Artist, album and track metadata with artwork', 'TheAudioDB is a community music-metadata database with the free test key `2` in the path. Search artists, list albums and tracks, and pull banners, logos and biographies. Sister site to TheSportsDB and TheMealDB.', 6, 'https://www.theaudiodb.com/api/v1/json/2', 'https://www.theaudiodb.com/api/v1/json/2', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (411, 'exchangerate-api-open', 'ExchangeRate-API (open)', '💱', 'Daily fiat exchange rates — open, no key', 'The open ExchangeRate-API endpoint returns daily-updated fiat rates for 160+ currencies with no key or signup. One GET on /latest/{base} yields the full cross-rate table plus next-update timestamps. Good for converters that can tolerate daily granularity.', 2, 'https://open.er-api.com/v6', 'https://open.er-api.com/v6', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (412, 'wger-workout', 'wger Workout', '🏋️', 'Open exercise and nutrition database', 'wger is an open-source workout manager whose REST API exposes exercises, muscles, equipment and ingredients. Read endpoints are public and keyless (append format=json); a token is only needed to write to a user account. Great for fitness-app prototypes.', 14, 'https://wger.de/api/v2', 'https://wger.de/api/v2', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (413, 'zenodo', 'Zenodo', '🔬', 'Search open research datasets and publications', 'Zenodo (run by CERN) hosts open datasets, papers and software with DOIs. Its API searches and fetches records with metadata, files and citation info — keyless for read access, though a token raises rate limits. A front door to open-science outputs.', 7, 'https://zenodo.org/api', 'https://zenodo.org/api', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (414, 'gbif', 'GBIF', '🦋', 'Global biodiversity — species and occurrences', 'The Global Biodiversity Information Facility API serves taxonomic names, species records and billions of occurrence points contributed by museums and researchers worldwide. Keyless JSON with rich filtering — the standard source for biodiversity and mapping tools.', 4, 'https://api.gbif.org/v1', 'https://api.gbif.org/v1', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (415, 'inaturalist', 'iNaturalist', '🐾', 'Species, observations and photos from iNaturalist', 'iNaturalist''s API exposes crowd-sourced wildlife observations, taxa and identification photos. Read endpoints are public and keyless (OAuth only for posting). Filter by taxon, place or user — ideal for nature-ID apps and citizen-science dashboards.', 5, 'https://api.inaturalist.org/v1', 'https://api.inaturalist.org/v1', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (416, 'restful-api-dev', 'restful-api.dev', '🧰', 'Free CRUD sandbox for objects — no signup', 'restful-api.dev is a free hosted REST sandbox: GET a list of sample objects and POST/PUT/DELETE your own for testing HTTP clients. No key or signup, JSON throughout. Handy for tutorials, Postman demos and integration tests.', 8, 'https://api.restful-api.dev', 'https://api.restful-api.dev', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (417, 'lichess', 'Lichess', '♟️', 'Open chess data — players, games and puzzles', 'Lichess exposes profiles, ratings, game exports (PGN/JSON) and tournaments through a public API. Many read endpoints need no token (one raises rate limits and unlocks account routes). The go-to open alternative to Chess.com for chess tooling.', 11, 'https://lichess.org/api', 'https://lichess.org/api', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (418, 'php-noise', 'PHP-Noise', '🌫️', 'Generate seamless noise-texture backgrounds from a color', 'Feed it a hex or RGB color and it returns a procedurally generated noise-texture PNG, optionally as a base64 data URI wrapped in JSON. Useful for CSS backgrounds, placeholder art and subtle grain overlays. Fully keyless with a handful of tuning parameters.', 13, 'https://php-noise.com/', 'https://php-noise.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (419, 'xcolors', 'xColors', '🎨', 'Generate and convert colors across hex, RGB and HSL', 'Ask for a random color and receive it in hex, RGB and HSL at once, or convert a color you already have between those formats. A lightweight helper for palettes, theming and design tooling. Runs keyless on a community-hosted instance after the original Heroku host retired.', 13, 'https://x-colors.yurace.pro', 'https://x-colors.yurace.pro/api', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (420, 'downstatus', 'DownStatus', '🟢', 'Real-time up/down status for 90+ popular services', 'A keyless JSON feed reporting whether services like Discord, GitHub and Cloudflare are operational, degraded or down, aggregated from user reports. Query one service by slug, list every tracked service, or pull ongoing outages. Each record carries recent report counts and a link to the human-readable status page.', 8, 'https://isitdownstatus.com/en/api-docs', 'https://isitdownstatus.com/api/v1', 'none', 'endpoint', 1, 1, 'Free — no API key (per docs)', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (421, 'bng2latlong', 'bng2latlong', '🗺️', 'Convert British National Grid coords to lat/long', 'Turns OSGB36 British National Grid coordinates (easting, northing) into WGS84 decimal latitude and longitude, returned as a compact JSON object with a status flag. Part of GetTheData''s set of free UK reference-data services. No key or POST body needed.', 3, 'https://www.getthedata.com/bng2latlong', 'https://api.getthedata.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (422, 'open-government-portugal', 'Open Government, Portugal', '🇵🇹', 'Portugal''s national open-data catalog as paginated JSON', 'The API behind Portugal''s official open-data portal, listing datasets with metadata such as access type, description, timestamps, badges, and contact points. Responses are paginated JSON so you can crawl the whole catalog. Built on the udata platform and keyless for reads.', 17, 'https://dados.gov.pt/en/docapi/', 'https://dados.gov.pt/api/1', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified (per-dataset licenses, mostly open)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (423, 'helium', 'Helium', '📈', 'Media-bias news scoring and AI market forecasts', 'Serves financial news search with source-bias scoring and balanced synthesis, plus AI-generated market data such as ticker forecasts with bullish and bearish cases and probability-weighted outcomes. The first fifty queries per IP need no key. Endpoints are shaped for MCP-style agent tooling.', 2, 'https://heliumtrades.com/mcp-page/', 'https://heliumtrades.com', 'none', 'endpoint', 1, 1, 'First 50 queries per IP free, no key (paid API key beyond, ~$0.02/query)', '50 free queries per IP subnet', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (424, 'wolne-lektury', 'Wolne Lektury', '📚', 'Polish free-library books, authors and epochs as JSON', 'A keyless catalog API for WolneLektury.pl, Poland''s free digital library of public-domain and open-licensed literature. Query books, authors, genres and literary epochs, each returning tidy JSON with cover art, colors and download links. The full book list is a multi-megabyte payload, so lean on the smaller collection endpoints for quick calls.', 12, 'https://wolnelektury.pl/api/', 'https://wolnelektury.pl/api', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Works are public domain or on free/Creative Commons licenses (per WolneLektury); API terms not formally stated', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (425, 'rig-veda', 'Rig Veda', '🕉️', 'Structured metadata for the hymns of the Rig Veda', 'Turns the Rig Veda''s corpus of Vedic hymns into queryable JSON: which gods are praised, which poets composed the verses, and which metrical patterns they follow. Endpoints slice the material by mandala, deity, poet, meter or category, with an expanded mode for hymn-level detail. It runs on a free Render instance, so the first request after an idle period may cold-start before later calls settle around one second.', 12, 'https://aninditabasu.github.io/indica/topics/api_rv.html', 'https://indica-1hwj.onrender.com/rv/v3', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (426, 'bank-of-russia', 'Bank of Russia', '🏦', 'Central Bank of Russia daily FX rates, served as JSON', 'A community JSON mirror of the Bank of Russia''s official daily exchange-rate fixing, which the central bank itself publishes only as XML/SOAP. A single GET returns every listed currency''s ruble value alongside the previous day''s rate, making day-over-day deltas trivial. No key, CORS-open, and refreshed each business day around 11:30 Moscow time.', 2, 'https://www.cbr-xml-daily.ru/', 'https://www.cbr-xml-daily.ru', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified (underlying rates are official Bank of Russia public data)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (427, 'excuser', 'Excuser', '🙈', 'Random ready-made excuses, tagged by category, as JSON', 'A tiny novelty API that hands back a random excuse whenever you need one, sorted into categories like funny, office and family. Each call returns a small JSON array with an id, the excuse text and its category. The original Heroku deployment retired, so it now lives on a Vercel host.', 6, 'https://excuser-three.vercel.app/', 'https://excuser-three.vercel.app', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (428, 'national-grid-eso', 'National Grid ESO', '⚡', 'Great Britain''s electricity system operator open data, CKAN-style', 'The operator formerly known as National Grid ESO (now NESO) publishes Britain''s grid data through a standard CKAN API. List every dataset with a single keyless GET, then drill into wind forecasts, demand, carbon intensity and more. No key, no signup.', 1, 'https://www.neso.energy/data-portal', 'https://api.neso.energy/api/3', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'NESO Open Data Licence (OGL-based); varies per dataset', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (429, 'city-berlin', 'City, Berlin', '🐻', 'Berlin''s open data catalog via a plain CKAN API', 'Berlin''s official open data register runs on CKAN, so a single keyless GET returns the names of every published dataset. From there you can reach 3D building models, transit, demographics and thousands more city datasets. No key or account needed.', 17, 'https://daten.berlin.de/', 'https://datenregister.berlin.de/api/3', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Varies per dataset (many CC-BY / dl-de-by-2.0)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (430, 'istanbul-ibb-open-data', 'Istanbul (İBB) Open Data', '🏙️', 'Istanbul Metropolitan Municipality open data, CKAN-powered', 'The İBB (Istanbul Metropolitan Municipality) publishes city datasets through a standard CKAN API. A keyless package search returns titles, owning departments and resource counts across 500-plus datasets. Great for transit, environment and municipal statistics.', 17, 'https://data.ibb.gov.tr', 'https://data.ibb.gov.tr/api/3', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified (varies per dataset)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (431, 'open-government-argentina', 'Open Government, Argentina', '🇦🇷', 'Argentina''s national open data portal over CKAN', 'datos.gob.ar is Argentina''s central government open data catalog, served through a standard CKAN API. A keyless package search returns dataset titles, slugs and resource counts across 1,200-plus datasets. Covers prices, budgets, geography and more.', 17, 'https://datos.gob.ar/', 'https://datos.gob.ar/api/3', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified (varies per dataset)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (432, 'open-government-denmark', 'Open Government, Denmark', '🇩🇰', 'Danish municipal open data through a CKAN API', 'opendata.dk aggregates open data from Danish municipalities on a CKAN backend. A keyless package search returns dataset titles, slugs and resource counts across 600-plus datasets. Handy for local transport, planning and civic data.', 17, 'https://www.opendata.dk/', 'https://admin.opendata.dk/api/3', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified (varies per dataset)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (433, 'district-of-columbia-open-data', 'District of Columbia Open Data', '🏛️', 'Washington DC''s GIS datasets as queryable ArcGIS JSON', 'Washington DC serves its open datasets through public ArcGIS REST feature services. This keyless query hits the Metropolitan Police crime-incidents layer and returns structured JSON with offense, method, shift and block. Swap the layer id for other city data.', 17, 'http://opendata.dc.gov/pages/using-apis', 'https://maps2.dcgis.dc.gov/dcgis/rest/services/FEEDS/MPD/MapServer', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified (DC Open Data terms)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (434, 'open-government-singapore', 'Open Government, Singapore', '🇸🇬', 'Live Singapore environment, transport and weather data, no key', 'Singapore''s national open-data platform exposes real-time government feeds such as air temperature, rainfall and traffic, all as plain JSON. No signup or key is needed, and responses are CORS-enabled for browser apps. Handy for dashboards that want fresh readings straight from official sensors.', 17, 'https://data.gov.sg/developer', 'https://api.data.gov.sg/v1', 'none', 'endpoint', 1, 1, 'Free — no API key required; limits not published', 'Unpublished', 0, 'unclear', 'Singapore Open Data Licence', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (435, 'open-government-taiwan', 'Open Government, Taiwan', '🇹🇼', 'Metadata for Taiwan''s national open-data catalog, keyless', 'Taiwan''s government open-data portal offers a keyless REST API returning JSON metadata for each published dataset, including title, provider, license and update cadence. Fetch a dataset by its numeric id to see how the catalog describes it. Useful for indexing or exploring what Taiwanese agencies have released.', 17, 'https://data.gov.tw/', 'https://data.gov.tw/api/v2', 'none', 'endpoint', 1, 0, 'Free — no API key required; limits not published', 'Unpublished', 0, 'unclear', 'Open Government Data License, Taiwan (portal code "1")', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (436, 'songsterr', 'Songsterr', '🎸', 'Search guitar, bass and drum tabs by artist or title', 'Songsterr''s search endpoint returns JSON listings of songs matching a text pattern, each with a song id, artist, title and the available instrument tracks. No key is required for the search call. Good for looking up whether tabs exist for a given artist before deep-linking into the player.', 13, 'https://www.songsterr.com/a/wa/api/', 'https://www.songsterr.com/api', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (437, 'english-random-words', 'English Random Words', '📖', 'One random English word with a definition and pronunciation', 'Hits a single GET and returns a random English word bundled with its short definition and a pronunciation hint. Handy for word-of-the-day widgets, vocabulary drills, or seeding test data. No key, no params required.', 8, 'https://random-words-api.vercel.app/word', 'https://random-words-api.vercel.app', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (438, 'opensky-network', 'OpenSky Network', '✈️', 'Live ADS-B aircraft state vectors over a bounding box', 'Returns real-time state vectors (position, altitude, velocity, heading) for aircraft currently tracked by the OpenSky sensor network. Anonymous requests work without a key but are throttled and coarsened in time resolution. Great for flight-tracking maps and airspace dashboards.', 10, 'https://opensky-network.org/apidoc/index.html', 'https://opensky-network.org/api', 'none', 'endpoint', 1, 0, 'Free for non-commercial/research use; anonymous requests are rate-limited and time-coarsened', 'Anonymous access throttled; registered/OAuth users get higher limits', 0, 'no', 'Non-commercial/research use per OpenSky terms', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (439, 'transport-for-los-angeles-us', 'Transport for Los Angeles, US', '🚌', 'LA Metro bus and rail route overviews, keyless JSON', 'The LA Metro API (v2.1.38) serves GTFS-derived route, stop, shape and real-time trip data for LACMTA bus and rail, all keyless with CORS enabled. The route_overview endpoint lists every line with names, colors, terminals and timetable PDFs. Agency id must be LACMTA or LACMTA_Rail.', 10, 'https://developer.metro.net/api/', 'https://api.metro.net', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (440, 'airportsapi', 'airportsapi', '🛫', 'Look up an airport''s name and website by ICAO code', 'Give it a four-letter ICAO code and it returns the airport''s official name and homepage URL as JSON. Minimal but keyless, with CORS enabled for browser use. The underlying dataset is static and hasn''t been refreshed since 2017.', 10, 'https://airport-web.appspot.com/api/docs/', 'https://airport-web.appspot.com/_ah/api/airportsapi/v1', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (441, 'church-calendar', 'Church Calendar', '⛪', 'Catholic liturgical day, season and feast lookups as JSON', 'Returns the Roman Catholic liturgical calendar for any date: the season, week number, weekday and the day''s celebrations with their liturgical colour and rank. Multiple language calendars are available in the path. Served over plain HTTP only.', 16, 'http://calapi.inadiutorium.cz/', 'http://calapi.inadiutorium.cz/api/v0', 'none', 'endpoint', 0, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (442, 'hebrew-calendar', 'Hebrew Calendar', '🕎', 'Convert Gregorian dates to the Hebrew calendar as JSON', 'Hebcal''s converter turns any Gregorian date into its Hebrew-calendar equivalent, returning the Hebrew year, month and day plus the Hebrew-script date and any Torah portion or holiday that falls on it. Pass cfg=json to get structured output. The wider Hebcal API also covers Shabbat and holiday times.', 16, 'https://www.hebcal.com/home/developer-apis', 'https://www.hebcal.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (443, 'zippopotam-us', 'Zippopotam.us', '📮', 'Postal code to place, coordinates and region, keyless', 'Look up a postal code in any of dozens of supported countries and get back the place name, state/region and latitude/longitude. The path is simply the country code and postcode. No key, no signup, JSON out.', 3, 'http://www.zippopotam.us', 'https://api.zippopotam.us', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (444, 'nexchange', 'Nexchange', '🔁', 'Supported currencies and pairs for a crypto exchange API', 'The public endpoints of the n.exchange automated crypto-exchange list every supported currency with its limits, network, decimals and withdrawal fee, plus which trading pairs it participates in. This currency listing needs no key or auth. Order creation elsewhere in the API is a separate, authenticated flow.', 9, 'https://nexchange2.docs.apiary.io/', 'https://api.n.exchange', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (445, 'grunstromindex', 'GrünstromIndex', '🌱', 'Hourly green-power forecast for German postcodes', 'The Corrently GSI (Grünstromindex) endpoint forecasts the share of renewable electricity for a German postal code hour by hour, alongside wind/solar values, a CO2 estimate and an indicative energy price. Pass a zip code and get a JSON forecast array. Usage is governed by a fair-use policy, with paid tiers for higher limits.', 1, 'https://gruenstromindex.de/', 'https://api.corrently.io/v2.0', 'none', 'endpoint', 1, 1, 'Free under fair-use policy', 'Fair-use (paid tiers for higher limits)', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (446, 'postcodedata-nl', 'PostcodeData.nl', '🇳🇱', 'Dutch postcode + house number to street and coordinates', 'Resolves a Dutch postcode and house number into the street, city, municipality, province and both RD and WGS84 (lat/lon) coordinates. Pass type=json for structured output. Served over plain HTTP only.', 3, 'http://api.postcodedata.nl/v1/postcode/?postcode=1211EP&streetnumber=60&ref=domeinnaam.nl&type=json', 'http://api.postcodedata.nl/v1', 'none', 'endpoint', 0, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (447, 'open-government-canada', 'Open Government, Canada', '🍁', 'Search Canada''s open-data catalogue via the CKAN API', 'The Government of Canada''s open-data portal exposes a standard CKAN API, so you can search and page through tens of thousands of federal datasets and read their full metadata as JSON. No key is required for reads. Data is published under the Open Government Licence – Canada.', 17, 'http://open.canada.ca/en', 'https://open.canada.ca/data/api/3', 'none', 'endpoint', 1, 0, 'Free / open data', 'Unpublished', 0, 'yes', 'Open Government Licence – Canada', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (448, 'city-gdynia', 'City, Gdynia', '🏙️', 'Gdynia (PL) open-data catalogue over a CKAN API', 'The Polish city of Gdynia publishes its open data through a standard CKAN API, listing datasets that cover live public-transport arrivals, routes, timetables and more. The package_list endpoint returns dataset slugs as JSON with no key. Individual datasets are fetched by name from the same API.', 17, 'http://otwartedane.gdynia.pl/en/api_doc.html', 'https://otwartedane.gdynia.pl/api/3', 'none', 'endpoint', 1, 0, 'Free / open data', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (449, 'data-parliament-uk', 'Data.parliament.uk', '🏛️', 'UK Parliament linked-data: bills, members, votes and more', 'The UK Parliament Linked Data API serves datasets on bills, members, divisions, attendance and petitions. Append .json to any resource path to get JSON, with paging controlled by query parameters. Content is available under the Open Parliament Licence.', 17, 'https://explore.data.parliament.uk/?learnmore=Members', 'https://lda.data.parliament.uk', 'none', 'endpoint', 1, 1, 'Free / open data', 'Unpublished', 0, 'yes', 'Open Parliament Licence', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (450, 'purgomalum', 'PurgoMalum', '🧼', 'Profanity filter as a service, keyless JSON in and out', 'Pass any text and PurgoMalum returns it with profanity and obscenity removed or masked, using a built-in word list you can extend. The JSON service returns a simple result field. No key, no signup, GET only.', 8, 'http://www.purgomalum.com', 'https://www.purgomalum.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (451, 'tvmaze', 'TVMaze', '📺', 'Search TV shows, episodes and cast from a community DB', 'TVMaze exposes a keyless REST API for television metadata: show details, episode lists, air schedules, cast and crew. Query by name or ID and get clean JSON back, with no signup on the free tier.', 13, 'https://www.tvmaze.com/api', 'https://api.tvmaze.com', 'none', 'endpoint', 1, 1, 'Free for personal/non-commercial use, no key', 'At least 20 calls per 10 seconds per IP (per docs)', 0, 'no', 'CC BY-SA (attribution required, per docs)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (452, 'metro-lisboa', 'Metro Lisboa', '🚇', 'Live service status for Lisbon Metro''s four colored lines', 'Returns the current running status of Lisbon Metro''s yellow, blue, green and red lines as simple JSON. It is the same public feed that powers the operator''s status page, refreshed in near real time.', 10, 'https://app.metrolisboa.pt/status/getLinhas.php', 'https://app.metrolisboa.pt', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (453, 'transport-for-grenoble-france', 'Transport for Grenoble, France', '🚊', 'Grenoble tram and bus routes, stops and times as JSON', 'The Metromobilite open-data API serves the SMMAG transit network around Grenoble, France. This keyless endpoint lists every tram and bus route with names, colors and modes; other paths cover stops and real-time arrivals.', 10, 'https://www.mobilites-m.fr/pages/opendata/OpenDataApi.html', 'https://data.mobilites-m.fr', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (454, 'transport-for-paris-france', 'Transport for Paris, France', '🚇', 'Explore RATP Paris open-data datasets over a JSON API', 'RATP publishes Paris transit open data through an OpenDataSoft portal with a fully keyless REST API. Browse the dataset catalog or query records for things like station traffic and air quality, all returned as JSON.', 10, 'https://data.ratp.fr/', 'https://data.ratp.fr', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'OpenDataSoft platform defaults (unpublished here)', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (455, 'transport-for-philadelphia-us', 'Transport for Philadelphia, US', '🚆', 'Real-time SEPTA Philadelphia train positions and delays', 'SEPTA''s public API reports live regional-rail train locations, destinations, delays and next stops for the Philadelphia area. No key is required; the TrainView endpoint returns an array of every active train as JSON.', 10, 'https://www3.septa.org/hackathon/', 'https://www3.septa.org', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (456, 'transport-for-united-states', 'Transport for United States', '🚌', 'Live bus and transit predictions across US agencies', 'The Umo IQ (formerly NextBus) public JSON feed covers dozens of North American transit agencies. Start from the agency list, then drill into routes, stops and real-time vehicle predictions, no key needed.', 10, 'https://retro.umoiq.com/xmlFeedDocs/NextBusXMLFeed.pdf', 'https://retro.umoiq.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Data copyright transit agencies / Umo IQ', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (457, 'resmush-it', 'ReSmush.it', '🗜️', 'Free image optimization: shrink JPG, PNG and more by URL', 'Point reSmush.it at an image URL and it returns a compressed copy plus before/after byte sizes as JSON. It is a keyless optimization service supporting JPG, PNG, GIF, BMP and TIFF with adjustable quality.', 13, 'https://resmush.it/api', 'http://api.resmush.it', 'none', 'endpoint', 0, 1, 'Free; per-image size cap applies (see docs)', 'Unpublished', 0, 'unclear', 'N/A — optimization service, not a dataset', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (458, 'open-government-romania', 'Open Government, Romania', '🇷🇴', 'Romania''s national open-data catalog over the CKAN API', 'data.gov.ro is Romania''s official open-data portal running on CKAN, so it speaks the standard CKAN Action API. This keyless call lists dataset identifiers; further endpoints return metadata and downloadable resources across government topics.', 17, 'https://data.gov.ro/', 'https://data.gov.ro', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Varies by dataset (CKAN portal)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (459, 'minor-planet-center', 'Minor Planet Center', '☄️', 'Query asteroids by orbit, size and value via Asterank', 'Asterank wraps Minor Planet Center and JPL orbital data behind a keyless query API. Send a MongoDB-style filter and get back asteroids with diameter, orbital elements, albedo and Asterank''s estimated mining value as JSON.', 4, 'http://www.asterank.com/mpc', 'http://www.asterank.com', 'none', 'endpoint', 0, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified (data derived from JPL/MPC)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (460, 'mlb-records-and-stats', 'MLB Records and Stats', '⚾', 'Official MLB stats: teams, standings, players and games', 'MLB''s Stats API serves current and historical baseball data, teams, rosters, standings, schedules and box scores, without an API key. Responses are JSON and carry MLB Advanced Media''s copyright terms.', 14, 'https://appac.github.io/mlb-data-api-docs/', 'https://statsapi.mlb.com/api/v1', 'none', 'endpoint', 1, 1, 'Free — no key; subject to MLB copyright terms', 'Unpublished', 0, 'no', 'MLB Advanced Media copyright (see terms)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (461, 'chronicling-america', 'Chronicling America', '📰', 'Search millions of digitized historic US newspaper pages', 'The Library of Congress serves its Chronicling America collection of historic American newspapers as JSON through the loc.gov API. Search by keyword, place or date to retrieve page-level records with titles, dates and image links.', 7, 'https://www.loc.gov/apis/', 'https://www.loc.gov', 'none', 'endpoint', 1, 1, 'Free — public-domain collection data', 'LoC throttles heavy crawling (see LoC API policy)', 0, 'yes', 'Public domain / no known copyright (Library of Congress)', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (462, 'extinct-animals-api', 'Extinct Animals API', '🐾', 'Extinct Animals API — This API provides information about animals that became…', 'Extinct Animals API exposes this API provides information about animals that became extinct in the last 11,650 years, known as the Holocene extinction. It gathers data from Wikipedia and individual animal pages, allowing users to retrieve information about these extinct species, including their names and last recorded sightings. We verified a keyless GET endpoint returning JSON (Animals). Check the provider docs for rate limits and terms before production use.', 5, 'https://cheba-apis.vercel.app/', 'https://extinct-api.herokuapp.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (463, 'first-news-api', 'FIRST News API', '📰', 'FIRST News API — Public query for FIRST News with additional parameters …', 'FIRST News API exposes public query for FIRST News with additional parameters for filtering results. No credentials required. We verified a keyless GET endpoint returning JSON (News). Check the provider docs for rate limits and terms before production use.', 7, 'https://api.first.org/v1/get-news', 'https://api.first.org', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (464, 'fantasy-role-playing-api', 'Fantasy Role Playing API', '🔧', 'Fantasy Role Playing API — Set API allows users to query and generate entities', 'Fantasy Role Playing API exposes set API allows users to query and generate entities within a fantasy role-playing world. It supports various actions such as rolling items and characters via HTTP GET requests, making it easily accessible and compatible with JSON, CURL, and CORS. We verified a keyless GET endpoint returning JSON (Development). Check the provider docs for rate limits and terms before production use.', 8, 'https://set.world', 'https://set.world', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (465, 'fake-json-api', 'Fake JSON API', '🔧', 'Fake JSON API — This free public API allows developers to easily obtain…', 'Fake JSON API exposes this free public API allows developers to easily obtain fake JSON data for testing and development. There is no need for registration, tokens, or authentication, simplifying the process of retrieving dummy data quickly. We verified a keyless GET endpoint returning JSON (Development). Check the provider docs for rate limits and terms before production use.', 8, 'https://softwium.com/fake-api/', 'https://softwium.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (466, 'fedora-messaging-api', 'Fedora Messaging API', '💬', 'Fedora Messaging API — Retrieve historical messages sent via Fedora Messaging ', 'Fedora Messaging API exposes retrieve historical messages sent via Fedora Messaging using HTTP GET requests. Query by username, package, message source, topic, etc. We verified a keyless GET endpoint returning JSON (Social). Check the provider docs for rate limits and terms before production use.', 16, 'https://apps.fedoraproject.org/datagrepper/', 'https://apps.fedoraproject.org', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (467, 'footer-year-update', 'Footer Year Update', '📅', 'Footer Year Update — This API automatically retrieves the current year for w…', 'Footer Year Update exposes this API automatically retrieves the current year for website footers, eliminating the need for manual updates each January. Designed for developers, it ensures that the displayed year is accurate and up to date, improving user experience while saving time and resources. We verified a keyless GET endpoint returning JSON (Calendar). Check the provider docs for rate limits and terms before production use.', 16, 'https://getfullyear.com', 'https://getfullyear.com', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (468, 'finsignals-api', 'FinSignals API', '💬', 'FinSignals API — The FinSignals API provides a RESTful interface for cla…', 'FinSignals API exposes the FinSignals API provides a RESTful interface for classifying financial social posts, including text from platforms like Reddit. It evaluates a post''s sentiment, directionality, content quality, and other relevant signals in a structured JSON response. We verified a keyless GET endpoint returning JSON (Social). Check the provider docs for rate limits and terms before production use.', 16, 'https://finsignals.ai/docs/', 'https://api.finsignals.ai', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (469, 'free-uv-index-api', 'Free UV Index API', '🌤', 'Free UV Index API — Provides real-time UV Index and 5 day Hourly UV Index F…', 'Free UV Index API exposes provides real-time UV Index and 5 day Hourly UV Index Forecast globally without API Key. Single endpoint for current UV Index and forecast based on latitude/longitude. We verified a keyless GET endpoint returning JSON (Weather). Check the provider docs for rate limits and terms before production use.', 1, 'https://currentuvindex.com/api', 'https://currentuvindex.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (470, 'glax-weather-api', 'Glax Weather API', '🌤', 'Glax Weather API — This API provides current weather data for a specified …', 'Glax Weather API exposes this API provides current weather data for a specified location, presenting information visually through Glax. Users can retrieve data in JSON or PNG formats and customize their queries with parameters like location, units, and forecast options. We verified a keyless GET endpoint returning JSON (Weather). Check the provider docs for rate limits and terms before production use.', 1, 'https://dragon.best/api/glax_weather/', 'https://dragon.best', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (471, 'global-shark-attack-api', 'Global Shark Attack API', '🔧', 'Global Shark Attack API — The Global Shark Attack File (GSAF) API offers acces', 'Global Shark Attack API exposes the Global Shark Attack File (GSAF) API offers access to a comprehensive dataset of human-shark interactions, including detailed incident reports categorized by type, such as unprovoked, provoked, boat-related, war-related, and questionable incidents. Users can explore bite patterns, species identification, and circumstances surrounding shark encounters, providing valuable insights for researchers, enthusiasts, and conservationists interested in understanding shark behavior and the r', 8, 'https://public.opendatasoft.com/explore/dataset/global-shark-attack', 'https://public.opendatasoft.com', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
