insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (473, 'geonet-api', 'GeoNet API', '🔧', 'GeoNet API — The GeoNet API allows developers to run common network …', 'GeoNet API exposes the GeoNet API allows developers to run common network tools from servers located around the world, facilitating the identification of network behavior based on user region. It includes functionalities like GeoPing for latency measurement and GeoDNS for DNS record lookups. We verified a keyless GET endpoint returning JSON (Development). Check the provider docs for rate limits and terms before production use.', 8, 'https://geonet.shodan.io/', 'https://geonet.shodan.io', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
