insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (478, 'infranode-open-data-api', 'InfraNode Open Data API', '🗺', 'InfraNode Open Data API — InfraNode is a free public REST API that consolidate', 'InfraNode Open Data API exposes infraNode is a free public REST API that consolidates open data from German cities, providing a consistent JSON envelope across multiple data sources. It eliminates the need for multiple API keys and allows access to a wide range of data regarding urban environments without advertising or payment barriers. We verified a keyless GET endpoint returning JSON (Geocoding). Check the provider docs for rate limits and terms before production use.', 3, 'https://infranode.dev', 'https://infranode.dev', 'none', 'endpoint', 1, 1, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
