insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (505, 'public-time-api', 'Public Time API', '📅', 'Public Time API — This API provides the current timestamp in various form…', 'Public Time API exposes this API provides the current timestamp in various formats, including text, JSON, and CSS custom properties. It supports different endpoints for specific use cases, such as returning UNIX timestamps or sending periodic updates via Server-Sent Events and WebSockets. We verified a keyless GET endpoint returning JSON (Calendar). Check the provider docs for rate limits and terms before production use.', 16, 'https://zenn.dev/siyukatu/articles/public-time-api?locale=en', 'https://zenn.dev', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
