insert into apis (id, slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) values (507, 'openfda-api', 'openFDA API', '🍔', 'openFDA API — openFDA provides access to a variety of public data rel…', 'openFDA API exposes openFDA provides access to a variety of public data related to FDA-regulated products. It offers APIs for searching FDA data for drugs, devices, food, and other relevant categories crucial for healthcare decisions and research. We verified a keyless GET endpoint returning JSON (Food & Drink). Check the provider docs for rate limits and terms before production use.', 14, 'https://open.fda.gov/', 'https://open.fda.gov', 'none', 'endpoint', 1, 0, 'Free — limits not published', 'Unpublished', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL);
